// ═══════════════════════════════════════════════════════════════════════
// LOAD TRUMP CALENDAR EVENTS AUTOMATICALLY
// ═══════════════════════════════════════════════════════════════════════
let TRUMP_CALENDAR_EVENTS = [];
let trumpCalendarLoaded = false; // Flag to prevent duplicate loads

async function loadTrumpCalendarEvents(retryCount = 0) {
  // Skip if already loaded (to prevent duplicates)
  if(trumpCalendarLoaded) {
    console.log('[Trump Calendar] Already loaded this session, skipping auto-load');
    return;
  }
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 5000); // 5 second timeout

    const response = await fetch('../data/trump_calendar_latest.json', { signal: controller.signal });
    clearTimeout(timeoutId);

    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const data = await response.json();
    if (!data.events || !Array.isArray(data.events)) throw new Error('No events in response');

    // Convert Trump calendar format to ECON_EVENTS format
    // Filter out executive time and pool call events
    TRUMP_CALENDAR_EVENTS = data.events
      .filter(evt => {
        const name = String(evt.details || evt.type || evt.daily_text || '').toLowerCase();
        // Exclude routine schedule items
        return !name.includes('executive time') &&
               !name.includes('pool call') &&
               !name.includes('in-town pool');
      })
      .map(evt => ({
        date: evt.date || '',
        time: evt.time || '00:00',
        name: evt.details || evt.type || evt.daily_text || 'Event',
        period: '',
        noTime: !evt.time
      }));

    // Merge into ECON_EVENTS if it exists
    if (typeof ECON_EVENTS !== 'undefined') {
      ECON_EVENTS.push(...TRUMP_CALENDAR_EVENTS);
      try{
        const now = new Date();
        TRUMP_CALENDAR_EVENTS.forEach(evt => {
          if(!evt.date || !evt.time) return;
          const dt = new Date(`${evt.date}T${evt.time}:00`);
          const mins = Math.round((dt.getTime() - now.getTime()) / 60000);
          if(mins >= 0 && mins <= 5){
            _feedPushSimpleSignal('ECON CAL', `5 minute warning: ${evt.name} starts at ${evt.time}.`, 'signal', ['WARN', 'ECON'], { type: 'econ5mWarning', event: evt });
          }
        });
      }catch(e){}
      // Mark as loaded to prevent duplicate auto-loads
      trumpCalendarLoaded = true;

      // Re-render the calendar immediately
      if (typeof renderEconCalendar === 'function') {
        renderEconCalendar();
      }
    }
  } catch (e) {
    console.warn('[Trump Calendar] Load error:', e.message);
    // Retry once after delay
    if (retryCount < 1) {
      setTimeout(() => loadTrumpCalendarEvents(retryCount + 1), 2000);
    }
  }
}

// Load on page init
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => {
    setTimeout(loadTrumpCalendarEvents, 500); // Wait for ECON_EVENTS to load
  });
} else {
  setTimeout(loadTrumpCalendarEvents, 500);
}

// Reload every 30 minutes
setInterval(loadTrumpCalendarEvents, 30 * 60 * 1000);

