function switchPage(page, el){
  // Hide all pages with !important
  ['overview','gex','database','trading','stats','insights'].forEach(p=>{
    const div = document.getElementById('page-'+p);
    if(div){ 
      div.style.setProperty('display', 'none', 'important');
      div.style.setProperty('visibility', 'hidden', 'important');
    }
  });
  // Clear DTE pills when leaving overview
  if(page !== 'overview'){
    const dtePills = document.getElementById('dte-gex-pills');
    if(dtePills) dtePills.innerHTML = '';
  }
  // Show selected page with !important
  const target = document.getElementById('page-'+page);
  if(target){ 
    target.style.setProperty('display', 'flex', 'important');
    target.style.setProperty('visibility', 'visible', 'important');
    target.style.setProperty('flex', '1', 'important');
  }

  // Update nav active state
  document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('active'));
  const navEl = el || document.getElementById('nav-'+page);
  if(navEl) navEl.classList.add('active');

  // If switching back to overview, trigger re-render
  if(page==='overview'){
    setTimeout(()=>{ try{ initOvEvents(); drawOverviewChart(); buildDTEGEXPills(); }catch(e){} }, 50);
  }
  // If switching to GEX page, initialize with closest expiration
  if(page==='gex'){
    setTimeout(()=>{ try{ initGexPage(); }catch(e){} }, 50);
  }
}

function setMode(mode,el){
  currentMode='overview';
  document.querySelectorAll('.nav-item').forEach(t=>t.classList.remove('active'));
  const nav=document.getElementById('nav-overview');if(nav)nav.classList.add('active');
  const mc=document.getElementById('main-chart-panel');if(mc)mc.style.display='flex';
  const ladder=document.getElementById('options-ladder');if(ladder)ladder.style.display='flex';
  setTimeout(()=>{initOvEvents();drawOverviewChart();},50);
}














