function updateTopGamma(){ 
  if(!rawChain||!rawChain.length) return;
  const fmtG=v=>{const a=Math.abs(v);const s=v>=0?'+':'-';if(a>=1e9)return s+'$'+(a/1e9).toFixed(2)+'B';if(a>=1e6)return s+'$'+(a/1e6).toFixed(2)+'M';if(a>=1e3)return s+'$'+(a/1e3).toFixed(2)+'K';return s+'$'+a.toFixed(2);};
  const topPos=rawChain.reduce((a,b)=>b.netGEX>a.netGEX?b:a,rawChain[0]);
  const topNeg=rawChain.reduce((a,b)=>b.netGEX<a.netGEX?b:a,rawChain[0]);
  const p1=document.getElementById('rs-top-pos-gamma');if(p1)p1.textContent=topPos?topPos.strike.toLocaleString():'—';
  const p2=document.getElementById('rs-top-pos-val');if(p2)p2.textContent=topPos?fmtG(topPos.netGEX):'';
  const n1=document.getElementById('rs-top-neg-gamma');if(n1)n1.textContent=topNeg?topNeg.strike.toLocaleString():'—';
  const n2=document.getElementById('rs-top-neg-val');if(n2)n2.textContent=topNeg?fmtG(topNeg.netGEX):'';
}

const MAX_SNAPS = 60;

// ── STATE ──────────────────────────────────────────────────────────
let accessToken=null, refreshToken=null;
let rawChain=[], spotPrice=0, flipPoint=null, gammaZeroPoint=null;
let compareRawChain=[], compareSpotPrice=0;
const MIN_GEX_STRIKE_COUNT = 40;
const DEFAULT_GEX_STRIKE_RANGE = 100;
const DEFAULT_GEX_STRIKE_COUNT = 80;
let currentView='all', currentStrikeCount=parseInt(window.AppState?.strikeCount, 10) || DEFAULT_GEX_STRIKE_COUNT, currentSort='strike';

function setConfiguredStrikeCount(count) {
  const parsed = parseInt(count, 10);
  const next = parsed > 0 ? Math.max(MIN_GEX_STRIKE_COUNT, parsed) : 0;
  currentStrikeCount = next;
  if (!window.AppState) window.AppState = {};
  window.AppState.strikeCount = next;
  const input = document.getElementById('strike-count-input');
  if (input && parseInt(input.value, 10) !== next) input.value = String(next);
  return next;
}

function getConfiguredStrikeCount() {
  // Prefer AppState if set, otherwise use currentStrikeCount
  const fromState = parseInt(window.AppState?.strikeCount, 10);
  if (Number.isFinite(fromState) && fromState >= 0) {
    const configured = fromState > 0 ? Math.max(MIN_GEX_STRIKE_COUNT, fromState) : 0;
    if (currentStrikeCount !== configured) currentStrikeCount = configured;
    return configured;
  }
  // Fall back to currentStrikeCount when AppState is missing
  return currentStrikeCount > 0 ? Math.max(MIN_GEX_STRIKE_COUNT, currentStrikeCount) : 0;
}

function getVisibleStrikeRows(rows, spot, count = getConfiguredStrikeCount(), descending = false) {
  const sorted = [...(rows || [])].sort((a, b) => a.strike - b.strike);
  return descending ? sorted.reverse() : sorted;
}

function getSpxStrikeUniverse() {
  const strikes = new Set((rawChain || []).map(r => Number(r.strike)).filter(Number.isFinite));
  Object.values(expiryMap || {}).forEach(exp => {
    Object.keys(exp?.calls || {}).forEach(k => {
      const n = Number(k);
      if (Number.isFinite(n)) strikes.add(n);
    });
    Object.keys(exp?.puts || {}).forEach(k => {
      const n = Number(k);
      if (Number.isFinite(n)) strikes.add(n);
    });
  });
  return [...strikes].sort((a, b) => a - b);
}

function inferStrikeStep(strikes) {
  const diffs = [];
  for (let i = 1; i < strikes.length; i++) {
    const d = +(strikes[i] - strikes[i - 1]).toFixed(4);
    if (d > 0 && d <= 100) diffs.push(d);
  }
  if (!diffs.length) return 5;
  const counts = new Map();
  diffs.forEach(d => counts.set(d, (counts.get(d) || 0) + 1));
  return [...counts.entries()].sort((a, b) => b[1] - a[1] || a[0] - b[0])[0][0] || 5;
}

function getCenteredStrikeList(spot, count = getConfiguredStrikeCount()) {
  const universe = getSpxStrikeUniverse();
  const visibleCount = Math.max(1, count);
  if (!universe.length) return [];
  const step = inferStrikeStep(universe);
  const atm = universe.reduce((best, strike) => Math.abs(strike - spot) < Math.abs(best - spot) ? strike : best, universe[0]);
  const belowCount = Math.floor(visibleCount / 2);
  const start = atm - belowCount * step;
  return Array.from({ length: visibleCount }, (_, i) => +(start + i * step).toFixed(4));
}

function getDisplayStrikeCount() {
  const count = getConfiguredStrikeCount();
  if (count > 0) return Math.max(MIN_GEX_STRIKE_COUNT, count);
  return rawChain && rawChain.length ? rawChain.length : DEFAULT_GEX_STRIKE_COUNT;
}

function getStrikeCountForSpotRange(rows, spot, range = DEFAULT_GEX_STRIKE_RANGE) {
  const strikes = [...new Set((rows || []).map(r => Number(r.strike)).filter(Number.isFinite))].sort((a, b) => a - b);
  if (!strikes.length || !(spot > 0)) return DEFAULT_GEX_STRIKE_COUNT;
  const inRange = strikes.filter(strike => strike >= spot - range && strike <= spot + range).length;
  return Math.max(MIN_GEX_STRIKE_COUNT, inRange || DEFAULT_GEX_STRIKE_COUNT);
}

function inferRowsStrikeStep(rows, fallback = 5) {
  const strikes = [...new Set((rows || []).map(r => Number(r.strike)).filter(Number.isFinite))].sort((a, b) => a - b);
  return strikes.length > 1 ? inferStrikeStep(strikes) : fallback;
}

function calcDollarGammaExposure(gamma, contracts, spot) {
  const g = Number(gamma) || 0;
  const c = Number(contracts) || 0;
  const s = Number(spot) || 0;
  // Call GEX: OI × Gamma × 100 × (0.01 × Spot) - positive because dealers are short
  return g * c * 100 * s * s * 0.01;
}

function calcPutGammaExposure(gamma, contracts, spot) {
  const g = Number(gamma) || 0;
  const c = Number(contracts) || 0;
  const s = Number(spot) || 0;
  // Put GEX: OI × Gamma × 100 × (0.01 × Spot) - negative because dealers are long
  return -(g * c * 100 * s * s * 0.01);
}

// Volume GEX using Lee-Ready Heuristic: calls dealer short (positive), puts dealer long (negative)
function calcVolumeGammaExposure(gamma, volume, spot, isCalls) {
  const g = Number(gamma) || 0;
  const v = Number(volume) || 0;
  const s = Number(spot) || 0;
  // Call Volume: positive (dealer short)
  // Put Volume: negative (dealer long)
  if(isCalls) {
    return g * v * 100 * s * s * 0.01;
  } else {
    return -(g * v * 100 * s * s * 0.01);
  }
}

function normPdf(x) {
  return Math.exp(-0.5 * x * x) / Math.sqrt(2 * Math.PI);
}

function calcBlackScholesGamma(spot, strike, iv, timeToExpYears, rate = 0, dividendYield = 0) {
  const S = Number(spot) || 0;
  const K = Number(strike) || 0;
  const sigma = Number(iv) || 0;
  const T = Number(timeToExpYears) || 0;
  if (!(S > 0) || !(K > 0) || !(sigma > 0) || !(T > 0)) return 0;
  const sqrtT = Math.sqrt(T);
  const d1 = (Math.log(S / K) + (rate - dividendYield + 0.5 * sigma * sigma) * T) / (sigma * sqrtT);
  return Math.exp(-dividendYield * T) * normPdf(d1) / (S * sigma * sqrtT);
}

function getTimeToExpiryYears(expiryStr) {
  if (!expiryStr) return 0;
  const dt = new Date(expiryStr + 'T16:00:00');
  const now = new Date();
  const ms = dt.getTime() - now.getTime();
  return ms > 0 ? ms / (365 * 24 * 60 * 60 * 1000) : 0;
}

window.__gexFlipOverlayState = window.__gexFlipOverlayState || null;
if (typeof Chart !== 'undefined' && !window.__gexFlipOverlayRegistered) {
  window.__gexFlipOverlayRegistered = true;
  Chart.register({
    id: 'gexFlipOverlay',
    afterDatasetsDraw(chart) {
      const state = window.__gexFlipOverlayState;
      if (!state || !state.enabled) return;
      const { ctx, chartArea } = chart;
      const rows = state.rows || [];
      const exp = state.exp || 0;
      if (!rows.length || !(exp > 0) || !chartArea) return;
      const meta = chart.getDatasetMeta(0);
      if (!meta?.data?.length) return;
      const points = [];
      const spot = state.spot || 0;
      for (let i = 0; i < rows.length; i++) {
        const r = rows[i];
        const callGamma = calcBlackScholesGamma(spot, r.strike, r.callIV || r.putIV || 0, exp);
        const putGamma = calcBlackScholesGamma(spot, r.strike, r.putIV || r.callIV || 0, exp);
        const v = calcDollarGammaExposure(callGamma, r.callOI || 0, spot) - calcDollarGammaExposure(putGamma, r.putOI || 0, spot);
        points.push({ x: v, y: meta.data[i]?.y ?? 0 });
      }
      const xScale = chart.scales.x;
      const xFor = v => xScale.getPixelForValue(v);
      ctx.save();
      ctx.beginPath();
      ctx.strokeStyle = '#00e5ff';
      ctx.lineWidth = 2;
      ctx.setLineDash([2, 4]);
      points.forEach((p, i) => {
        const x = xFor(p.x);
        i === 0 ? ctx.moveTo(x, p.y) : ctx.lineTo(x, p.y);
      });
      ctx.stroke();
      ctx.setLineDash([]);
      ctx.restore();
    }
  });
}

function expandRowsAroundSpot(rows, spot, count = getDisplayStrikeCount()) {
  const source = Array.isArray(rows) ? rows : [];
  return densifyStrikeRows(source);
}
