function getDefaultDTE() {
  const now = new Date();
  const hours = now.getHours();
  const minutes = now.getMinutes();
  const timeInMinutes = hours * 60 + minutes;
  const fivePM = 17 * 60; // 5:00 PM in minutes
  
  // After 5pm ET, default to 1DTE
  if (timeInMinutes >= fivePM) {
    return 1;
  }
  return 0;
}

