// Auto-seed prev closes from quotes-batch (dxLink prevDayClosePrice — no Yahoo needed)
// Retries up to 10x with 2s gaps until dxLink has streamed Summary data.
(async function initPrevCloses() {
  const cacheKey = 'prevCloses_v3';
  const etDate = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' })).toISOString().slice(0, 10);
  const cached = JSON.parse(sessionStorage.getItem(cacheKey) || 'null');
  if (cached && cached.date === etDate && cached.spx > 0 && cached.es > 0) {
    spxPrevClose = cached.spx;
    esPrevClose  = cached.es;
    if (cached.vix > 0) window._vixPrevClose = cached.vix;
    console.log('[prevCloses] loaded from session cache:', cached);
    const callTopbar = () => { if (typeof updateTopbarESChange === 'function') updateTopbarESChange(); };
    callTopbar(); setTimeout(callTopbar, 500); setTimeout(callTopbar, 2000);
    return;
  }

  async function tryFetch() {
    try {
      const r = await fetch(window.location.origin + '/proxy/api/tt/quotes-batch');
      if (!r.ok) return false;
      const raw = await r.json();
      const items = raw?.data?.items || [];
      let spx = 0, es = 0, vix = 0;
      items.forEach(q => {
        const sym = (q.symbol || '').split(':')[0];
        const prev = parseFloat(q['prev-close'] || q.prevClose || q['previous-close'] || q['settlement-price'] || 0);
        if (prev <= 0) return;
        if (sym === 'SPX' || sym === '$SPX') spx = prev;
        if (sym.startsWith('/ES'))           es  = prev;
        if (sym === 'VIX' || sym === '$VIX' || sym === '$VIX.X') vix = prev;
      });
      if (spx > 0 && es > 0) {
        spxPrevClose = spx;
        esPrevClose  = es;
        if (vix > 0) window._vixPrevClose = vix;
        sessionStorage.setItem(cacheKey, JSON.stringify({ date: etDate, spx, es, vix }));
        console.log('[prevCloses] seeded from quotes-batch:', { spx, es, vix });
        if (typeof updateESPriceDisplay === 'function') updateESPriceDisplay();
        // updateTopbarESChange is in index.html — call it now and again after a short delay
        // in case the topbar ES price element hasn't been populated yet
        const callTopbar = () => { if (typeof updateTopbarESChange === 'function') updateTopbarESChange(); };
        callTopbar();
        setTimeout(callTopbar, 500);
        setTimeout(callTopbar, 2000);
        return true;
      }
    } catch (e) { console.warn('[prevCloses] fetch error:', e.message); }
    return false;
  }

  // Try immediately, then retry every 2s up to 10 times (dxLink may not have streamed yet)
  for (let i = 0; i < 10; i++) {
    if (await tryFetch()) return;
    await new Promise(r => setTimeout(r, 2000));
  }

  // Final fallback: em-closes endpoint (has its own close-fetching logic)
  try {
    const r = await fetch(window.location.origin + '/proxy/api/tt/em-closes');
    if (r.ok) {
      const d = await r.json();
      const c = d?.data || {};
      if (c.spx > 0 && c.es > 0) {
        spxPrevClose = c.spx;
        esPrevClose  = c.es;
        sessionStorage.setItem(cacheKey, JSON.stringify({ date: etDate, spx: c.spx, es: c.es, vix: 0 }));
        const callTopbar = () => { if (typeof updateTopbarESChange === 'function') updateTopbarESChange(); };
        callTopbar(); setTimeout(callTopbar, 500);
      }
    }
  } catch(_) {}
})();
// ES→SPX conversion closes (stored in localStorage.todayCloses after 4pm ET)
let esCloseForConv=0, spxCloseForConv=0;
let _todayClosesDate=''; // ET date string for the stored closes
let _lastMidnightResetDate=''; // prevent repeated midnight resets

(function loadTodayCloses() {
  try {
    const etDate = new Intl.DateTimeFormat('en-CA', { timeZone: 'America/New_York', year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date());
    const stored = JSON.parse(localStorage.getItem('todayCloses') || 'null');
    // Validate: ES and SPX closes must differ by at least 1 point (ES trades at a premium)
    const validSpread = stored && Math.abs(stored.es - stored.spx) >= 1;
    if (stored && stored.date === etDate && stored.es > 0 && stored.spx > 0 && validSpread) {
      esCloseForConv = stored.es;
      spxCloseForConv = stored.spx;
      _todayClosesDate = stored.date;
    } else if (stored && !validSpread) {
      // Bad data — clear it
      localStorage.removeItem('todayCloses');
    }
    _lastMidnightResetDate = etDate;
  } catch(e) {}
})();

setInterval(function checkTodayClosesCapture() {
  try {
    const now = new Date();
    const nyParts = new Intl.DateTimeFormat('en-US', { timeZone: 'America/New_York', weekday: 'short', hour: '2-digit', minute: '2-digit', hour12: false }).formatToParts(now);
    const part = t => nyParts.find(p => p.type === t)?.value || '';
    const day = part('weekday');
    const mins = (parseInt(part('hour'), 10) || 0) * 60 + (parseInt(part('minute'), 10) || 0);
    const etDate = new Intl.DateTimeFormat('en-CA', { timeZone: 'America/New_York', year: 'numeric', month: '2-digit', day: '2-digit' }).format(now);
    const isWeekday = !['Sat','Sun'].includes(day);
    // Midnight reset — clear stored closes so next day starts fresh from prev-close
    if (etDate !== _lastMidnightResetDate) {
      _lastMidnightResetDate = etDate;
      localStorage.removeItem('todayCloses');
      esCloseForConv = 0; spxCloseForConv = 0; _todayClosesDate = '';
    }
    // 4:00pm–4:02pm ET on weekdays: capture today's closes
    if (isWeekday && mins >= 960 && mins < 962 && _todayClosesDate !== etDate) {
      // Use spxPrevClose as SPX close proxy (it gets set from TT prev-close during market hours)
      // Only store if ES and SPX differ by at least 1 point (sanity check)
      const spxCloseCandidate = spotPrice > 0 ? spotPrice : spxPrevClose;
      if (esPrice > 0 && spxCloseCandidate > 0 && Math.abs(esPrice - spxCloseCandidate) >= 1) {
        esCloseForConv = esPrice;
        spxCloseForConv = spxCloseCandidate;
        _todayClosesDate = etDate;
        localStorage.setItem('todayCloses', JSON.stringify({ es: esPrice, spx: spxCloseCandidate, date: etDate }));
      }
    }
  } catch(e) {}
}, 30000);
