// GEX Change snapshot system — per-refresh + time-interval
let gexPrevSnapshot = null;      // Map<strike, netVolGEX> — previous refresh
let gexPrevSnapshotTime = null;
let gexSnapshots = [];           // [{ts, data: Map}] — timed snapshots
