// Rolling Vol GEX snapshot system — 30-minute history
let volGexSnapshots = [];
function recordVolGexSnapshot(){
  const ts = Date.now();
  const data = new Map();
  for(const r of rawChain){
    if(r.netVolGEX != null) data.set(r.strike, r.netVolGEX);
  }
  volGexSnapshots.push({ts, data});
  // Keep only last 35 minutes of snapshots (with 5-min margin)
  const cutoff = ts - 35 * 60 * 1000;
  volGexSnapshots = volGexSnapshots.filter(s => s.ts > cutoff);
}

function scheduleAutoSnapshots() {
  const et = () => new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
  const checkAndSnap = (hour, min, key) => {
    const now = et();
    if (now.getHours() === hour && now.getMinutes() === min && !peakGEXSnapshots[key]) {
      const peakRow = rawChain.reduce((best, row) => (Math.abs(row.netGEX || 0) > Math.abs(best.netGEX || 0) ? row : best), rawChain[0]);
      if (peakRow) {
        peakGEXSnapshots[key] = {time: now.toLocaleTimeString(), strike: peakRow.strike, gex: peakRow.netGEX};
        console.log(`[GEX] Auto-snap ${key}: ${peakRow.strike} @ ${peakRow.netGEX.toFixed(0)}`);
      }
    }
  };
  checkAndSnap(9, 45, 'snapAt945');
  checkAndSnap(10, 30, 'snapAt1030');
  checkAndSnap(12, 0, 'snapAtNoon');
}
setInterval(scheduleAutoSnapshots, 60000); // Check every minute

function getCurrentEtSessionKey() {
  const now = new Date();
  const etNow = new Date(now.toLocaleString('en-US', { timeZone: 'America/New_York' }));
  return `${etNow.getFullYear()}-${String(etNow.getMonth()+1).padStart(2,'0')}-${String(etNow.getDate()).padStart(2,'0')}`;
}

function ensureSignedVolSession() {
  const key = getCurrentEtSessionKey();
  if (spxSignedVolSessionKey !== key) {
    spxSignedVolSessionKey = key;
    spxSignedVolGEXByStrike = new Map();
    spxSignedVolContractsByStrike = new Map();
  }
}

function getOccOptionStrike(symbol) {
  const m = String(symbol || '').match(/[CP](\d{8})$/);
  return m ? parseInt(m[1], 10) / 1000 : null;
}

function normalizeDxFeedData(data) {
  if (!Array.isArray(data)) return [];
  if (data.length && typeof data[0] === 'object' && !Array.isArray(data[0])) return data;
  const eventType = data[0];
  const rows = data[1];
  if (typeof eventType !== 'string' || !Array.isArray(rows)) return [];
  const fieldsByType = {
    Quote:    ['bidPrice','askPrice','bidSize','askSize'],
    Trade:    ['price','dayVolume','size'],
    TradeETH: ['price','dayVolume','size'],
    Greeks:   ['volatility','delta','gamma','theta','rho','vega'],
    Summary:  ['openInterest','dayVolume','dayOpenPrice','dayHighPrice','dayLowPrice','dayClosePrice','dayClosePriceType','prevDayClosePrice','prevClosePriceType'],
  };
  const fields = fieldsByType[eventType];
  if (!fields) return [];
  const rowsIncludeType = rows[0] === eventType;
  const step = fields.length + (rowsIncludeType ? 2 : 1);
  const out = [];
  for (let i = 0; i <= rows.length - step; i += step) {
    const base = i + (rowsIncludeType ? 2 : 1);
    const item = {
      eventType: rowsIncludeType ? rows[i] : eventType,
      eventSymbol: rowsIncludeType ? rows[i + 1] : rows[i],
      time: Date.now()
    };
    fields.forEach((field, j) => item[field] = rows[base + j]);
    out.push(item);
  }
  return out;
}

function getSignedTradeDirection(item, quote) {
  const tradePrice = parseFloat(item.price || 0);
  if (quote && quote.bid > 0 && quote.ask > 0) {
    if (tradePrice >= quote.ask) return 1;
    if (tradePrice <= quote.bid) return -1;
  }
  return 0;
}

function applySignedVolGexToRawChain() {
  if (!rawChain.length) return;
  rawChain.forEach(r => {
    const strikeState = spxSignedVolGEXByStrike.get(r.strike) || {};
    const contractState = spxSignedVolContractsByStrike.get(r.strike) || {};
    r.callSignedVolume = contractState.call || 0;
    r.putSignedVolume = contractState.put || 0;
    r.callSignedVolGEX = strikeState.call || 0;
    r.putSignedVolGEX = strikeState.put || 0;
    r.netSignedVolGEX = strikeState.net || 0;
  });
}

function processSignedOptionTrade(item) {
  ensureSignedVolSession();
  const symbol = item.eventSymbol || '';
  const meta = spxOptionMetaBySymbol.get(symbol);
  if (!meta) return false;
  const quote = spxOptionQuotes.get(symbol);
  const tradeDirection = getSignedTradeDirection(item, quote);
  if (!tradeDirection) return false;
  const tradeSize = parseInt(item.size || 0, 10);
  const spot = Number(spotPrice || esPrice || 0);
  if (!tradeSize || !(spot > 0) || !(meta.gamma > 0)) return false;
  const optionType = meta.side === 'call' ? 1 : -1;
  const tickGEX = tradeDirection * optionType * meta.gamma * tradeSize * 50 * spot * spot * 0.01;
  const strikeState = spxSignedVolGEXByStrike.get(meta.strike) || { call: 0, put: 0, net: 0 };
  if (meta.side === 'call') strikeState.call += tickGEX;
  else strikeState.put += tickGEX;
  strikeState.net += tickGEX;
  spxSignedVolGEXByStrike.set(meta.strike, strikeState);
  const contractState = spxSignedVolContractsByStrike.get(meta.strike) || { call: 0, put: 0 };
  if (meta.side === 'call') contractState.call += tradeDirection * tradeSize;
  else contractState.put += tradeDirection * tradeSize;
  spxSignedVolContractsByStrike.set(meta.strike, contractState);
  const row = rawChain.find(r => r.strike === meta.strike);
  if (row) {
    row.callSignedVolume = contractState.call || 0;
    row.putSignedVolume = contractState.put || 0;
    row.callSignedVolGEX = strikeState.call || 0;
    row.putSignedVolGEX = strikeState.put || 0;
    row.netSignedVolGEX = strikeState.net || 0;
    
    if (meta.side === 'call') row.callVolume += tradeSize;
    else row.putVolume += tradeSize;

    // Sync the live volume back to the raw API dictionaries 
    const strikeKey = meta.strike.toFixed(1); 
    if (meta.side === 'call' && typeof calls !== 'undefined' && calls[strikeKey]) {
        calls[strikeKey].volume = row.callVolume;
        // ADD THIS TEST LOG
        if (meta.strike === 7400) console.log(`[LIVE STREAM] Caught 7400 Call Trade! New Vol: ${row.callVolume}`);
    } else if (meta.side === 'put' && typeof puts !== 'undefined' && puts[strikeKey]) {
        puts[strikeKey].volume = row.putVolume;
        // ADD THIS TEST LOG
        if (meta.strike === 7400) console.log(`[LIVE STREAM] Caught 7400 Put Trade! New Vol: ${row.putVolume}`);
    }
  }
  return !!row;
}

function connectSignedVolFlow() {
  if (spxFlowSocket && (spxFlowSocket.readyState === WebSocket.OPEN || spxFlowSocket.readyState === WebSocket.CONNECTING)) return;
  const proto = location.protocol === 'https:' ? 'wss' : 'ws';
  spxFlowSocket = new WebSocket(`${proto}://${window.location.host}/ws/dxlink`);
  spxFlowSocket.onopen = () => {
    spxFlowSocket.send(JSON.stringify({ type: 'subscribe', symbols: ['SPX'], spxSubscribe: true }));
  };
  spxFlowSocket.onmessage = event => {
    try {
      const msg = JSON.parse(event.data);
      if (msg.type !== 'FEED_DATA' || !Array.isArray(msg.data)) return;
      let needsRedraw = false;
      normalizeDxFeedData(msg.data).forEach(item => {
        const symbol = item.eventSymbol || '';
        if (!symbol.startsWith('.SPXW') && !symbol.startsWith('SPXW')) return;
        if (item.eventType === 'Quote') {
          const bid = parseFloat(item.bidPrice || 0);
          const ask = parseFloat(item.askPrice || 0);
          if (bid > 0 && ask > 0) spxOptionQuotes.set(symbol, { bid, ask });
          return;
        }
        if (item.eventType !== 'Trade' && item.eventType !== 'TradeETH') return;
        if (processSignedOptionTrade(item)) needsRedraw = true;
      });
      if (needsRedraw) {
        if (typeof renderOptionsLadder === 'function') renderOptionsLadder(rawChain);
        if (typeof drawOverviewChart === 'function') drawOverviewChart();
      }
    } catch (err) {
      console.warn('Signed vol flow parse error:', err);
    }
  };
  spxFlowSocket.onclose = () => {
    setTimeout(connectSignedVolFlow, 5000);
  };
}

function takeGexSnapshot(){
  if(!rawChain.length) return;
  const snap = new Map();
  rawChain.forEach(r=>snap.set(r.strike, r.netGEX||0));
  // Store as previous refresh snapshot
  gexPrevSnapshot = snap;
  gexPrevSnapshotTime = Date.now();
  // Also push to timed snapshots array
  gexSnapshots.push({ts: Date.now(), data: snap});
  const cutoff = Date.now() - 3*60*60*1000;
  gexSnapshots = gexSnapshots.filter(s=>s.ts >= cutoff);
  // Push to 1-min snapshots (keep last 2 hours)
  gex1MinSnapshots.push({ts: Date.now(), data: snap});
  gex1MinSnapshots = gex1MinSnapshots.filter(s=>s.ts >= Date.now() - 2*60*60*1000);
  // Record vol GEX snapshot for rolling 30-min history
  recordVolGexSnapshot();
}

function getGexChangeSnapshot(){
  if(gexChangeIntervalMin === 'refresh') return gexPrevSnapshot;
  if(!gexSnapshots.length) return null;
  const targetTs = Date.now() - gexChangeIntervalMin * 60 * 1000;
  let best = null;
  for(const s of gexSnapshots){
    if(s.ts <= targetTs + 90000){
      if(!best || s.ts > best.ts) best = s;
    }
  }
  return best ? best.data : null;
}

function getSnapshotAge(){
  if(gexChangeIntervalMin === 'refresh'){
    return gexPrevSnapshotTime ? Math.round((Date.now()-gexPrevSnapshotTime)/1000)+'s ago' : null;
  }
  const snap = getGexChangeSnapshot();
  if(!snap) return null;
  const s = gexSnapshots.find(s=>s.data===snap);
  return s ? Math.round((Date.now()-s.ts)/60000)+'m ago' : null;
}

function onGexChangeIntervalChange(){
  const sel = document.getElementById('gex-change-interval');
  if(sel) gexChangeIntervalMin = sel.value === 'refresh' ? 'refresh' : parseInt(sel.value);
  if(rawChain.length) renderOptionsLadder(rawChain);
}

