// ── RESET OVERVIEW STATE ──
// Called when returning to overview page from another page
window.resetOverviewState = function(){
  console.log('[Overview] Resetting state for page return');
  isFetching = false;

  // If rawChain already has data from today, just re-render — don't rebuild
  const todayStr = typeof getNYDateString === 'function' ? getNYDateString() : new Date().toISOString().slice(0,10);
  const chainDate = rawChain.length && rawChain[0]._date;
  if (rawChain.length > 0 && (!chainDate || chainDate === todayStr)) {
    console.log('[Overview] rawChain intact (' + rawChain.length + ' strikes) — re-rendering without rebuild');
    finishGEXCompute(typeof getInsightsTargetExpirationDate === 'function' ? getInsightsTargetExpirationDate() : todayStr);
    return;
  }

  // Chain is empty or stale — full rebuild
  rawChain = [];
  _initialGreeksReceived = false;
  _pendingFinishGEXDate  = null;
  if(typeof buildChainOnce === 'function'){
    console.log('[Overview] rawChain empty/stale — triggering chain rebuild');
    buildChainOnce(0);
  }
};

// ── BUILD CHAIN ONCE — Initial REST API fetch + dxlink subscription ──
// Called on first page load to prebuild the SPX 0DTE chain
// After this, dxlink websocket provides all updates (Quote, Greeks, Summary, Trade)
async function buildChainOnce(retryCount = 0){
  console.log('[buildChainOnce] Called - accessToken:', !!accessToken, 'rawChain.length:', rawChain.length, 'isFetching:', isFetching, 'retry:', retryCount);
  if(!accessToken){
    console.warn('[buildChainOnce] No accessToken - cannot proceed');
    return;
  }
  if(rawChain.length > 0){
    console.log('[buildChainOnce] Chain already built, skipping');
    return; // Already built, skip
  }
  if(isFetching){
    console.log('[buildChainOnce] Already fetching, skipping');
    return;
  }
  isFetching=true;
  const overlay=document.getElementById('refresh-overlay');
  const mc=document.getElementById('main-chart-panel');if(mc)mc.style.display='flex';
  log('Building chain…');
  try{
    // Fetch near-term SPX chains; DTE clicks select the expiry used for both charts.
    // On initial load, only fetch 0DTE. Clicking 1/2/3DTE triggers lazy fetch.
    const buildAllowedExpiries = (allExpDates) => {
      const todayStr = getNYDateString();
      const sorted = (allExpDates || []).filter(Boolean).sort();
      const findClosest = (target) => {
        if (!sorted.length) return null;
        if (sorted.includes(target)) return target;
        return sorted.find(d => d >= target) || null;
      };
      const allowed = new Set();
      // 0DTE only on initial load — other DTEs loaded lazily on click
      const zero = findClosest(getInsightsTargetExpirationDate());
      if (zero) allowed.add(zero);
      // Also pre-build the expiry map entries for 1-3DTE so pills know their dates,
      // but we won't actually fetch their chain data until clicked.
      const _holidaySet2 = (typeof GEX_HOLIDAYS !== 'undefined') ? GEX_HOLIDAYS : new Set();
      const _isHoliday2 = (d) => _holidaySet2.has(d.toISOString().slice(0,10));
      let tradingDaysFound = 0;
      for(const d of sorted) {
        if(d <= todayStr) continue;
        const dt = new Date(d+'T12:00:00');
        if(dt.getDay()===0||dt.getDay()===6||_isHoliday2(dt)) continue;
        tradingDaysFound++;
        if(tradingDaysFound <= 3) allowed.add(d); // add 1/2/3DTE dates so pills can display dates
        if(tradingDaysFound >= 3) break;
      }
      return allowed;
    };

    const t0 = performance.now();
    const chainRes = await fetch(PROXY + '/proxy/api/tt/chains/SPX?range=all');
    const chainData = await chainRes.json();
    const t1 = performance.now();
    console.log(`[GEX] Chain fetch: ${(t1-t0).toFixed(0)}ms`);
    console.log(`[GEX] Chain response status: ${chainRes.status}, has data.items: ${!!chainData.data?.items}, items length: ${chainData.data?.items?.length || 0}`, chainData);

    // Build allow-list of expirations from data
    const allExpDates = chainData.data?.items
      ? chainData.data.items.map(g => g['expiration-date'])
      : (chainData.data?.options || []).map(o => o.expiration_date);
    const allowedExpiries = buildAllowedExpiries(allExpDates);
    console.log(`[GEX] Allowed expiries:`, Array.from(allowedExpiries));

    // Build chain data from TastyTrade options chain
    const callExpDateMap = {};
    const putExpDateMap = {};
    const _todayStr0dte = getInsightsTargetExpirationDate();

    if(chainData.data?.items) {
      chainData.data.items.forEach(expGroup => {
        const expDate = expGroup['expiration-date'];
        if (!allowedExpiries.has(expDate)) return;
        // For future expiries (1-3DTE), register a stub so pills display dates correctly
        // but skip parsing chain data — it will be fetched lazily when clicked.
        if (expDate > _todayStr0dte) {
          if (!callExpDateMap[expDate]) callExpDateMap[expDate] = {};
          if (!putExpDateMap[expDate]) putExpDateMap[expDate] = {};
          return; // stub only, no strike data
        }
        console.log(`[GEX] ${expDate}: ${(expGroup.strikes || []).length} strikes from proxy`);
        (expGroup.strikes || []).forEach(strikeRow => {
          const strikePrice = String(strikeRow['strike-price']);
          if (!callExpDateMap[expDate]) callExpDateMap[expDate] = {};
          if (!putExpDateMap[expDate]) putExpDateMap[expDate] = {};
          const normalize = opt => {
            const greeks = opt?.greeks || {};
            const pickNum = (...vals) => {
              for (const v of vals) {
                const n = parseFloat(v);
                if (Number.isFinite(n)) return n;
              }
              return 0;
            };
            // TEST: Dump the raw API data for 7400 to the console
            if (parseInt(strikePrice) === 7400) console.log('[RAW API 7400]', opt);

            return {
              symbol: opt.symbol,
              streamerSymbol: opt['streamer-symbol'] || opt.symbol,
              delta: pickNum(opt.delta, greeks.delta, opt['delta']),
              gamma: pickNum(opt.gamma, greeks.gamma, opt['gamma']),
              vega: pickNum(opt.vega, greeks.vega, opt['vega']),
              theta: pickNum(opt.theta, greeks.theta, opt['theta']),
              // Catch every possible API variation for Open Interest and Volume
              openInterest: parseInt(opt['open-interest']) || parseInt(opt.open_interest) || parseInt(opt.openInterest) || 0,
              totalVolume: parseInt(opt.volume) || parseInt(opt['day-volume']) || parseInt(opt.totalVolume) || 0,
              strikePrice: parseFloat(strikePrice),
              expirationDate: expDate,
              mark: opt.last || ((opt.bid || 0) + (opt.ask || 0)) / 2
            };
          };
          if (strikeRow.call) callExpDateMap[expDate][strikePrice] = [normalize(strikeRow.call)];
          if (strikeRow.put) putExpDateMap[expDate][strikePrice] = [normalize(strikeRow.put)];
        });
      });
    } else if(chainData.data?.options) {
      chainData.data.options.forEach(opt => {
        const expDate = opt.expiration_date;
        if (!allowedExpiries.has(expDate)) return;
        const strikePrice = opt.strike_price.toString();

        if (!callExpDateMap[expDate]) callExpDateMap[expDate] = {};
        if (!putExpDateMap[expDate]) putExpDateMap[expDate] = {};

        const greeks = opt.greeks || {};

        if (opt.option_type === 'C') {
          callExpDateMap[expDate][strikePrice] = [{
            symbol: opt.symbol,
            delta: greeks.delta || 0,
            gamma: greeks.gamma || 0,
            vega: greeks.vega || 0,
            theta: greeks.theta || 0,
            openInterest: opt.open_interest || 0,
            totalVolume: opt.volume || 0,
            strikePrice: opt.strike_price,
            expirationDate: expDate,
            mark: opt.last || 0
          }];
        } else if (opt.option_type === 'P') {
          putExpDateMap[expDate][strikePrice] = [{
            symbol: opt.symbol,
            delta: greeks.delta || 0,
            gamma: greeks.gamma || 0,
            vega: greeks.vega || 0,
            theta: greeks.theta || 0,
            openInterest: opt.open_interest || 0,
            totalVolume: opt.volume || 0,
            strikePrice: opt.strike_price,
            expirationDate: expDate,
            mark: opt.last || 0
          }];
        }
      });
    }

    const t2 = performance.now();
    console.log(`[GEX] Chain parse: ${(t2-t1).toFixed(0)}ms, ${Object.keys(callExpDateMap).length} expirations`);
    processChain({callExpDateMap, putExpDateMap});
    const t3 = performance.now();
    console.log(`[GEX] processChain: ${(t3-t2).toFixed(0)}ms, ${rawChain.length} strikes`);

    // ── Subscribe 0DTE streamer-symbols to DX Greeks (ATM ONLY) ──
    if (chainData.data?.items) {
      const todayStr = getInsightsTargetExpirationDate ? getInsightsTargetExpirationDate() : (new Date().toISOString().slice(0,10));
      const todayGroup = chainData.data.items.find(g => g['expiration-date'] === todayStr);
      if (todayGroup) {
        // Get current spot price — try multiple sources
        let spotPrice = window.currentSpxPrice || window.__spotPrice || 0;
        if (!spotPrice) {
          spotPrice = dxQuoteCache['SPX']?.last || dxQuoteCache['$SPX']?.last || 0;
        }
        // Fallback: estimate from chain midpoint if spot unknown
        if (!spotPrice && todayGroup.strikes && todayGroup.strikes.length > 0) {
          const strikes = (todayGroup.strikes || []).map(s => parseFloat(s['strike-price'])).filter(s => s > 0).sort((a,b) => a-b);
          if (strikes.length > 0) {
            spotPrice = (strikes[0] + strikes[strikes.length - 1]) / 2;  // midpoint of strikes
            console.log(`[GEX] Spot price estimated from strikes: $${spotPrice.toFixed(0)}`);
          }
        }
        if (!spotPrice) spotPrice = 5800;  // Ultimate fallback

        // Filter to ATM strikes only — ±$200 covers the full GEX chart range
        const atmRange = 200;
        const allStrikes = todayGroup.strikes || [];
        // Store for periodic re-subscription as SPX moves
        window._gexAllStrikes0dte = allStrikes;
        const filteredStrikes = allStrikes.filter(row => {
          const strike = parseFloat(row['strike-price']);
          return strike > 0 && Math.abs(strike - spotPrice) <= atmRange;
        });

        console.log(`[GEX] 0DTE: ${allStrikes.length} total strikes, filtered to ${filteredStrikes.length} ATM (spot: $${spotPrice.toFixed(0)}, range ±${atmRange})`);

        const newSyms = [];
        filteredStrikes.forEach(row => {
          const strike = parseFloat(row['strike-price']);
          if (!strike) return;
          ['call','put'].forEach(right => {
            const opt = row[right];
            if (!opt) return;
            const sym = opt['streamer-symbol'] || opt.symbol || '';
            if (!sym || _spx0dteStreamerSymbols.has(sym)) return;
            _spx0dteStreamerSymbols.add(sym);
            _streamerSymbolToStrike.set(sym, { strike, right });
            newSyms.push(sym);
          });
        });
        if (newSyms.length) {
          const feedTypesBySymbol = {};
          newSyms.forEach(s => { feedTypesBySymbol[s] = ['Quote','Greeks','Summary','Trade']; });
          fetch(window.location.origin + '/proxy/dxlink/subscribe', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ symbols: newSyms, feedTypesBySymbol })
          }).catch(e => console.warn('[GEX] subscribe POST failed:', e));
          dxSubscribe(newSyms, { spxSubscribe: true });
          console.log(`[GEX] Subscribed ${newSyms.length} 0DTE streamer-symbols (ATM ±$${atmRange}) to DX Greeks`);
        }
      }
    }

    const _buildDateKey = getInsightsTargetExpirationDate ? getInsightsTargetExpirationDate() : (new Date().toISOString().slice(0,10));
    if (_initialGreeksReceived) {
      // Greeks already flowing (e.g. page reload mid-session) — render now
      finishGEXCompute(_buildDateKey);
    } else {
      // Wait for first dxLink Greeks batch before rendering
      _pendingFinishGEXDate = _buildDateKey;
      console.log('[GEX] Chain built — waiting for first dxLink Greeks batch before rendering');
      // Safety fallback: render after 8s even if Greeks never arrive
      setTimeout(() => {
        if (_pendingFinishGEXDate) {
          console.warn('[GEX] Greeks timeout — rendering with REST data');
          const d = _pendingFinishGEXDate;
          _pendingFinishGEXDate = null;
          _initialGreeksReceived = true;
          finishGEXCompute(d);
        }
      }, 8000);
    }
    console.log('[GEX] Chain build complete — Greeks streaming via DX WebSocket');
  }catch(e){
    console.error('buildChainOnce error:', e, e.stack);
    log('Error: '+e.message,'error');
    const tag=document.getElementById('status-tag');if(tag){tag.className='tag tag-err';tag.textContent='● '+e.message.slice(0,28);}
    log('Failed to load: '+e.message,'error');

    // Retry once if this is the first attempt
    if(retryCount < 1){
      console.log('[GEX] Retrying chain fetch after 2 seconds...');
      isFetching = false;
      setTimeout(() => buildChainOnce(retryCount + 1), 2000);
      return;
    }
  }finally{
    isFetching=false;
    if(overlay)overlay.classList.remove('visible');
  }
}

// ── PERIODIC GREEK RE-SUBSCRIPTION — subscribes new ATM strikes as SPX moves ──
// Runs every 60s; if SPX has moved beyond the initial ±$200 window, subscribes new strikes
setInterval(function _gexResubscribeNewStrikes() {
  const allStrikes = window._gexAllStrikes0dte;
  if (!allStrikes || !allStrikes.length) return;
  const spot = window.currentSpxPrice || dxQuoteCache['SPX']?.last || dxQuoteCache['$SPX']?.last || 0;
  if (!(spot > 0)) return;
  const newSyms = [];
  allStrikes.forEach(row => {
    const strike = parseFloat(row['strike-price']);
    if (!strike || Math.abs(strike - spot) > 200) return;
    ['call','put'].forEach(right => {
      const opt = row[right];
      if (!opt) return;
      const sym = opt['streamer-symbol'] || opt.symbol || '';
      if (!sym || _spx0dteStreamerSymbols.has(sym)) return;
      _spx0dteStreamerSymbols.add(sym);
      _streamerSymbolToStrike.set(sym, { strike, right });
      _dxQuoteSubSymbols.add(sym);
      newSyms.push(sym);
    });
  });
  if (newSyms.length) {
    const sock = getDXQuoteSocket();
    if (sock.readyState === WebSocket.OPEN) {
      sock.send(JSON.stringify({ type: 'subscribe', symbols: newSyms, spxSubscribe: true }));
    }
    console.log(`[GEX] Re-subscribed ${newSyms.length} new ATM strikes as SPX moved to $${spot.toFixed(0)}`);
  }
}, 60000);

// ── MANUAL REFRESH — Re-render UI + ensure dxlink subscription ──
// Called when user clicks refresh button to double-check all data is present
// Does NOT fetch from REST API (chain already built by buildChainOnce)
let _refreshInProgress = false;  // Prevent refresh from re-fetching chain

function fetchGEX(){
  if(!accessToken)return;
  if(_refreshInProgress) return;  // Already refreshing
  if(rawChain.length === 0){
    // Chain not yet built, do initial build instead
    return buildChainOnce();
  }
  if(isFetching)return;
  isFetching=true;
  _refreshInProgress = true;  // Mark that refresh is in progress

  // Snapshot current Vol GEX BEFORE refreshing so diff shows change
  if(rawChain.length) takeGexSnapshot();
  const overlay=document.getElementById('refresh-overlay');
  if(overlay)overlay.classList.add('visible');
  log('Refreshing…');
  try{
    // CRITICAL: Refresh ONLY re-computes display from cached data
    // NO new chain fetches, NO new subscriptions
    const todayStr = getInsightsTargetExpirationDate ? getInsightsTargetExpirationDate() : (new Date().toISOString().slice(0,10));
    console.log('[GEX] Manual refresh: re-computing from cached data only');

    // Re-compute GEX from existing rawChain (dxlink updates have already modified it)
    finishGEXCompute(todayStr);

    // Re-render the chart
    if(typeof drawOverviewChart === 'function') drawOverviewChart();
    console.log('[GEX] Manual refresh complete');
  }catch(e){
    console.error('fetchGEX error:', e, e.stack);
    log('Error: '+e.message,'error');
    const tag=document.getElementById('status-tag');if(tag){tag.className='tag tag-err';tag.textContent='● '+e.message.slice(0,28);}
  }finally{
    isFetching=false;
    _refreshInProgress = false;  // Refresh complete
    if(overlay)overlay.classList.remove('visible');
    if(!autoRefreshPaused) startCountdown();
  }
}

// ── LAZY DTE CHAIN FETCH — called when user clicks 1/2/3DTE pill ──
async function fetchLazyDTEChain(expiryDate) {
  if (!expiryDate) return;
  if (expiryMap?.[expiryDate] && Object.keys(expiryMap[expiryDate].calls || {}).length) {
    return expiryMap[expiryDate];
  }
  if (gexExpiryFetchCache.has(expiryDate)) return gexExpiryFetchCache.get(expiryDate);
  console.log('[GEX] Lazy-fetching chain for', expiryDate);
  const fetchPromise = (async () => {
    const res = await fetch(`${PROXY}/proxy/api/tt/chains/SPX?range=all&expiration=${encodeURIComponent(expiryDate)}`);
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const chainData = await res.json();
    if (!chainData.data?.items) throw new Error('No items in lazy chain response');
    chainData.data.items.forEach(expGroup => {
      const expDate = expGroup['expiration-date'];
      if (expDate !== expiryDate) return;
      const callMap = {};
      const putMap = {};
      (expGroup.strikes || []).forEach(strikeRow => {
        const strikePrice = String(strikeRow['strike-price']);
        const normalize = opt => {
          const greeks = opt?.greeks || {};
          const pickNum = (...vals) => {
            for (const v of vals) {
              const n = parseFloat(v);
              if (Number.isFinite(n)) return n;
            }
            return 0;
          };
          return ({
          symbol: opt.symbol,
          streamerSymbol: opt['streamer-symbol'] || opt.symbol,
          delta: pickNum(opt.delta, greeks.delta, opt['delta']),
          gamma: pickNum(opt.gamma, greeks.gamma, opt['gamma']),
          vega: pickNum(opt.vega, greeks.vega, opt['vega']),
          theta: pickNum(opt.theta, greeks.theta, opt['theta']),
          openInterest: parseInt(opt['open-interest']) || parseInt(opt.open_interest) || parseInt(opt.openInterest) || 0,
          totalVolume: parseInt(opt.volume) || parseInt(opt['day-volume']) || parseInt(opt.totalVolume) || 0,
          strikePrice: parseFloat(strikePrice),
          expirationDate: expDate,
          mark: opt.last || ((opt.bid || 0) + (opt.ask || 0)) / 2
        });
        };
        if (strikeRow.call) callMap[strikePrice] = [normalize(strikeRow.call)];
        if (strikeRow.put)  putMap[strikePrice]  = [normalize(strikeRow.put)];
      });
      // Merge into expiryMap
      if (!expiryMap[expDate]) expiryMap[expDate] = { calls: {}, puts: {} };
      Object.assign(expiryMap[expDate].calls, callMap);
      Object.assign(expiryMap[expDate].puts, putMap);
      delete expiryMap[expDate]._stub;
      console.log(`[GEX] Lazy load ${expDate}: ${Object.keys(callMap).length} strikes`);
    });
    return expiryMap?.[expiryDate] || null;
  })();
  gexExpiryFetchCache.set(expiryDate, fetchPromise);
  try {
    return await fetchPromise;
  } catch(e) {
    gexExpiryFetchCache.delete(expiryDate);
    console.error('[GEX] fetchLazyDTEChain error:', e);
    throw e;
  }
}


function updateSPXDisplay(quote) {
  if (!quote) return;
  const num = (...vals) => {
    for (const v of vals) {
      const n = parseFloat(v);
      if (Number.isFinite(n)) return n;
    }
    return 0;
  };
  const nyParts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/New_York',
    weekday: 'short',
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  }).formatToParts(new Date());
  const part = type => nyParts.find(p => p.type === type)?.value || '';
  const day = part('weekday');
  const mins = (parseInt(part('hour'), 10) || 0) * 60 + (parseInt(part('minute'), 10) || 0);
  const isWeekday = !['Sat', 'Sun'].includes(day);
  const spxOpen = isWeekday && mins >= 570 && mins < 960;

  const quoteLast = num(quote.lastPrice, quote.last, quote.mark, quote.price, quote.mid);
  const quotePrev = num(quote.closePrice, quote.previousClose, quote.prevClose, quote.close, quote.priorClose);
  if (quotePrev > 0) spxPrevClose = quotePrev;

  let displayPrice = 0;
  let chgBase = 0;

  if (spxOpen) {
    // Market hours: use real SPX quote
    displayPrice = quoteLast > 0 ? quoteLast : (spotPrice > 0 ? spotPrice : 0);
    if (quoteLast > 0) spotPrice = quoteLast;
    chgBase = spxPrevClose;
  } else {
    // Off-hours: derive SPX from ES futures
    // Formula: impliedSPX = esNow - (esClose - spxClose)
    // Use today's closes (post-4pm) or prev-close fallback (pre-9:30am)
    const esClose = esCloseForConv > 0 ? esCloseForConv : esPrevClose;
    const spxClose = spxCloseForConv > 0 ? spxCloseForConv : spxPrevClose;
    const esNow = esPrice > 0 ? esPrice : 0;
    if (esNow > 0 && esClose > 0 && spxClose > 0) {
      displayPrice = esNow - (esClose - spxClose);
    } else if (quoteLast > 0) {
      displayPrice = quoteLast;
    } else if (spotPrice > 0) {
      displayPrice = spotPrice;
    }
    // Change baseline: today's SPX close (post-4pm) or prev-close (pre-9:30am)
    chgBase = spxClose > 0 ? spxClose : spxPrevClose;
  }

  if (displayPrice > 0) spotPrice = displayPrice;
  if (spotPrice > 0 && window.GEX_SPOTS) window.GEX_SPOTS.SPX = spotPrice;
  else if (spotPrice > 0 && typeof GEX_SPOTS !== 'undefined') GEX_SPOTS.SPX = spotPrice;

  const pxEl = document.getElementById('spx-price');
  if (pxEl) {
    if (displayPrice > 0) {
      pxEl.textContent = displayPrice.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
      pxEl.title = spxOpen ? '' : `ES-implied (ES: ${esPrice.toFixed(2)})`;
    } else {
      pxEl.textContent = '—';
    }
  }

  const chEl = document.getElementById('spx-change');
  if (chEl) {
    const chg = (displayPrice > 0 && chgBase > 0)
      ? displayPrice - chgBase
      : num(quote.change, quote.netChange);
    const pct = (chgBase > 0 && displayPrice > 0)
      ? ((displayPrice - chgBase) / chgBase) * 100
      : num(quote.changePercent, quote.netPercentChange, quote.netPercentChangeInDouble);
    const chgSign = chg >= 0 ? '+' : '';
    chEl.textContent = chgSign + chg.toFixed(2) + ' (' + chgSign + pct.toFixed(2) + '%)';
    chEl.style.color = chg >= 0 ? '#00e676' : '#ff4757';
  }
}

function handleDXLinkQuote(quote) {
  if (quote.eventSymbol === 'SPX' || quote.eventSymbol === '$SPX') {
    // Check if market is open
    let spxOpen = false;
    try {
      const dtf = new Intl.DateTimeFormat('en-US', {
        timeZone: 'America/New_York',
        weekday: 'short',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false
      });
      const nyParts = typeof dtf.formatToParts === 'function' ? dtf.formatToParts(new Date()) : [];
      const part = type => nyParts.find(p => p.type === type)?.value || '';
      const day = part('weekday');
      const mins = (parseInt(part('hour'), 10) || 0) * 60 + (parseInt(part('minute'), 10) || 0);
      const isWeekday = !['Sat', 'Sun'].includes(day);
      spxOpen = isWeekday && mins >= 570 && mins < 960;
    } catch (e) {
      console.warn('[DX] Market hours check failed:', e.message);
    }

    // Quote events from dxLink use bidPrice/askPrice, not 'last'
    const mid = (quote.bidPrice > 0 && quote.askPrice > 0)
      ? (quote.bidPrice + quote.askPrice) / 2
      : 0;
    const newPrice = quote.last || quote.price || mid;

    // Only use SPX quote during market hours. After hours: ignore (use ES conversion instead)
    if (newPrice > 0 && spxOpen) {
      const wasZero = !(spotPrice > 0);
      spotPrice = newPrice;
      // If spotPrice was 0 when computeGEXMulti last ran, all bars are 0 — recompute now
      if (wasZero && rawChain.length > 0) {
        console.log('[DX] spotPrice became non-zero, re-running GEX computation:', spotPrice);
        if (typeof applyDTEMode === 'function') applyDTEMode();
      }
    }

    updateSPXDisplay({
      lastPrice: newPrice > 0 ? newPrice : (spotPrice > 0 ? spotPrice : 0),
      change: quote.change,
      changePercent: quote.changePercent
    });
    lastDXLinkUpdate = Date.now();
    console.log('[DX] SPX spotPrice updated:', spotPrice, '(src: last/price/mid, market open:', spxOpen, ')');
  }
}

