// ── CHART VIEW TOGGLE ─────────────────────────────────────────────
function setChartView(view, el){
  chartView = view;
  el.closest('.tabs').querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));
  el.classList.add('active');
  const barCanvas     = document.getElementById('gex-chart');
  const profileCanvas = document.getElementById('gex-profile-canvas');
  const cw            = document.querySelector('.chart-canvas-wrap');
  if(view === 'profile'){
    if(barCanvas)barCanvas.style.display='none';
    if(cw)cw.style.display='none';
    if(profileCanvas)profileCanvas.style.display='block';
    if(rawChain.length)renderGEXProfile();
  } else {
    if(barCanvas)barCanvas.style.display='';
    if(cw)cw.style.display='';
    if(profileCanvas)profileCanvas.style.display='none';
    if(rawChain.length)renderChart();
  }
}

// GEX profile zoom/pan state
let gexZoom = 1.0;
let gexPan = 0;
let gexDragging = false;
let gexDragStartX = 0;
let gexInitialized = false;
let gexRenderRAF = null;

function scheduleGEXRender(){
  if(gexRenderRAF) return;
  gexRenderRAF = requestAnimationFrame(()=>{
    gexRenderRAF = null;
    renderGEXProfile();
  });
}

function resetGEXProfileView(){
  gexZoom = 1;
  gexPan = 0;
  gexInitialized = false;
}

function renderGEXProfile(){
  const canvas = document.getElementById('gex-profile-canvas');
  if(!canvas || !rawChain.length) return;

  const parent = canvas.parentElement;
  const W = parent ? parent.clientWidth  : 900;
  const H = parent ? parent.clientHeight : 500;
  canvas.width  = W;
  canvas.height = H;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0,0,W,H);

  // Build sorted data (low to high strike = left to right like SpotGamma)
  let data = [...rawChain].sort((a,b) => a.strike - b.strike);
  
  // Initialize: default zoom centered on spot, showing ~10% range around spot
  if(!gexInitialized && spotPrice > 0 && data.length > 0){
    const minS0 = data[0].strike;
    const maxS0 = data[data.length-1].strike;
    const fullRange = maxS0 - minS0;
    if(fullRange > 0){
      // Show ~10% around spot OR 60 strikes worth, whichever is wider
      const strikeStep = data.length > 1 ? (maxS0 - minS0) / (data.length - 1) : 5;
      const desiredRange = Math.max(spotPrice * 0.05, strikeStep * 60, fullRange * 0.2);
      gexZoom = Math.max(1, Math.min(10, fullRange / desiredRange));
      // Pan so spot is centered
      const centerStrike = (minS0 + maxS0) / 2;
      gexPan = (spotPrice - centerStrike) / (fullRange / 2);
      gexPan = Math.max(-1, Math.min(1, gexPan));
    }
    gexInitialized = true;
  }

  const PAD = { t:40, r:20, b:50, l:72 };
  const cW  = W - PAD.l - PAD.r;
  const cH  = H - PAD.t - PAD.b;

  const minS = data[0].strike, maxS = data[data.length-1].strike;

  const strikeRange = maxS - minS;
  const viewWidth = strikeRange / gexZoom;
  const viewCenter = minS + strikeRange * 0.5 + (gexPan * strikeRange * 0.5);
  let viewMin = viewCenter - viewWidth * 0.5;
  let viewMax = viewCenter + viewWidth * 0.5;
  if(viewMin < minS){ viewMax += minS - viewMin; viewMin = minS; }
  if(viewMax > maxS){ viewMin -= viewMax - maxS; viewMax = maxS; }
  viewMin = Math.max(minS, viewMin);
  viewMax = Math.min(maxS, viewMax);

  // Only use visible strikes for y-axis scaling
  const visibleData = data.filter(d => d.strike >= viewMin && d.strike <= viewMax);
  const yScaleData = visibleData.length > 1 ? visibleData : data;
  let minG = 0, maxG = 0;
  for(let i = 0; i < yScaleData.length; i++){
    const v = yScaleData[i].netGEX;
    if(v < minG) minG = v;
    if(v > maxG) maxG = v;
  }
  minG *= 1.08; maxG *= 1.08;
  const range = maxG - minG || 1;

  const xFor = s => PAD.l + ((s - viewMin)/(viewMax - viewMin))*cW;
  const yFor = g => PAD.t + cH - ((g - minG)/range)*cH;
  const yZero = yFor(0);

  // ── Background shading: red left of flip, green right ──
  const flipX = flipPoint ? xFor(flipPoint) : xFor((minS+maxS)/2);

  // Red zone (high vol - negative GEX side, left of flip)
  const redGrad = ctx.createLinearGradient(PAD.l, 0, flipX, 0);
  redGrad.addColorStop(0, 'rgba(204,34,51,0.18)');
  redGrad.addColorStop(1, 'rgba(204,34,51,0.04)');
  ctx.fillStyle = redGrad;
  ctx.fillRect(PAD.l, PAD.t, flipX-PAD.l, cH);

  // Green zone (low vol - positive GEX side, right of flip)
  const greenGrad = ctx.createLinearGradient(flipX, 0, PAD.l+cW, 0);
  greenGrad.addColorStop(0, 'rgba(31,174,94,0.04)');
  greenGrad.addColorStop(1, 'rgba(31,174,94,0.18)');
  ctx.fillStyle = greenGrad;
  ctx.fillRect(flipX, PAD.t, PAD.l+cW-flipX, cH);

  // ── Grid ──
  ctx.strokeStyle = '#1a2535'; ctx.lineWidth = 0.5;
  // Horizontal grid lines
  const gexStep = getNiceStep(range/6);
  const firstG  = Math.ceil(minG/gexStep)*gexStep;
  for(let g=firstG; g<=maxG; g+=gexStep){
    const y = yFor(g); if(y<PAD.t||y>PAD.t+cH) continue;
    ctx.beginPath(); ctx.moveTo(PAD.l, y); ctx.lineTo(PAD.l+cW, y); ctx.stroke();
    ctx.fillStyle='#3a5570'; ctx.font='10px Arial'; ctx.textAlign='right';
    const lbl = Math.abs(g)>=1e9?(g/1e9).toFixed(1)+'G':Math.abs(g)>=1e6?(g/1e6).toFixed(0)+'M':'0';
    ctx.fillText(lbl, PAD.l-6, y+3);
  }
  // Vertical grid lines
  const sStep = 50;
  const firstS = Math.ceil(viewMin/sStep)*sStep;
  for(let s=firstS; s<=viewMax; s+=sStep){
    const x=xFor(s);
    ctx.strokeStyle='#1a2535'; ctx.lineWidth=0.5;
    ctx.beginPath(); ctx.moveTo(x,PAD.t); ctx.lineTo(x,PAD.t+cH); ctx.stroke();
    ctx.fillStyle='#3a5570'; ctx.font='10px Arial'; ctx.textAlign='center';
    ctx.fillText(s.toLocaleString(), x, PAD.t+cH+16);
  }

  // ── Zero line ──
  ctx.strokeStyle = 'rgba(180,180,180,0.4)'; ctx.lineWidth = 1;
  ctx.setLineDash([4,3]);
  ctx.beginPath(); ctx.moveTo(PAD.l,yZero); ctx.lineTo(PAD.l+cW,yZero); ctx.stroke();
  ctx.setLineDash([]);
  ctx.fillStyle='#5a7a99'; ctx.font='11px Arial'; ctx.textAlign='left';
  ctx.fillText('0.00',PAD.l+3,yZero-3);

  // ── Average GEX line ──
  let avgSum = 0;
  for(let i = 0; i < yScaleData.length; i++) avgSum += yScaleData[i].netGEX;
  const avgGEX = yScaleData.length ? avgSum / yScaleData.length : 0;
  const yAvg   = yFor(avgGEX);
  ctx.strokeStyle = 'rgba(255,179,0,0.7)'; ctx.lineWidth = 1.5;
  ctx.setLineDash([6,4]);
  ctx.beginPath(); ctx.moveTo(PAD.l,yAvg); ctx.lineTo(PAD.l+cW,yAvg); ctx.stroke();
  ctx.setLineDash([]);
  ctx.fillStyle='#ffb300'; ctx.font='bold 9px Arial'; ctx.textAlign='right';
  const avgLbl=(Math.abs(avgGEX)>=1e9?(avgGEX/1e9).toFixed(2)+'G':Math.abs(avgGEX)>=1e6?(avgGEX/1e6).toFixed(0)+'M':'~0');
  ctx.fillText('Avg '+avgLbl, PAD.l+cW-4, yAvg-4);

  // ── High Vol / Low Vol labels ──
  ctx.font='bold 11px Arial'; ctx.textAlign='left';
  ctx.fillStyle='rgba(204,34,51,0.6)';
  ctx.fillText('High Volatility', PAD.l+8, PAD.t+22);
  ctx.fillStyle='rgba(31,174,94,0.6)';
  ctx.textAlign='right';
  ctx.fillText('Low Volatility', PAD.l+cW-8, PAD.t+22);

  // Filter data to visible range with 1-point padding for smooth edges
  const visIdx = data.findIndex(d => d.strike >= viewMin);
  const startIdx = Math.max(0, visIdx - 1);
  const endIdx = data.findIndex((d,i) => i > startIdx && d.strike > viewMax);
  const drawData = endIdx === -1 ? data.slice(startIdx) : data.slice(startIdx, endIdx + 1);
  if(!drawData.length) return;
  
  // Clip to chart area so curve doesn't bleed into padding
  ctx.save();
  ctx.beginPath();
  ctx.rect(PAD.l, PAD.t, cW, cH);
  ctx.clip();

  // ── GEX curve (smooth line) ──
  ctx.beginPath();
  ctx.strokeStyle = '#e8edf5'; ctx.lineWidth = 2.5;
  drawData.forEach((d,i)=>{
    const x=xFor(d.strike), y=yFor(d.netGEX);
    i===0 ? ctx.moveTo(x,y) : ctx.lineTo(x,y);
  });
  ctx.stroke();

  // Fill under/over curve
  // Positive area (above zero) = green fill
  ctx.beginPath();
  drawData.forEach((d,i)=>{const x=xFor(d.strike),y=yFor(d.netGEX);i===0?ctx.moveTo(x,Math.min(y,yZero)):ctx.lineTo(x,Math.min(y,yZero));});
  ctx.lineTo(xFor(drawData[drawData.length-1].strike),yZero);
  ctx.lineTo(xFor(drawData[0].strike),yZero);
  ctx.closePath();
  const posGrad=ctx.createLinearGradient(0,PAD.t,0,yZero);
  posGrad.addColorStop(0,'rgba(31,174,94,0.25)');
  posGrad.addColorStop(1,'rgba(31,174,94,0.0)');
  ctx.fillStyle=posGrad; ctx.fill();

  // Negative area (below zero) = red fill
  ctx.beginPath();
  drawData.forEach((d,i)=>{const x=xFor(d.strike),y=yFor(d.netGEX);i===0?ctx.moveTo(x,Math.max(y,yZero)):ctx.lineTo(x,Math.max(y,yZero));});
  ctx.lineTo(xFor(drawData[drawData.length-1].strike),yZero);
  ctx.lineTo(xFor(drawData[0].strike),yZero);
  ctx.closePath();
  const negGrad=ctx.createLinearGradient(0,yZero,0,PAD.t+cH);
  negGrad.addColorStop(0,'rgba(204,34,51,0.0)');
  negGrad.addColorStop(1,'rgba(204,34,51,0.25)');
  ctx.fillStyle=negGrad; ctx.fill();

  // ── GEX curve on top again (so fill is behind) ──
  ctx.beginPath();
  ctx.strokeStyle='#e8edf5'; ctx.lineWidth=2.5;
  drawData.forEach((d,i)=>{const x=xFor(d.strike),y=yFor(d.netGEX);i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);});
  ctx.stroke();

  if(showOverviewFlipCurve){
    const profileExp = getTimeToExpiryYears(selectedExpiry || data[0]?.expirationDate || data[0]?.expiration_date || data[0]?.expiryDate);
    const profileSamples = Math.max(36, Math.min(90, drawData.length * 2));
    const profilePoints = [];
    let profileMin = Infinity;
    let profileMax = -Infinity;
    for(let i=0;i<profileSamples;i++){
      const s = viewMin + (viewMax - viewMin) * (profileSamples === 1 ? 0 : i / (profileSamples - 1));
      let total = 0;
      for(let j=0;j<data.length;j++){
        const r = data[j];
        const callGamma = calcBlackScholesGamma(s, r.strike, r.callIV || r.putIV || 0, profileExp);
        const putGamma = calcBlackScholesGamma(s, r.strike, r.putIV || r.callIV || 0, profileExp);
        total += calcDollarGammaExposure(callGamma, r.callOI || 0, s);
        total -= calcDollarGammaExposure(putGamma, r.putOI || 0, s);
      }
      profilePoints.push({ x: xFor(s), y: total });
      if(total < profileMin) profileMin = total;
      if(total > profileMax) profileMax = total;
    }
    const profileRange = (profileMax - profileMin) || 1;
    const yProfile = v => PAD.t + cH - ((v - profileMin) / profileRange) * cH;
    ctx.save();
    ctx.beginPath();
    ctx.strokeStyle = '#00e5ff';
    ctx.lineWidth = 2;
    ctx.setLineDash([2,4]);
    profilePoints.forEach((p,i)=>{ const y = yProfile(p.y); i===0 ? ctx.moveTo(p.x,y) : ctx.lineTo(p.x,y); });
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.restore();
  }

  ctx.restore();

  const peakRow = drawData.reduce((best, row) => (
    !best || Math.abs(row.netGEX || 0) > Math.abs(best.netGEX || 0) ? row : best
  ), null);
  if (peakRow) {
    const peakX = xFor(peakRow.strike);
    const peakY = yFor(peakRow.netGEX || 0);
    const peakLabel = peakRow.strike.toLocaleString();
    const drawRoundedRect = (x, y, w, h, r) => {
      const radius = Math.min(r, w / 2, h / 2);
      ctx.beginPath();
      ctx.moveTo(x + radius, y);
      ctx.lineTo(x + w - radius, y);
      ctx.arcTo(x + w, y, x + w, y + radius, radius);
      ctx.lineTo(x + w, y + h - radius);
      ctx.arcTo(x + w, y + h, x + w - radius, y + h, radius);
      ctx.lineTo(x + radius, y + h);
      ctx.arcTo(x, y + h, x, y + h - radius, radius);
      ctx.lineTo(x, y + radius);
      ctx.arcTo(x, y, x + radius, y, radius);
      ctx.closePath();
    };
    ctx.save();
    ctx.font = 'bold 10px Arial';
    const labelW = ctx.measureText(peakLabel).width + 14;
    const labelH = 18;
    const labelX = Math.max(PAD.l + 2, Math.min(PAD.l + cW - labelW - 2, peakX - labelW / 2));
    const labelY = Math.max(PAD.t + 2, peakY - 22);
    ctx.fillStyle = 'rgba(5,8,13,0.92)';
    drawRoundedRect(labelX, labelY, labelW, labelH, 6);
    ctx.fill();
    ctx.strokeStyle = '#e8edf5';
    ctx.lineWidth = 1;
    drawRoundedRect(labelX, labelY, labelW, labelH, 6);
    ctx.stroke();
    ctx.fillStyle = '#e8edf5';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
  ctx.fillText(peakLabel, labelX + labelW / 2, labelY + labelH / 2 + 0.5);
  ctx.restore();
  }

  // ── Flip/zero gamma vertical line ──
  if(flipPoint && showOverviewFlipCurve){
    const xFlip=xFor(flipPoint);
    ctx.strokeStyle='rgba(255,255,255,0.5)'; ctx.lineWidth=1; ctx.setLineDash([3,3]);
    ctx.beginPath(); ctx.moveTo(xFlip,PAD.t); ctx.lineTo(xFlip,PAD.t+cH); ctx.stroke();
    ctx.setLineDash([]);
    ctx.fillStyle='rgba(255,255,255,0.7)'; ctx.font='9px Arial'; ctx.textAlign='center';
    ctx.fillText('Zero Gamma', xFlip, PAD.t+10);
    ctx.fillText(flipPoint.toFixed(0), xFlip, PAD.t+cH+30);
  }

  // ── Spot price vertical line ──
  if(spotPrice>=viewMin&&spotPrice<=viewMax){
    const xSpot=xFor(spotPrice);
    ctx.strokeStyle='rgba(255,179,0,0.8)'; ctx.lineWidth=1.5; ctx.setLineDash([4,3]);
    ctx.beginPath(); ctx.moveTo(xSpot,PAD.t); ctx.lineTo(xSpot,PAD.t+cH); ctx.stroke();
    ctx.setLineDash([]);
  }

  // ── Axis labels ──
  ctx.fillStyle='#5a7a99'; ctx.font='11px Arial'; ctx.textAlign='center';
  ctx.fillText('Strike', PAD.l+cW/2, H-6);
  ctx.save(); ctx.translate(14,PAD.t+cH/2); ctx.rotate(-Math.PI/2);
  ctx.fillText('Net GEX', 0, 0); ctx.restore();

  // ── Title ──
  ctx.fillStyle='#a8b8cc'; ctx.font='bold 12px Arial'; ctx.textAlign='center';
  const dte=selectedExpiry?getDTE(selectedExpiry):null;
  ctx.fillText('SPX Gamma Exposure | '+(selectedExpiry||''), W/2, PAD.t-18);
}

// GEX profile mouse handlers - setup once
function setupGEXProfileHandlers(){
  const canvas = document.getElementById('gex-profile-canvas');
  if(!canvas || canvas.dataset.gexProfileHandlers === '1') return;
  canvas.dataset.gexProfileHandlers = '1';
  
  canvas.style.cursor = 'grab';
  
  canvas.addEventListener('wheel', e => {
    if(!(e.ctrlKey || e.metaKey || e.shiftKey)) return;
    e.preventDefault();
    const delta = e.deltaY > 0 ? 0.9 : 1.1;
    gexZoom = Math.max(1, Math.min(10, gexZoom * delta));
    scheduleGEXRender();
  }, { passive: false });
  
  canvas.addEventListener('mousedown', e => {
    gexDragging = true;
    gexDragStartX = e.clientX;
    canvas.style.cursor = 'grabbing';
  });
  
  window.addEventListener('mouseup', () => {
    if(gexDragging){
      gexDragging = false;
      canvas.style.cursor = 'grab';
    }
  });
  
  canvas.addEventListener('mousemove', e => {
    if(!gexDragging) return;
    const dx = e.clientX - gexDragStartX;
    gexDragStartX = e.clientX;
    const panSensitivity = 0.002;
    gexPan -= dx * panSensitivity / Math.max(gexZoom, 1);
    gexPan = Math.max(-1, Math.min(1, gexPan));
    scheduleGEXRender();
  });
  
  // Double-click to reset
  canvas.addEventListener('dblclick', () => {
    gexZoom = 1.0;
    gexPan = 0;
    gexInitialized = false; // re-center on spot
    scheduleGEXRender();
  });
}
if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', setupGEXProfileHandlers);
else setupGEXProfileHandlers();



// ── EST CLOCK ──────────────────────────────────────────────────────
function updateESTClock(){
  const now  = new Date();
  const est  = new Date(now.toLocaleString('en-US',{timeZone:'America/New_York'}));
  const h    = est.getHours(), m=est.getMinutes(), s=est.getSeconds();
  const hStr = h%12||12;
  const mStr = String(m).padStart(2,'0');
  const sStr = String(s).padStart(2,'0');
  const ampm = h<12?'AM':'PM';
  const clockEl   = document.getElementById('est-clock');
  const sessionEl = document.getElementById('est-session');
  const newClockText = hStr+':'+mStr+':'+sStr+' '+ampm;
  if(clockEl && clockEl.textContent !== newClockText) clockEl.textContent = newClockText;
  // Session label
  const mins = h*60+m;
  let sessionLabel='ET';
  if(mins>=240&&mins<570) sessionLabel='PRE-MARKET';       // 4:00-9:30
  else if(mins>=570&&mins<960) sessionLabel='MARKET OPEN'; // 9:30-4:00
  else if(mins>=960&&mins<1200) sessionLabel='AFTER HOURS';// 4:00-8:00
  else sessionLabel='CLOSED';
  if(sessionEl){
    if(sessionEl.textContent !== sessionLabel) sessionEl.textContent = sessionLabel;
    const newColor = sessionLabel==='MARKET OPEN'?'var(--green)':sessionLabel==='PRE-MARKET'?'var(--amber)':sessionLabel==='AFTER HOURS'?'var(--blue)':'var(--text3)';
    if(sessionEl.dataset._lastColor !== newColor){
      sessionEl.style.color = newColor;
      sessionEl.dataset._lastColor = newColor;
    }
  }
}
setInterval(updateESTClock,1000);
updateESTClock();

// ── PER-SYMBOL GEX (nearest expiry gamma dominant level) ──────────
// For SPX/SPY/ES we use our rawChain data
// For stocks we fetch nearest-expiry chain gamma summary
 // {sym: {flip,wall,ts}}
const STOCK_SYMS  = ['QQQ','AAPL','AMD','AMZN','GOOGL','META','MSFT','NVDA','TSLA'];
const GEX_SIGNAL_STATE = window.__gexSignalState || (window.__gexSignalState = { SPX: null, stock: {} });

// Format a GEX sub-label: Flip + dominant wall (highest of call/put)


function gexSubLabel(flip, callWall, putWall){
  const fmt=v=>v!=null?Number(v).toLocaleString('en-US',{maximumFractionDigits:0}):'—';
  let parts=[];
  if(callWall) parts.push(`<span class="gx-call">C <b>${fmt(callWall)}</b></span>`);
  if(putWall)  parts.push(`<span class="gx-put">P <b>${fmt(putWall)}</b></span>`);
  return parts.length?parts.join(''):'<span style="color:#1a2a3a">—</span>';
}

function _feedAddGexSignal(side, source, message, meta = {}){
  if(typeof window.addFeedItem !== 'function') return;
  window.addFeedItem({
    kind: 'signal',
    side,
    source,
    message,
    meta
  });
}

function _emitMvcSignal(prevMvc, currentMvc){
  if(!prevMvc || !currentMvc) return;
  const prevStrike = Number(prevMvc.strike || 0);
  const currentStrike = Number(currentMvc.strike || 0);
  const prevValue = Number(prevMvc.value || 0);
  const currentValue = Number(currentMvc.value || 0);
  const prevVolume = Number(prevMvc.volume || 0);
  const currentVolume = Number(currentMvc.volume || 0);
  if(prevStrike === currentStrike && prevValue === currentValue && prevVolume === currentVolume) return;
  _feedPushSimpleSignal(
    'MVC',
    `MVC changed to ${currentStrike ? currentStrike.toLocaleString() : '—'} while value was ${currentValue.toLocaleString('en-US', { maximumFractionDigits: 0 })}.`,
    'signal',
    ['CHANGE', 'MVC'],
    { type: 'mvcChange', prev: prevMvc, current: currentMvc }
  );
}

function _emitGexWallSignals(sym, current, prev){}

async function fetchStockGEX(sym){
  const el=document.getElementById('qgex-'+sym);
  if(!el||!accessToken) return;

  // Use cache if fresh (5 min)
  const cached=stockGEXCache[sym];
  if(cached&&(Date.now()-cached.ts)<300000){
    el.innerHTML=gexSubLabel(cached.flip, cached.callWall, cached.putWall);
    return;
  }
  el.innerHTML='<span style="color:#2a4060">loading…</span>';
  try{
    // Fetch from TastyTrade /tt/chains (returns Schwab-format callExpDateMap/putExpDateMap)
    const res = await proxyGet(+ '/proxy/api/tt/chains/'+sym+'?range=50');
    const cd = await res.json();
    
    // Get underlying price
    const upx = cd.underlyingPrice || spotPrice || 0;
    if(!upx) { el.innerHTML='<span style="color:#2a4060">no price</span>'; return; }

    // Find nearest expiry
    const cExp=Object.keys(cd.callExpDateMap||{}).sort()[0];
    const pExp=Object.keys(cd.putExpDateMap||{}).sort()[0];
    const calls=cExp?cd.callExpDateMap[cExp]:{};
    const puts =pExp?cd.putExpDateMap[pExp]:{};

    // Compute per-strike GEX
    const strikes={};
    Object.entries(calls).forEach(([k,v])=>{
      const opt=Array.isArray(v)?v[0]:v;
      const s=parseFloat(k);
      if(!strikes[s])strikes[s]={callGEX:0,putGEX:0};
      const pos=(opt.openInterest||0)>0?opt.openInterest:opt.totalVolume||0;
      strikes[s].callGEX=(opt.gamma||0)*pos*100*upx*upx*0.01;
    });
    Object.entries(puts).forEach(([k,v])=>{
      const opt=Array.isArray(v)?v[0]:v;
      const s=parseFloat(k);
      if(!strikes[s])strikes[s]={callGEX:0,putGEX:0};
      const pos=(opt.openInterest||0)>0?opt.openInterest:opt.totalVolume||0;
      strikes[s].putGEX=(opt.gamma||0)*pos*100*upx*upx*0.01;
    });

    const arr=Object.entries(strikes).map(([s,v])=>({strike:+s,callGEX:v.callGEX,putGEX:v.putGEX,netGEX:v.callGEX-v.putGEX}));
    if(!arr.length){el.innerHTML='<span style="color:#2a4060">no data</span>';return;}

    const sorted=arr.sort((a,b)=>a.strike-b.strike);
    let flip=null;
    for(let i=0;i<sorted.length-1;i++){
      if(sorted[i].netGEX<=0&&sorted[i+1].netGEX>=0){
        const neg=Math.abs(sorted[i].netGEX),pos=sorted[i+1].netGEX;
        flip=sorted[i+1].strike-((sorted[i+1].strike-sorted[i].strike)*pos/(pos+neg));
        break;
      }
    }
    const callWall=arr.reduce((a,b)=>b.callGEX>a.callGEX?b:a,arr[0]).strike;
    const putWall =arr.reduce((a,b)=>b.putGEX>a.putGEX?b:a,arr[0]).strike;

    const nextState = { spot: upx, flip, callWall, putWall, ts: Date.now() };
    _emitGexWallSignals(sym, nextState, GEX_SIGNAL_STATE.stock[sym] || null);
    GEX_SIGNAL_STATE.stock[sym] = nextState;
    stockGEXCache[sym] = { flip, callWall, putWall, ts: Date.now() };
    el.innerHTML=gexSubLabel(flip, callWall, putWall);
  }catch(e){
    el.innerHTML='<span style="color:#2a4060">—</span>';
  }
}

