// Economic events — loaded dynamically from Next.js API. Fallback to empty array.
let ECON_EVENTS = [];

(async function loadEconEvents() {
  try {
    const res = await fetch('/api/econ-calendar');
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    if (Array.isArray(data)) {
      ECON_EVENTS.push(...data);
      // Re-render if calendar already initialized
      if (typeof renderEconCalendar === 'function') renderEconCalendar();
    }
  } catch(e) {
    console.warn('[EconCalendar] Failed to load from API:', e.message);
  }
})();

// Determines event urgency class for the countdown badge
function _econUrgency(ms){
  if(ms < 0)          return { cls:'#1a2a1a', txt:'#2a5a2a', label:'Past' };
  if(ms < 60000)      return { cls:'#0a2a0a', txt:'#00e676', label: Math.floor(ms/1000)+'s' };
  if(ms < 3600000)    return { cls:'#1a1a08', txt:'#ffb300', label: Math.floor(ms/60000)+'m '+Math.floor((ms%60000)/1000)+'s' };
  const d=Math.floor(ms/86400000), h=Math.floor((ms%86400000)/3600000), m=Math.floor((ms%3600000)/60000);
  const label = d>0 ? d+'d '+h+'h '+m+'m' : h+'h '+m+'m';
  const cls = ms<7200000?'#1a1000':'#0d1520';
  const txt = ms<7200000?'#ffb300':'#29b6f6';
  return { cls, txt, label };
}

function _econEventDT(ev){
  const [h,m]=ev.time.split(':').map(Number);
  // Parse date as local midnight then set hours to avoid DST shifts
  const d=new Date(ev.date+'T00:00:00');
  d.setHours(h,m,0,0);
  return d;
}

function _econFmtTime(time24){
  const [h,m]=time24.split(':').map(Number);
  const ampm=h>=12?'pm':'am';
  const hr=h>12?h-12:(h===0?12:h);
  return hr+':'+(m<10?'0':'')+m+' '+ampm+' ET';
}

// Group events by date label
function _econGroupByDay(events){
  const days={}, order=[];
  events.forEach(ev=>{
    const d=new Date(ev.date+'T12:00:00');
    const lbl=d.toLocaleDateString('en-US',{weekday:'long',month:'short',day:'numeric'});
    if(!days[lbl]){ days[lbl]=[]; order.push(lbl); }
    days[lbl].push(ev);
  });
  return order.map(lbl=>({ lbl, events:days[lbl].slice().sort((a,b)=>a.time.localeCompare(b.time)) }));
}

let _econTimer=null, _econQuote='';

async function fetchQuoteOfDay(){
  try{
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 2000); // 2 second timeout

    const res = await fetch(window.location.origin + '/proxy/api/quote-of-day', { signal: controller.signal });
    clearTimeout(timeoutId);

    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const data = await res.json();
    if (data.quote) _econQuote = data.quote;
  } catch(e) {
    console.log('Quote fetch:', e.message);
    // Continue anyway - quote is optional
  }
}

function _econFormatQuote(rawQuote){
  const input = String(rawQuote || '').trim();
  if(!input) return '';

  let quote = input
    .replace(/[“”]/g, '"')
    .replace(/[‘’]/g, "'")
    .trim();

  let author = '';
  const dashMatch = quote.match(/\s[-–—]\s([^"-][^-–—]+)$/);
  if(dashMatch){
    author = dashMatch[1].trim().replace(/^"+|"+$/g, '');
    quote = quote.slice(0, dashMatch.index).trim();
  }

  quote = quote.replace(/^"+|"+$/g, '').trim();
  quote = quote.replace(/"\s*$/g, '').trim();

  if(!quote) return author ? `- ${author}` : '';
  return author ? `"${quote}" - ${author}` : `"${quote}"`;
}

function _econGetSnapshotEarnings(todayStr){
  const fromWindow = Array.isArray(window.ECON_EARNINGS_EVENTS) ? window.ECON_EARNINGS_EVENTS : [];
  let fromStorage = [];
  try {
    const raw = localStorage.getItem('econSnapshotEarnings');
    const parsed = raw ? JSON.parse(raw) : [];
    if (Array.isArray(parsed)) fromStorage = parsed;
  } catch (e) {}

  return [...fromWindow, ...fromStorage]
    .filter(item => item && item.date === todayStr && item.symbol)
    .map(item => ({
      time: String(item.time || item.session || 'TBA'),
      symbol: String(item.symbol || '').toUpperCase(),
      name: String(item.name || item.company || item.symbol || '')
    }))
    .slice(0, 6);
}

function _econSnapshotPriority(ev){
  const name = String(ev?.name || '').toLowerCase();
  const time = String(ev?.time || '');
  let score = 0;

  if (name.includes('non-farm payroll') || name.includes('nonfarm payroll') || name.includes('employment report')) score += 2000;
  if (name.includes('unemployment rate')) score += 1990;
  if (name.includes('hourly wages') || name.includes('average hourly earnings')) score += 1980;
  if (name.includes('cpi') || name.includes('consumer price index') || name.includes('core cpi')) score += 1900;
  if (name.includes('fomc') || name.includes('fed rate decision') || name.includes('interest rate decision') || name.includes('dot plot') || name.includes('powell press conference')) score += 1800;
  if (name.includes('gdp')) score += 1700;
  if (name.includes('ppi') || name.includes('producer price index')) score += 1600;
  if (name.includes('ism manufacturing')) score += 1500;
  if (name.includes('ism services')) score += 1400;
  if (name.includes('retail sales')) score += 1300;
  if (name.includes('adp')) score += 1200;
  if (name.includes('jobless claims')) score += 1100;
  if (name.includes('pce price') || name.includes('personal consumption expenditures') || name.includes('core pce') || name.includes('pce inflation')) score += 1000;
  if (name.includes('durable goods')) score += 900;
  if (name.includes('industrial production')) score += 800;
  if (name.includes('housing starts') || name.includes('building permits')) score += 700;
  if (name.includes('existing home sales')) score += 600;
  if (name.includes('jolts') || name.includes('job openings')) score += 500;
  if (name.includes('consumer confidence') || name.includes('michigan sentiment')) score += 400;
  if (name.includes('factory orders')) score += 300;
  if (name.includes('trade balance')) score += 200;
  if (name.includes('ecb') || name.includes('boe') || name.includes('central bank') || name.includes('global cpi') || name.includes('global gdp') || name.includes('global pmi')) score += 100;

  if (name.includes('speech')) score -= 120;
  if (time === '08:30') score += 45;
  if (time === '10:00') score += 20;
  if (ev?.noTime === true) score -= 50;

  return score;
}

function _econPickFeaturedEvent(events){
  if(!Array.isArray(events) || !events.length) return null;
  return events.slice().sort((a,b)=>{
    const scoreDiff = _econSnapshotPriority(b) - _econSnapshotPriority(a);
    if(scoreDiff !== 0) return scoreDiff;
    return a.time.localeCompare(b.time);
  })[0];
}

