function renderEconCalendar(){
  const body=document.getElementById('calendar-body');
  if(!body) return;
  const now=new Date();
  const groups=_econGroupByDay(ECON_EVENTS);
  let html=_econQuote?`<div style="padding:8px 4px 12px;font-size:11px;color:#ffffff;font-style:italic;border-bottom:1px solid #0d1825;margin-bottom:8px">${_econQuote}</div>`:'';
  // Find today's date string to highlight
  const todayStr=now.toISOString().slice(0,10);

  // Show all days with events (no filtering). Order: today first, then future, then past
  const todayGroup=[], futureGroups=[], pastGroups=[];
  groups.forEach(g=>{
    const isToday=g.events[0].date===todayStr;
    if(isToday) todayGroup.push(g);
    else if(g.events[0].date>todayStr) futureGroups.push(g);
    else pastGroups.push(g);
  });
  const orderedGroups=[...todayGroup,...futureGroups,...pastGroups];
  orderedGroups.forEach((g,idx)=>{
    const isToday=g.events[0].date===todayStr;
    const isPastDay=pastGroups.includes(g);
    const isFirst=idx===0;
    html+=`<div style="padding:2px 4px 1px;font-size:13px;letter-spacing:.12em;text-transform:uppercase;
      color:${isToday?'#29b6f6':isPastDay?'#2a4060':'#29b6f6'};font-weight:700;margin-top:4px;border-top:1px solid #0d1825;
      ${isFirst?'border-top:none;margin-top:0':''}">
      ${g.lbl}${isToday?' <span style="color:#00e676;font-size:10px">▶ TODAY</span>':''}${isPastDay?' <span style="color:#1e3050;font-size:10px">✓ DONE</span>':''}
    </div>`;
    // Sort events: active/future first, past at bottom
    const sortedEvents=[...g.events].sort((a,b)=>{
      const msA=_econEventDT(a)-now, msB=_econEventDT(b)-now;
      const aPast=msA<0, bPast=msB<0;
      if(aPast===bPast) return msA-msB; // Both active or both past: sort by time
      return aPast?1:-1; // Active before past
    });
    sortedEvents.forEach(ev=>{
      const dt=_econEventDT(ev);
      const ms=dt-now;
      const urg=_econUrgency(ms);
      const isPast=ms<0;
      const noTime=ev.noTime===true;
      const timeStr=noTime?'':_econFmtTime(ev.time);
      const hasMeta=(ev.forecast||ev.prev)&&!isPast;
      html+=`<div style="display:grid;grid-template-columns:80px 1fr auto;gap:0 6px;align-items:start;
        padding:4px 2px 3px;border-bottom:1px solid #080f18;opacity:${isPast?0.5:1}">
        <span style="font-size:11px;color:#e8edf5;white-space:nowrap;padding-top:1px">${timeStr}</span>
        <span>
          <span style="font-size:12px;color:#e8edf5;line-height:1.3">${ev.name}</span>
          ${hasMeta?`<br><span style="font-size:10px;color:#a8b8cc">${ev.period?ev.period+' · ':''}Fcst: ${ev.forecast}&nbsp;&nbsp;Prev: ${ev.prev}</span>`:''}
        </span>
        ${noTime?'<span></span>':`<span data-econ-dt="${ev.date}T${ev.time}" style="font-size:11px;font-weight:700;padding:1px 5px;border-radius:2px;
          background:${urg.cls};color:${urg.txt};white-space:nowrap;align-self:start;margin-top:1px;
          font-family:Arial,monospace">${urg.label}</span>`}
      </div>`;
    });
  });
  body.style.display='block';
  body.style.alignItems='';
  body.style.justifyContent='';
  body.innerHTML=html||'<span style="color:#1e3050;font-size:11px">No events this week</span>';
}

let economicCalendarStarted = false;

function startEconCalendar(){
  // Prevent double-initialization
  if(economicCalendarStarted) {
    console.log('[Economic Calendar] Already started, skipping');
    return;
  }
  economicCalendarStarted = true;

  // Render calendar immediately (don't wait for quote)
  renderEconCalendar();

  // Fetch quote in background and re-render if it arrives
  fetchQuoteOfDay().then(() => renderEconCalendar()).catch(() => {
    // Quote fetch failed, but calendar is already showing
  });

  if(_econTimer) clearInterval(_econTimer);
  _econTimer=setInterval(renderEconCalendar,10000);
}

// ── REFRESH TRUMP CALENDAR BUTTON ──
window.refreshTrumpCalendar = function(btn) {
  if(!btn) btn = document.getElementById('cal-refresh-btn');

  const originalText = btn ? btn.textContent : 'TRUMP';
  const originalBg = btn ? btn.style.background : 'rgba(0,229,255,.1)';

  if(btn) {
    btn.textContent = '↻ Fetching...';
    btn.style.background = 'rgba(0,229,255,.2)';
    btn.disabled = true;
  }

  console.log('[Calendar] Triggering Trump calendar fetch from proxy');

  // IMPORTANT: Reset the flag so we can load fresh data
  trumpCalendarLoaded = false;

  // Try proxy endpoint first, fallback to direct fetch
  const tryProxyRoute = () => {
    return fetch(window.location.origin + '/proxy/api/trump-calendar-refresh', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    })
    .then(r => {
      if(!r.ok) throw new Error(`HTTP ${r.status}`);
      return r.json();
    })
    .then(data => {
      console.log('[Calendar] ✓ Proxy fetched:', data.count, 'events');
      return data;
    });
  };

  // Fallback: fetch directly from factba.se
  const tryDirectFetch = () => {
    console.log('[Calendar] Proxy endpoint not available, fetching directly from factba.se');
    return fetch('https://media-cdn.factba.se/rss/json/trump/calendar-full.json', {
      headers: { 'User-Agent': 'Mozilla/5.0' }
    })
    .then(r => {
      if(!r.ok) throw new Error(`HTTP ${r.status}`);
      return r.json();
    })
    .then(data => {
      console.log('[Calendar] ✓ Direct fetch:', (Array.isArray(data) ? data.length : data.events?.length || 0), 'events');
      // If it's an array, wrap it
      if(Array.isArray(data)){
        return { events: data, count: data.length, fetched: new Date().toISOString() };
      }
      return data;
    });
  };

  // Try proxy first, fallback to direct
  tryProxyRoute()
    .catch(err => {
      console.warn('[Calendar] Proxy failed:', err.message, '- trying direct fetch');
      return tryDirectFetch();
    })
    .then(data => {
      // Get today's date
      const today = new Date().toISOString().slice(0, 10);

      // Step 1: Get fresh today events from API
      let events = Array.isArray(data) ? data : (data.events || []);

      // Ensure events is an array
      if(!Array.isArray(events)) {
        console.error('[Calendar] Events is not an array:', typeof events);
        events = [];
      }

      const freshTodayEvents = events.filter(evt => evt.date === today);

      console.log('[Calendar] Fresh events from API:', freshTodayEvents.length);

      // Step 2: COMPLETELY REBUILD ECON_EVENTS without any Trump events
      // This prevents any duplicates from previous loads
      if(typeof ECON_EVENTS !== 'undefined'){
        // Keep ONLY non-Trump events (remove ALL Trump events entirely)
        window.ECON_EVENTS = ECON_EVENTS.filter(e => {
          const name = String(e.name || '').toLowerCase();
          // Remove if it's a Trump/President event or routine schedule items
          const isPresidentEvent = name.includes('president') ||
                                   name.includes('executive time') ||
                                   name.includes('in-town pool') ||
                                   name.includes('pool call') ||
                                   name.includes('white house');
          return !isPresidentEvent;
        });

        console.log('[Calendar] Removed old Trump events, ECON_EVENTS now has:', ECON_EVENTS.length);

        // Step 3: Add ONLY fresh TODAY's Trump events
        const newTrumpEvents = freshTodayEvents.map(evt => ({
          date: evt.date || '',
          time: evt.time || '00:00',
          name: evt.details || evt.type || evt.daily_text || 'Event',
          period: '',
          noTime: !evt.time
        }));

        ECON_EVENTS.push(...newTrumpEvents);
        TRUMP_CALENDAR_EVENTS = newTrumpEvents;

        console.log('[Calendar] Added', newTrumpEvents.length, 'fresh Trump events. Total:', ECON_EVENTS.length);

        // Re-render calendar (but don't interrupt countdown timer)
        if(typeof renderEconCalendar === 'function'){
          renderEconCalendar();
        }

        // Ensure countdown timer is still running after calendar rerender
        if(!countdownTimer) {
          console.log('[Calendar] Countdown timer was stopped, restarting...');
          if(typeof startCountdown === 'function') {
            startCountdown();
          }
        }
      }

      if(btn) {
        btn.textContent = '✓ Updated';
        btn.style.background = 'rgba(0,230,100,.2)';
        setTimeout(() => {
          btn.textContent = originalText;
          btn.style.background = originalBg;
          btn.disabled = false;
        }, 2000);
      }

      console.log('[Calendar] ✓ Calendar refreshed:', TRUMP_CALENDAR_EVENTS.length, 'Trump events');
    })
    .catch(err => {
      console.error('[Calendar] ✗ Refresh failed:', err.message);
      if(btn) {
        btn.textContent = '✗ Error';
        btn.style.background = 'rgba(255,71,87,.2)';
        setTimeout(() => {
          btn.textContent = originalText;
          btn.style.background = originalBg;
          btn.disabled = false;
        }, 2000);
      }
    });
}

// ── SIGNAL FEED ───────────────────────────────────────────────────────────
const FEED_DISCORD_WEBHOOK_URL = '' + window.location.origin + '/proxy/api/discord-webhook';
const FEED_ALERT_DISCORD_WEBHOOK_URL = '' + window.location.origin + '/proxy/api/discord-webhook';

function _feedGetState(){
  if(!window.__signalFeedState){
    let demoDismissed = false;
    let items = [];
    try{
      demoDismissed = localStorage.getItem('signalFeedDemoDismissed') === '1';
      const raw = localStorage.getItem('signalFeedItems');
      if(raw) items = JSON.parse(raw) || [];
    }catch(e){}
    window.__signalFeedState = { items, filter: 'all', seen: new Set(items.map(item => item.id).filter(Boolean)), sent: new Set(), seedKey: null, demoDismissed };
  }
  return window.__signalFeedState;
}

function _feedWeekResetKey(now = new Date()){
  const monday = new Date(now);
  const day = (monday.getDay() + 6) % 7;
  monday.setHours(0, 0, 0, 0);
  monday.setDate(monday.getDate() - day);
  return monday.toISOString().slice(0, 10);
}

function _feedStamp(ts){
  const d = new Date(ts || Date.now());
  return d.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
}

function _feedSeedMock(){
  const state = _feedGetState();
  const key = _feedWeekResetKey();
  if(state.seedKey === key) return;
  state.seedKey = key;
  state.items = state.items.filter(item => !String(item.id || '').startsWith('seed-'));
  try{ localStorage.setItem('signalFeedItems', JSON.stringify(state.items.slice(0, 100))); }catch(e){}
}

function _feedNormalizeItem(item){
  return {
    id: item.id || `feed-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    ts: item.ts || Date.now(),
    kind: item.kind || 'signal',
    side: item.side || 'signal',
    source: item.source || 'ALERT',
    message: item.message || '',
    meta: item.meta || {}
  };
}

function _feedPushSimpleSignal(source, message, side = 'signal', tags = [], meta = {}){
  if(typeof window.addFeedItem !== 'function') return;
  window.addFeedItem({
    kind: 'signal',
    side,
    source,
    message,
    meta: { ...meta, tags }
  });
}

function _feedSignalKey(item){
  const meta = item?.meta || {};
  return [
    String(item?.kind || ''),
    String(item?.side || ''),
    String(item?.source || ''),
    String(item?.message || ''),
    JSON.stringify(meta.tags || []),
    String(meta.type || ''),
    String(meta.time || ''),
    String(meta.date || '')
  ].join('|');
}

function _feedQueueSignal(item){
  const normalized = _feedNormalizeItem(item || {});
  const state = _feedGetState();
  const key = _feedSignalKey(normalized);
  if(state.seen.has(key)) return null;
  state.seen.add(key);
  window.addFeedItem(normalized);
  return normalized.id;
}

function _feedScanEconomicWarnings(){
  try{
    const state = _feedGetState();
    if(!Array.isArray(window.ECON_EVENTS) || !window.ECON_EVENTS.length) return;
    const now = new Date();
    window.ECON_EVENTS.forEach(ev => {
      if(!ev || !ev.date || !ev.time || ev.noTime) return;
      const dt = new Date(`${ev.date}T${String(ev.time).padStart(5, '0')}:00`);
      const diffMin = Math.round((dt.getTime() - now.getTime()) / 60000);
      if(diffMin >= 0 && diffMin <= 5){
        const key = `econ|${ev.date}|${ev.time}|${String(ev.name || '')}`;
        if(state.seen.has(key)) return;
        state.seen.add(key);
        window.addFeedItem({
          kind: 'signal',
          side: 'signal',
          source: 'ECON CAL',
          message: `5 minute warning: ${ev.name} starts at ${_econFmtTime(ev.time)}.`,
          meta: { type: 'econ5mWarning', date: ev.date, time: ev.time, tags: ['WARN', 'ECON'] }
        });
      }
    });
  }catch(e){}
}

function _feedBuildDiscordAlertText(item){
  const source = String(item.source || 'ALERT').toUpperCase();
  const tags = Array.isArray(item.meta?.tags) ? item.meta.tags.map(t => String(t).toUpperCase()).slice(0, 2) : [];
  const tagText = tags.length ? ` [${tags.join(' | ')}]` : '';
  return `${source}: ${String(item.message || '').trim()}${tagText}`;
}

async function _feedPostDiscordAlert(item){
  return; // Auto-posting to Discord disabled
  if(!item || item.id === 'demo-feed-card' || item.meta?.demo || item.meta?.noDiscord) return;
  const state = _feedGetState();
  const signature = `${String(item.kind || '')}|${String(item.side || '')}|${String(item.source || '')}|${String(item.message || '')}|${JSON.stringify(item.meta?.tags || [])}`;
  if(state.sent.has(signature)) return;
  state.sent.add(signature);
  try{
    const res = await fetch(FEED_ALERT_DISCORD_WEBHOOK_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: _feedBuildDiscordAlertText(item) })
    });
    if(!res.ok) console.warn('[feed] Discord alert webhook failed:', res.status);
  }catch(err){
    console.warn('[feed] Discord alert webhook error:', err?.message || err);
  }
}

function _feedItemHtml(item){
  const time = _feedStamp(item.ts);
  const tone = item.side === 'buy' ? 'buy' : item.side === 'sell' ? 'sell' : item.side === 'signal' ? 'signal' : 'neutral';
  const text = String(item.message || '').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  const tags = Array.isArray(item.meta?.tags) && item.meta.tags.length ? item.meta.tags : [item.kind || 'signal', item.source || 'alert'];
  const isPlaybook = String(item.source || '').toUpperCase() === 'PLAYBOOK' || String(item.meta?.type || '') === 'playbookHistory';
  const toneFill = isPlaybook ? '#24183a' : tone === 'buy' ? '#0d2d17' : tone === 'sell' ? '#2a1111' : '#10243a';
  const toneBorder = isPlaybook ? '#a855f788' : tone === 'buy' ? '#1fae5e88' : tone === 'sell' ? '#cc223388' : '#29b6f688';
  const toneText = isPlaybook ? '#c084fc' : tone === 'buy' ? '#00e676' : tone === 'sell' ? '#ff4757' : '#29b6f6';
  const tagHtml = tags.slice(0, 2).map((tag, idx) => {
    const isPrimary = idx === 0;
    const pillTone = isPlaybook && isPrimary ? 'info' : (isPrimary ? tone : 'neutral');
    const pillBg = isPlaybook && isPrimary ? '#341e51' : (isPrimary ? toneFill : '#111822');
    const pillText = isPlaybook && isPrimary ? '#e9d5ff' : (isPrimary ? toneText : '#5a7a99');
    const pillBorder = isPlaybook && isPrimary ? '#c084fc55' : (isPrimary ? toneBorder + '44' : '#1e3050');
    return '<span class="sfi-pill ' + pillTone + '" style="background:' + pillBg + ';color:' + pillText + ';border:1px solid ' + pillBorder + '">' + String(tag).toUpperCase() + '</span>';
  }).join('');
  const iconGlyph = isPlaybook ? 'P' : tone === 'buy' ? '+' : tone === 'sell' ? '-' : '!';
  const cardGlow = isPlaybook ? '0 0 0 1px rgba(168,85,247,0.12), inset 0 0 0 1px rgba(53,85,123,0.20)' : 'inset 0 0 0 1px rgba(53,85,123,0.20)';
  return '<div class="sfi sfi-' + tone + '" data-feed-id="' + item.id + '" data-feed-kind="' + item.kind + '" data-feed-side="' + item.side + '" style="position:relative;align-items:flex-start;padding:9px 16px;background:#0b0f15;border-color:' + toneBorder + ';border-radius:7px;box-shadow:' + cardGlow + '">' +
    '<button type="button" data-feed-delete="' + item.id + '" aria-label="Delete signal" style="position:absolute;right:12px;top:10px;border:none;background:transparent;color:#98a6b8;font-size:20px;line-height:1;cursor:pointer;font-weight:700">&times;</button>' +
    '<div class="sfi-ico ' + tone + '" style="width:42px;height:42px;font-size:22px;border-radius:4px;margin-top:0;background:' + toneFill + ';color:' + toneText + '">' + iconGlyph + '</div>' +
    '<div style="flex:1;min-width:0;padding-right:38px">' +
      '<div style="display:flex;align-items:flex-start;justify-content:flex-end;gap:12px;margin-bottom:3px">' +
        '<div class="sfi-time" style="font-size:15px;line-height:1;color:#ffffff;font-weight:800;letter-spacing:.04em;white-space:nowrap">' + time + '</div>' +
      '</div>' +
      '<div class="sfi-msg" style="font-size:16px;line-height:1.2;color:#eef2f7;margin:0 0 6px 0">' + text + '</div>' +
      '<div style="display:flex;gap:8px;flex-wrap:wrap">' + tagHtml + '</div>' +
    '</div>' +
  '</div>';
}


function renderSignalFeed(){
  _feedSeedMock();
  const state = _feedGetState();
  const zone = document.getElementById('feed-capture-zone');
  if(!zone) return;
  state.filter = 'all';
  const storedItems = Array.isArray(state.items) ? state.items : [];
  const visibleItems = storedItems.length ? [...storedItems].sort((a, b) => Number(b.ts || 0) - Number(a.ts || 0)) : [];
  const demoEl = document.getElementById('feed-demo-card');
  if(state.items.length && demoEl) demoEl.remove();
  zone.innerHTML = visibleItems.length ? visibleItems.map(_feedItemHtml).join('') : '';
}

function ensureSignalFeedVisible(){
  const zone = document.getElementById('feed-capture-zone');
  if(!zone) return;
  if(!zone.innerHTML || !zone.children.length){
    renderSignalFeed();
  }
}

window.feedFilter = function(filter){
  const state = _feedGetState();
  state.filter = 'all';
  renderSignalFeed();
};

window.addFeedItem = function(item){
  const state = _feedGetState();
  const normalized = _feedNormalizeItem(item || {});
  state.items.unshift(normalized);
  try{ localStorage.setItem('signalFeedItems', JSON.stringify(state.items.slice(0, 100))); }catch(e){}
  if(!state.seen.has(normalized.id)){
    state.seen.add(normalized.id);
    _feedPostDiscordAlert(normalized);
  }
  renderSignalFeed();
  return normalized.id;
};

window.pushSignalFeedItem = function(item){
  return window.addFeedItem(item);
};

window.removeFeedItem = function(id){
  const state = _feedGetState();
  if(id === 'demo-feed-card'){
    state.demoDismissed = true;
    try{ localStorage.setItem('signalFeedDemoDismissed', '1'); }catch(e){}
    const demoEl = document.getElementById('feed-demo-card');
    if(demoEl) demoEl.remove();
    renderSignalFeed();
    return;
  }
  state.items = state.items.filter(item => item.id !== id);
  try{ localStorage.setItem('signalFeedItems', JSON.stringify(state.items.slice(0, 100))); }catch(e){}
  renderSignalFeed();
};

window.refreshSignalFeed = function(){
  renderSignalFeed();
};

document.addEventListener('click', e => {
  const btn = e.target.closest('[data-feed-delete]');
  if(!btn) return;
  window.removeFeedItem(btn.dataset.feedDelete);
});

window.addEventListener('db-mvc-updated', () => {
  try{
    const current = {
      strike: window.mvcOIVol?.strike ?? null,
      value: window.mvcOIVol?.value ?? null,
      volume: window.mvcOIVol?.volume ?? null
    };
    const prev = window.__lastMvcFeedState || null;
    _emitMvcSignal(prev, current);
    window.__lastMvcFeedState = current;
  }catch(e){}
});

function _feedCaptureHtml2Canvas(){
  if(typeof window.html2canvas === 'function') return Promise.resolve(window.html2canvas);
  return new Promise((resolve, reject) => {
    const script = document.createElement('script');
    script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
    script.async = true;
    script.onload = () => resolve(window.html2canvas);
    script.onerror = () => reject(new Error('html2canvas failed to load'));
    document.head.appendChild(script);
  });
}

async function _feedCapturePanel(){
  const el = document.getElementById('feed-capture-zone');
  if(!el) throw new Error('feed capture zone missing');
  const html2canvasFn = await _feedCaptureHtml2Canvas();
  const canvas = await html2canvasFn(el, { backgroundColor: '#0a0f16', scale: 2, useCORS: true, logging: false, allowTaint: true });
  return new Promise((resolve, reject) => canvas.toBlob(blob => blob ? resolve(blob) : reject(new Error('capture failed')), 'image/png'));
}

function _feedSetButtonState(btn, text, color){
  if(!btn) return;
  btn.textContent = text;
  btn.style.color = color;
}

window.feedCopyScreenshot = async function(){
  const btn = document.getElementById('feed-copy-shot-btn');
  const restore = 'COPY';
  _feedSetButtonState(btn, '...', '#ffb300');
  try{
    const blob = await _feedCapturePanel();
    if(!navigator.clipboard || typeof ClipboardItem === 'undefined') throw new Error('clipboard unavailable');
    await navigator.clipboard.write([new ClipboardItem({ 'image/png': blob })]);
    _feedSetButtonState(btn, '✓', '#00e676');
  }catch(err){
    _feedSetButtonState(btn, 'ERR', '#ff4757');
  }
  setTimeout(() => _feedSetButtonState(btn, restore, '#00e5ff'), 1500);
};

window.feedShare = async function(platform){
  const btn = platform === 'x' ? document.getElementById('feed-share-x-btn') : document.getElementById('feed-share-discord-btn');
  const restore = platform === 'x' ? 'X' : 'DISCORD';
  const restoreColor = platform === 'x' ? '#00e5ff' : '#7289da';
  _feedSetButtonState(btn, '...', '#ffb300');
  try{
    if(platform === 'x'){
      window.open('https://twitter.com/intent/tweet?text=SPX+Signal+Feed', '_blank');
      _feedSetButtonState(btn, '✓', '#00e676');
      setTimeout(() => _feedSetButtonState(btn, restore, restoreColor), 1200);
      return;
    }
    const blob = await _feedCapturePanel();
    const form = new FormData();
    form.append('payload_json', JSON.stringify({ content: 'SPX Signal Feed' }));
    form.append('files[0]', blob, 'signal-feed.png');
    const res = await fetch(FEED_DISCORD_WEBHOOK_URL, { method: 'POST', body: form });
    if(!res.ok) throw new Error(`webhook ${res.status}`);
    _feedSetButtonState(btn, '✓', '#00e676');
  }catch(err){
    _feedSetButtonState(btn, 'ERR', '#ff4757');
  }
  setTimeout(() => _feedSetButtonState(btn, restore, restoreColor), 1500);
};

function initSignalFeed(){
  if(typeof setFeedTab === 'function') setFeedTab('signal', document.getElementById('feed-tab-signal'));
  renderSignalFeed();
  window.feedFilter('all');
  _feedScanEconomicWarnings();
  if(!window.__signalFeedWarnTimer){
    window.__signalFeedWarnTimer = setInterval(_feedScanEconomicWarnings, 30000);
  }

  requestAnimationFrame(ensureSignalFeedVisible);
  setTimeout(ensureSignalFeedVisible, 250);
  setTimeout(ensureSignalFeedVisible, 1000);
  setTimeout(renderSignalFeed, 150);
}
if(document.readyState === 'loading'){
  document.addEventListener('DOMContentLoaded', () => setTimeout(initSignalFeed, 0));
} else {
  setTimeout(initSignalFeed, 0);
}
window.addEventListener('load', () => setTimeout(renderSignalFeed, 0));

