// ── GEX CHART & HEATMAP SHARE ─────────────────────────────────────────
// Render the overview canvas into a 4:3 output canvas for sharing
function gexChartTo43Canvas(){
  const src = document.getElementById('overview-canvas');
  if(!src) return null;
  const srcW = src.width, srcH = src.height;
  const outW = srcW;
  const outH = Math.round(srcW * (9/16));
  const out = document.createElement('canvas');
  out.width = outW; out.height = outH;
  const ctx = out.getContext('2d');
  ctx.fillStyle = '#05080d';
  ctx.fillRect(0, 0, outW, outH);
  // Center the source canvas vertically inside the 4:3 frame
  const dy = Math.round((outH - srcH) / 2);
  ctx.drawImage(src, 0, dy);
  return out;
}

async function gexChartWithToolbarTo43Canvas(){
  const toolbar = document.getElementById('gex-level-bar');
  const src = document.getElementById('overview-canvas');
  if(!src || !toolbar) return null;
  const html2canvasFn = await window.loadHtml2CanvasSafe();
  if(!html2canvasFn) return null;
  
  // Build a minimal toolbar canvas showing only the expiration
  let toolbarCanvas = null;
  try {
    const expText = document.getElementById('gex-current-exp')?.textContent?.replace(/[()]/g,'').trim() || '—';
    const tbH = 32;
    const tbW = src.width;
    toolbarCanvas = document.createElement('canvas');
    toolbarCanvas.width = tbW;
    toolbarCanvas.height = tbH;
    const tctx = toolbarCanvas.getContext('2d');
    tctx.fillStyle = '#0a0f16';
    tctx.fillRect(0, 0, tbW, tbH);
    tctx.strokeStyle = '#1a2a3a';
    tctx.lineWidth = 1;
    tctx.beginPath(); tctx.moveTo(0, tbH - 0.5); tctx.lineTo(tbW, tbH - 0.5); tctx.stroke();
    tctx.font = 'bold 13px Arial';
    tctx.fillStyle = '#00e5ff';
    tctx.textBaseline = 'middle';
    tctx.fillText('SPX GEX', 14, tbH / 2);
    tctx.fillStyle = '#1a2a3a';
    tctx.fillText('  |  ', 14 + tctx.measureText('SPX GEX').width, tbH / 2);
    const sepW = tctx.measureText('SPX GEX  |  ').width;
    tctx.font = '12px Arial';
    tctx.fillStyle = '#5a7a99';
    tctx.fillText('Exp: ', 14 + sepW, tbH / 2);
    tctx.fillStyle = '#ffffff';
    tctx.fillText(expText, 14 + sepW + tctx.measureText('Exp: ').width, tbH / 2);
  } catch(e) {
    console.log('Toolbar render failed:', e);
  }
  
  const srcW = src.width, srcH = src.height;
  const outW = srcW;
  const outH = Math.round(srcW * (9/16));
  const out = document.createElement('canvas');
  out.width = outW; out.height = outH;
  const ctx = out.getContext('2d');
  ctx.fillStyle = '#05080d';
  ctx.fillRect(0, 0, outW, outH);
  
  // Draw toolbar if captured
  let toolbarHeight = 0;
  if(toolbarCanvas) {
    const tbW = toolbarCanvas.width;
    const tbH = toolbarCanvas.height;
    // Scale toolbar to fit width
    const scale = outW / tbW;
    const scaledTbH = Math.round(tbH * scale);
    ctx.drawImage(toolbarCanvas, 0, 0, outW, scaledTbH);
    toolbarHeight = scaledTbH;
    console.log('Toolbar rendered:', scaledTbH);
  }
  
  // Center the source canvas below toolbar
  const remainingH = outH - toolbarHeight;
  const scaledSrcH = Math.min(srcH, remainingH);
  const dy = toolbarHeight + Math.round((remainingH - scaledSrcH) / 2);
  const scaledSrcW = Math.round(scaledSrcH * (srcW / srcH));
  const dx = Math.round((outW - scaledSrcW) / 2);
  ctx.drawImage(src, dx, dy, scaledSrcW, scaledSrcH);
  console.log('Final canvas:', outW, outH, 'toolbar:', toolbarHeight, 'chart dy:', dy);
  return out;
}

