// Build a tightly-cropped heatmap canvas: column headers + data rows only, no blank flex space
async function _buildHeatmapCanvas(html2canvasFn){
  const toolbar = document.getElementById('heatmap-toolbar') || document.getElementById('ladder-header');
  const body = document.getElementById('heatmap-body') || document.getElementById('ladder-body');
  const ladder = document.getElementById('options-ladder') || document.getElementById('options-ladder-capture-zone');
  if(!toolbar || !body || !ladder) throw new Error('Heatmap elements not found');
  const panelW = ladder.offsetWidth || 530;
  const wrap = document.createElement('div');
  wrap.style.cssText = 'position:fixed;top:-9999px;left:-9999px;background:#05080d;display:block;width:' + panelW + 'px;overflow:visible';
  const hdrClone = toolbar.cloneNode(true);
  hdrClone.style.cssText = hdrClone.style.cssText + ';position:static;display:grid;width:' + panelW + 'px;';
  const bodyClone = body.cloneNode(true);
  bodyClone.style.cssText = bodyClone.style.cssText + ';display:block;overflow:visible;max-height:none;height:auto;flex:none;';
  wrap.appendChild(hdrClone);
  wrap.appendChild(bodyClone);
  document.body.appendChild(wrap);
  try{
    return await html2canvasFn(wrap, {
      backgroundColor: '#05080d',
      scale: 2,
      useCORS: true,
      logging: false,
      allowTaint: true,
      onclone: (clonedDoc, clonedEl) => {
        clonedEl.querySelectorAll('.hm-row.hm-atm, .hm-atm').forEach(row => {
          row.style.outline = '1.5px solid rgba(0,229,255,0.85)';
          row.style.outlineOffset = '-1px';
          const strikeCell = row.querySelector('.hm-strike') || row.firstElementChild;
          if(strikeCell){ strikeCell.style.color = '#00e5ff'; strikeCell.style.background = '#0a2030'; }
        });
      }
    });
  } finally {
    if(document.body.contains(wrap)) document.body.removeChild(wrap);
  }
}

