// ── NEWS FEED (Twitter/X via proxy) ───────────────────────────────
const TWITTER_PROXY = window.location.origin + '/proxy/twitter';
let newsTab = 'all';
let newsInterval = null;
let cachedTweets = []; // all tweets cached, filtered on tab switch

const NEWS_TABS = ['all','FirstSquawk','DeItaone','financialjuice','LiveSquawk','Fxhedgers','zerohedge'];

function setNewsTab(tab) {
  newsTab = tab;
  NEWS_TABS.forEach(t => {
    const el = document.getElementById('news-tab-' + t);
    if (!el) return;
    const active = t === tab;
    el.style.background    = active ? '#0d1f2f' : 'transparent';
    el.style.color         = active ? '#29b6f6' : '#3a5570';
    el.style.borderColor   = active ? '#29b6f644' : '#1e3050';
  });
  renderTweets();
}

function timeAgo(isoStr) {
  const diff = Math.floor((Date.now() - new Date(isoStr)) / 1000);
  if (diff < 60)    return diff + 's ago';
  if (diff < 3600)  return Math.floor(diff / 60) + 'm ago';
  if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
  return Math.floor(diff / 86400) + 'd ago';
}

function renderTweets() {
  const body = document.getElementById('news-body');
  if (!body) return;
  const tweets = newsTab === 'all'
    ? cachedTweets
    : cachedTweets.filter(t => t.author.username.toLowerCase() === newsTab.toLowerCase());

  if (!tweets.length) {
    body.innerHTML = '<div style="color:#1e3050;font-size:11px;padding:16px;text-align:center">No tweets available</div>';
    return;
  }

  const accountColors = {
    FirstSquawk: '#00e5ff', DeItaone: '#29b6f6', financialjuice: '#ff6b35',
    LiveSquawk: '#00e676', Fxhedgers: '#ffb300', zerohedge: '#ff4757'
  };

  let html = '';
  tweets.forEach(tweet => {
    const age   = timeAgo(tweet.created_at);
    const color = accountColors[tweet.author.username] || '#29b6f6';
    const text  = tweet.text.replace(/https?:\/\/\S+/g, '').trim(); // strip trailing URLs
    html += `
      <div onclick="window.open('${tweet.url}','_blank')"
           style="padding:8px 12px;border-bottom:1px solid #080f18;cursor:pointer;transition:background .1s"
           onmouseover="this.style.background='#0a0f18'" onmouseout="this.style.background='transparent'">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
          <span style="font-size:9px;font-weight:700;color:${color};letter-spacing:.06em;text-transform:uppercase">@${tweet.author.username}</span>
          <span style="font-size:9px;color:#2a4060;font-variant-numeric:tabular-nums">${age}</span>
        </div>
        <div style="font-size:12px;color:#c8d8e8;line-height:1.5">${text}</div>
        ${tweet.metrics.like_count ? `<div style="margin-top:4px;font-size:9px;color:#2a4060">♥ ${tweet.metrics.like_count}  🔁 ${tweet.metrics.retweet_count||0}</div>` : ''}
      </div>`;
  });
  body.innerHTML = html;
}

async function fetchTwitterNews(manual = false) {
  const body = document.getElementById('news-body');
  const ts   = document.getElementById('news-ts');
  if (!body) return;

  if (manual) {
    body.innerHTML = '<div style="color:#1e3050;font-size:11px;padding:16px;text-align:center">Refreshing…</div>';
  }

  try {
    const res  = await fetch(`${TWITTER_PROXY}?max=5`);
    const data = await res.json();

    if (!res.ok || data.error) {
      body.innerHTML = `<div style="color:#ff4757;font-size:10px;padding:12px">Twitter error: ${data.error || res.statusText}</div>`;
      return;
    }

    cachedTweets = data.tweets || [];
    if (ts) ts.textContent = new Date().toLocaleTimeString('en-US', { hour12: false });
    renderTweets();

  } catch(e) {
    body.innerHTML = `<div style="color:#ff4757;font-size:10px;padding:12px">Proxy error: ${e.message}<br><span style="color:#2a4060">Is proxy.js running? (node proxy.js)</span></div>`;
  }
}

function startNewsFeed() {
  fetchTwitterNews();
  if (newsInterval) clearInterval(newsInterval);
  newsInterval = setInterval(() => fetchTwitterNews(), 30000); // auto-refresh every 30s
}

document.addEventListener('DOMContentLoaded', startNewsFeed);


// ── AUTO REFRESH ───────────────────────────────────────────────────
function startAutoRefresh(){
  stopAutoRefresh();
  autoRefreshPaused=false;
  // No more polling interval — dxlink websocket handles all real-time updates
  // Only keep 1-minute GEX snapshot for the Δ 1MIN column
  if(!window._gex1minTimer){
    window._gex1minTimer = setInterval(()=>{
      if(rawChain.length){
        const snap = new Map();
        rawChain.forEach(r=>snap.set(r.strike, r.netGEX||0));
        gex1MinSnapshots.push({ts: Date.now(), data: snap});
        gex1MinSnapshots = gex1MinSnapshots.filter(s=>s.ts >= Date.now() - 2*60*60*1000);
      }
    }, 60000);
  }
}
function stopAutoRefresh(){
  if(autoRefreshInterval){ clearInterval(autoRefreshInterval); autoRefreshInterval=null; }
  if(countdownTimer){ clearInterval(countdownTimer); countdownTimer=null; }
}
function resetCountdown(){
  countdownSecs=REFRESH_SECS;
  updateCountdownUI();
  if(countdownTimer){ clearInterval(countdownTimer); countdownTimer=null; }
  if(!autoRefreshPaused) startCountdown();
}
function startCountdown(){
  countdownSecs=REFRESH_SECS;
  updateCountdownUI();
  countdownTimer=setInterval(()=>{
    if(!autoRefreshPaused){ countdownSecs=Math.max(0,countdownSecs-1); updateCountdownUI(); }
  },1000);
}
function updateCountdownUI(){
  const vdd=document.getElementById('countdown-val-dd');
  const bdd=document.getElementById('countdown-bar-dd');
  if(!vdd||!bdd) {
    // Elements don't exist on this page (e.g., GEX page)
    return;
  }
  vdd.textContent=countdownSecs+'s';
  const pct=(countdownSecs/REFRESH_SECS)*100;
  bdd.style.width=pct+'%';
  if(countdownSecs<=5){ bdd.style.background='var(--red)'; vdd.style.color='var(--red)'; }
  else if(countdownSecs<=10){ bdd.style.background='var(--amber)'; vdd.style.color='var(--amber)'; }
  else{ bdd.style.background='var(--cyan)'; vdd.style.color='var(--cyan)'; }
}
function toggleAutoRefresh(){
  const btn=document.getElementById('auto-toggle-btn');
  const btndd=document.getElementById('auto-toggle-btn-dd');
  autoRefreshPaused=!autoRefreshPaused;
  if(autoRefreshPaused){
    btn.textContent='▶ Resume'; btn.style.color='var(--amber)';
    if(btndd){btndd.textContent='▶ Resume'; btndd.style.color='var(--amber)';}
    if(countdownTimer){ clearInterval(countdownTimer); countdownTimer=null; }
  } else {
    btn.textContent='⏸ Pause'; btn.style.color='';
    if(btndd){btndd.textContent='⏸ Pause'; btndd.style.color='';}
    resetCountdown();
  }
}
function manualRefresh(){ fetchGEX(); resetCountdown(); }
function setTableLoading(){ document.getElementById('table-wrap').innerHTML='<div class="empty-state"><div class="spinner"></div><h3>Loading…</h3></div>'; }
function setTableError(msg){ document.getElementById('table-wrap').innerHTML=`<div class="empty-state"><h3 style="color:var(--red)">Error</h3><p style="font-size:12px;color:var(--text2)">${msg}</p><button class="btn btn-ghost" onclick="fetchGEX()" style="margin-top:12px">↻ Retry</button></div>`; }
