function updateStatsBar(){
  if(!rawChain.length||!spotPrice) return;
  const spxF=v=>v!=null&&!isNaN(v)?v.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}):'—';
  const esF=v=>{
    const es=spxLevelToES(v);
    return es!=null&&isFinite(es)?es.toLocaleString('en-US',{minimumFractionDigits:0,maximumFractionDigits:0}):null;
  };
  const callWall=rawChain.reduce((a,b)=>b.callGEX>a.callGEX?b:a,rawChain[0])?.strike;
  const putWall=rawChain.reduce((a,b)=>Math.abs(b.putGEX)>Math.abs(a.putGEX)?b:a,rawChain[0])?.strike;
  const hvl=rawChain.reduce((a,b)=>Math.abs(b.netGEX)<Math.abs(a.netGEX)?b:a,rawChain[0])?.strike;
  const flip=flipPoint;
  const totalGEX=rawChain.reduce((s,r)=>s+r.netGEX,0);
  // Calculate total Delta Exposure (DEX), Theta Exposure (CHEX), Vega Exposure (VEX)
  const totalDEX=rawChain.reduce((s,r)=>s+(r.netDEX||0),0);
  const totalCHEX=rawChain.reduce((s,r)=>s+(Math.abs(Number(r.callTheta||0)) - Math.abs(Number(r.putTheta||0)))*(Number(r.callOI||0)+Number(r.putOI||0)+Number(r.callVolume||0)+Number(r.putVolume||0))*(Number(spotPrice)||0)*100,0);
  const totalVEX=rawChain.reduce((s,r)=>s+(Math.abs(Number(r.callVega||0)) - Math.abs(Number(r.putVega||0)))*(Number(r.callOI||0)+Number(r.putOI||0)+Number(r.callVolume||0)+Number(r.putVolume||0))*(Number(spotPrice)||0)*100,0);
  const straddle=calcStraddle();
  window._levels={flip,callWall,putWall,hvl,
    noLong:callWall,noShort:putWall,
    estUp:7566,
    estDn:7299,
    sig1Up:straddle?spotPrice+straddle.sigma1:null,
    sig1Dn:straddle?spotPrice-straddle.sigma1:null};
  window._esLevels=getESLevelsFromSPX(window._levels);
  window._levelMathContext={callWall,putWall,flip,totalGEX,totalDEX,totalCHEX,totalVEX,mode:'oi'};
  if(straddle){
    const eu=window._levels.estUp,ed=window._levels.estDn;
    safeSet('rs-est-up',spxF(eu)); safeSet('rs-est-dn',spxF(ed));
    const ue=esF(eu),de=esF(ed);
    safeSet('rs-est-up-es',ue?'ES '+ue:''); safeSet('rs-est-dn-es',de?'ES '+de:'');
    safeSet('rs-sig-up',spxF(window._levels.sig1Up)); safeSet('rs-sig-dn',spxF(window._levels.sig1Dn));
    // ── DAILY EM: frozen move (captured 4–6pm ET) off the 4pm closes ──────────
    // EM value is unchanged (calcStraddle().dailyMove), but frozen once per ET
    // day. Up/Dn are drawn from the official closes, not the live spot:
    //   SPX  = spxPrevClose ± move (toolbar / quotes-page close)
    //   ES   = esF() adds (esPrevClose − spxPrevClose) basis, so it resolves to
    //          esPrevClose ± move = the 15:45 candle 4pm print ± move.
    // Cache-only: never recompute on refresh. If nothing is captured yet
    // (before the first 4–6pm window), leave the existing daily values as-is.
    const frozenEM = getFrozenDailyEM();
    if (frozenEM) {
      const dailyMove = frozenEM.dailyMove;
      const emIV = frozenEM.iv, emDte = frozenEM.dte;
      const spxBase = (spxPrevClose > 0) ? spxPrevClose : spotPrice;
      safeSet('rs-iv',(emIV*100).toFixed(1)+'%');
      const du=spxBase+dailyMove,dd=spxBase-dailyMove;
      safeSet('rs-daily-up',spxF(du)); safeSet('rs-daily-dn',spxF(dd));
      const due=esF(du),dde=esF(dd);
      safeSet('rs-daily-up-es',due?'ES '+due:''); safeSet('rs-daily-dn-es',dde?'ES '+dde:'');
      safeSet('rs-daily-pts','±'+dailyMove.toFixed(1));
      safeSet('rs-iv-display',(emIV*100).toFixed(1)+'%');
      safeSet('rs-em-dte',emDte===1?'(1DTE)':emDte>1?'('+emDte+'DTE)':'');
    }
  }
  const noLongHi=callWall,noLongLo=flip,noShortHi=putWall,noShortLo=hvl;
  safeSet('rs-nolong-hi',spxF(noLongHi)); safeSet('rs-nolong-hi-es',esF(noLongHi)?'ES '+esF(noLongHi):'');
  safeSet('rs-nolong-lo',spxF(noLongLo)); safeSet('rs-nolong-lo-es',esF(noLongLo)?'ES '+esF(noLongLo):'');
  safeSet('rs-noshort-hi',spxF(noShortHi)); safeSet('rs-noshort-hi-es',esF(noShortHi)?'ES '+esF(noShortHi):'');
  safeSet('rs-noshort-lo',spxF(noShortLo)); safeSet('rs-noshort-lo-es',esF(noShortLo)?'ES '+esF(noShortLo):'');
  safeSet('rs-flip',spxF(flip)); safeSet('rs-flip-es',esF(flip)?'ES '+esF(flip):'');
  safeSet('rs-callwall',spxF(callWall)); safeSet('rs-callwall-es',esF(callWall)?'ES '+esF(callWall):'');
  safeSet('rs-putwall',spxF(putWall)); safeSet('rs-putwall-es',esF(putWall)?'ES '+esF(putWall):'');
  safeSet('rs-hvl',spxF(hvl)); safeSet('rs-hvl-es',esF(hvl)?'ES '+esF(hvl):'');
  const bn=totalGEX/1e9;
  safeHTML('rs-netgex','<span style="color:'+(bn>=0?'var(--green)':'var(--red)')+'\">'+(bn>=0?'+':'')+'$'+bn.toFixed(2)+'B</span>');
  safeHTML('rs-regime','<span style="color:'+(bn>=0?'var(--green)':'var(--red)')+'\">'+(bn>=0?'Pos GEX':'Neg GEX')+'</span>');
  safeSet('rs-expiry',(selectedExpiry||'—')+(selectedExpiry?' ('+getDTE(selectedExpiry)+'DTE)':''));
  updateESPriceDisplay();
  updateTopGamma();
  // MVC: Max Vol Concentration — highest net GEX by OI+Vol and by Vol only
  (function(){
    if(!rawChain.length) return;
    const fmtS=v=>v!=null?v.toLocaleString('en-US',{maximumFractionDigits:0}):'—';
    const mvcOI = getHighestNetGexRow(rawChain, 'netGEX');
    const mvcVol = getHighestNetGexRow(rawChain, 'netVolGEX');
    const topNetExposureStrike = mvcOI ? fmtS(mvcOI.strike) : '—';
    
    // Export to global scope for snapshot function
    window.mvcOIVol = {
      strike: mvcOI?.strike ?? 0,
      value: mvcOI?.netGEX ?? 0,
      volume: ((mvcOI?.callVolume || 0) + (mvcOI?.putVolume || 0))
    };
    window.mvcVolOnly = {
      strike: mvcVol?.strike ?? 0,
      value: mvcVol?.netVolGEX || 0,
      volume: ((mvcVol?.callVolume || 0) + (mvcVol?.putVolume || 0))
    };
    
    // Export DEX data
    if (window.AppState) {
      window.AppState.netDexStrike = mvcOI?.netDEX || 0;
      window.AppState.totalNetDEX_OI = mvcOI?.totalNetDEX || 0;
    }
    
    const oiEl=document.getElementById('mvc-oi');
    const volEl=document.getElementById('mvc-vol');
    if(oiEl) oiEl.textContent=topNetExposureStrike;
    if(volEl) volEl.textContent=mvcVol?fmtS(mvcVol.strike):'—';
  })();
  if(typeof populateQuotesExpiryDropdown==='function') populateQuotesExpiryDropdown();
  updateStatsPanel();
}

// ── STATS PANEL ────────────────────────────────────────────────────
function updateStatsPanel(){
  // Uses esPrice as the reference (ES futures price)
  const ref = esPrice > 0 ? esPrice : (spotPrice > 0 ? spotPrice : 0);
  if(!ref) return;
  const excelStats = window.esStatsCache || {};
  const excelLevel = key => {
    const n = parseFloat(String(excelStats[key] || '').replace(/[^0-9.-]/g, ''));
    return Number.isFinite(n) ? n : null;
  };

  // ES/SPX ratio for converting SPX levels → ES
  const ratio = esPrice > 0 && spotPrice > 0 ? esPrice / spotPrice : 1;

  // Format ES price (integer)
  const fmtES = v => v != null && !isNaN(v) ? Math.round(v * ratio).toLocaleString('en-US') : '—';

  // Distance from current ES price: signed pts and direction arrow
  const dist = (esLevel) => {
    if(esLevel == null || isNaN(esLevel) || !ref) return '—';
    const d = esLevel - ref;
    const abs = Math.abs(d).toFixed(0);
    const arrow = d >= 0 ? '▲' : '▼';
    return arrow + abs + ' pts';
  };

  // Distance color: always white
  const distColor = (esLevel) => '#fff';

  // For a zone (two prices), use closest boundary to current ES price
  const zoneDist = (hi, lo) => {
    if(hi == null || lo == null) return '—';
    const hiES = hi * ratio, loES = lo * ratio;
    const closer = Math.abs(hiES - ref) <= Math.abs(loES - ref) ? hiES : loES;
    return dist(closer);
  };
  const zoneDistColor = (hi, lo) => {
    if(hi == null || lo == null) return '#555';
    const hiES = hi * ratio, loES = lo * ratio;
    const closer = Math.abs(hiES - ref) <= Math.abs(loES - ref) ? hiES : loES;
    return distColor(closer);
  };

  const lv = window._levels || {};
  const straddle = calcStraddle();

  // Header: current ES price
  const hdr = document.getElementById('stats-es-price-hdr');
  if(hdr) hdr.textContent = ref > 0 ? 'ES ' + Math.round(ref).toLocaleString() : '—';

  // Helper to set value + distance
  const setSD = (valId, distId, spxLevel, color) => {
    const esLv = spxLevel != null ? spxLevel * ratio : null;
    const el = document.getElementById(valId);
    const dl = document.getElementById(distId);
    if(el) el.textContent = esLv != null ? Math.round(esLv).toLocaleString() : '—';
    if(dl){ dl.textContent = dist(esLv); dl.style.color = '#fff'; }
    if(color && el) el.style.color = color;
  };

  // Weekly Estimated Move (use existing estUp/estDn from _levels, already in SPX)
  const eu = lv.estUp, ed = lv.estDn;
  const euES = excelLevel('UP') ?? (eu ? eu * ratio : null), edES = excelLevel('DOWN') ?? (ed ? ed * ratio : null);
  const uEl=document.getElementById('st-est-up'), dEl=document.getElementById('st-est-dn');
  const udEl=document.getElementById('st-est-up-dist'), ddEl=document.getElementById('st-est-dn-dist');
  if(uEl) uEl.textContent = euES ? Math.round(euES).toLocaleString() : '—';
  if(dEl) dEl.textContent = edES ? Math.round(edES).toLocaleString() : '—';
  if(udEl){ udEl.textContent = dist(euES); udEl.style.color = '#fff'; }
  if(ddEl){ ddEl.textContent = dist(edES); ddEl.style.color = '#fff'; }

  // Weekly Volume Profile — manually set ES levels each week
  const VP = {
    vah: excelLevel('VAH') ?? 7483,
    vpoc: excelLevel('VPOC') ?? 7432,
    val: excelLevel('VAL') ?? 7398,
    mid: excelLevel('MID') ?? 7452
  };
  const setESLevel = (valId, distId, esLv, color) => {
    const el = document.getElementById(valId);
    const dl = document.getElementById(distId);
    if(el){ el.textContent = esLv != null ? Math.round(esLv).toLocaleString() : '—'; if(color) el.style.color = color; }
    if(dl){ dl.textContent = dist(esLv); dl.style.color = '#fff'; }
  };
  setESLevel('st-vah',  'st-vah-dist',  VP.vah,  '#fff');
  setESLevel('st-vpoc', 'st-vpoc-dist', VP.vpoc, '#fff');
  setESLevel('st-val',  'st-val-dist',  VP.val,  '#fff');
  setESLevel('st-mid',  'st-mid-dist',  VP.mid,  '#fff');

  // No Long / No Short — hardcoded ES levels, update each week
  const ZONES = {
    noLong: excelLevel('NO LONG') ?? 7617,
    noShort: excelLevel('NO SHORT') ?? 7264
  };
  setESLevel('st-nolong-hi',  'st-nolong-hi-dist',  ZONES.noLong,  '#fff');
  setESLevel('st-noshort-hi', 'st-noshort-hi-dist', ZONES.noShort, '#fff');
}

function renderTable(){
  const maxGEX=Math.max(...rawChain.map(r=>Math.abs(r.netGEX)),1);
  let data=[...rawChain].sort((a,b)=>b.strike-a.strike);
  if(currentStrikeCount>0&&spotPrice>0&&data.length>currentStrikeCount){
    const ai=data.reduce((bi,r,i)=>Math.abs(r.strike-spotPrice)<Math.abs(data[bi].strike-spotPrice)?i:bi,0);
    const half=Math.floor(currentStrikeCount/2);
    const s=Math.max(0,Math.min(ai-half,data.length-currentStrikeCount));
    data=data.slice(s,s+currentStrikeCount);
  }
  if(currentSort==='gex')data.sort((a,b)=>Math.abs(b.netGEX)-Math.abs(a.netGEX));
  const maxCallOI=Math.max(...data.map(r=>r.callOI||0));
  const maxPutOI=Math.max(...data.map(r=>r.putOI||0));
  const topCallStrike=data.find(r=>r.callOI===maxCallOI&&maxCallOI>0)?.strike;
  const topPutStrike=data.find(r=>r.putOI===maxPutOI&&maxPutOI>0)?.strike;
  const atm=data.reduce((p,c)=>Math.abs(c.strike-spotPrice)<Math.abs(p.strike-spotPrice)?c:p,data[0]||{strike:0});
  const fmtG=v=>{const abs=Math.abs(v);const sign=v>=0?'':'-';if(abs>=1e9)return sign+'$'+(abs/1e9).toFixed(2)+'B';if(abs>=1e6)return sign+'$'+(abs/1e6).toFixed(2)+'M';if(abs>=1e3)return sign+'$'+(abs/1e3).toFixed(2)+'K';return sign+'$'+abs.toFixed(2);};
  const fmtN=(v,d=4)=>v==null||isNaN(v)?'—':v.toFixed(d);
  const fmtK=v=>v==null?'—':v>=1000?(v/1000).toFixed(1)+'K':v.toString();
  const sw=currentView;
  let html=`<table class="gex-table"><thead><tr>
    <th class="strike-col">Strike</th>
    <th class="call-col">Call IV</th><th class="call-col">Call Δ</th><th class="call-col">Call OI</th><th class="call-col">Call GEX</th>
    <th style="min-width:150px">Net GEX</th>
    <th class="put-col">Put GEX</th><th class="put-col">Put OI</th><th class="put-col">Put Δ</th><th class="put-col">Put IV</th>
  </tr></thead><tbody>`;
  data.forEach(r=>{
    const isATM=r.strike===atm?.strike;
    const isFlip=flipPoint&&Math.abs(r.strike-flipPoint)<2.5;
    const isTopCall=r.strike===topCallStrike;
    const isTopPut=r.strike===topPutStrike;
    let rowCls=isATM?'atm-row':'';
    if(isTopCall)rowCls+=' hi-call';
    if(isTopPut)rowCls+=' hi-put';
    const pct=maxGEX>0?Math.abs(r.netGEX)/maxGEX*100:0;
    const bc=r.netGEX>=0?'green':'red';
    html+=`<tr class="${rowCls}">
      <td class="strike-col">${r.strike.toLocaleString()}
        ${isATM?'<span class="atm-badge">ATM</span>':''}
        ${isFlip?'<span class="flip-badge">FLIP</span>':''}
        ${isTopCall?'<span class="hi-badge call">★ CALL</span>':''}
        ${isTopPut?'<span class="hi-badge put">★ PUT</span>':''}
      </td>
      <td class="call-col">${sw!=='puts'?r.callIV.toFixed(1)+'%':'—'}</td>
      <td class="call-col">${sw!=='puts'?fmtN(r.callDelta,3):'—'}</td>
      <td class="call-col">${sw!=='puts'?fmtK(r.callOI):'—'}</td>
      <td class="call-col">${sw!=='puts'?fmtG(r.callGEX):'—'}</td>
      <td class="${r.netGEX>=0?'pos-gex':'neg-gex'}">
        <div class="bar-wrap"><div class="bar-bg"><div class="bar-fill ${bc}" style="width:${pct.toFixed(1)}%"></div></div><span class="bar-val">${fmtG(r.netGEX)}</span></div>
      </td>
      <td class="put-col">${sw!=='calls'?fmtG(r.putGEX):'—'}</td>
      <td class="put-col">${sw!=='calls'?fmtK(r.putOI):'—'}</td>
      <td class="put-col">${sw!=='calls'?fmtN(r.putDelta,3):'—'}</td>
      <td class="put-col">${sw!=='calls'?r.putIV.toFixed(1)+'%':'—'}</td>
    </tr>`;
  });
  html+='</tbody></table>';
  const tw=document.getElementById('table-wrap');
  if(tw)tw.innerHTML=html;
}

function renderChart(){
  let data=[...rawChain].sort((a,b)=>b.strike-a.strike);
  if(currentStrikeCount>0&&spotPrice>0&&data.length>currentStrikeCount){
    const ai=data.reduce((bi,r,i)=>Math.abs(r.strike-spotPrice)<Math.abs(data[bi].strike-spotPrice)?i:bi,0);
    const half=Math.floor(currentStrikeCount/2);
    const s=Math.max(0,Math.min(ai-half,data.length-currentStrikeCount));
    data=data.slice(s,s+currentStrikeCount);
  }
  const values=data.map(r=>r.netGEX/1e6);
  const labels=data.map(r=>'$'+r.strike.toLocaleString());
  const bgC=values.map(v=>v>=0?'rgba(31,174,94,0.85)':'rgba(204,34,51,0.85)');
  const bdC=values.map(v=>v>=0?'#00e676':'#ff4757');
  const atmStrike=data.reduce((p,c)=>Math.abs(c.strike-spotPrice)<Math.abs(p.strike-spotPrice)?c:p,data[0]);
  const atmLabel=atmStrike?'$'+atmStrike.strike.toLocaleString():null;
  const legendSpot=document.getElementById('legend-spot');
  if(legendSpot)legendSpot.textContent=spotPrice>0?'SPX $'+spotPrice.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}):'';
  const heading=document.getElementById('chart-heading');
  if(heading)heading.textContent='Net GEX by Strike — SPX'+(selectedExpiry?' | '+selectedExpiry:'');
  const canvas=document.getElementById('gex-chart');
  if(!canvas)return;
  let tooltip=document.getElementById('chart-tooltip');
  if(!tooltip){tooltip=document.createElement('div');tooltip.id='chart-tooltip';tooltip.style.cssText='position:fixed;display:none;z-index:10000;width:320px;background:#07101a;border:1px solid #25415f;border-radius:6px;box-shadow:0 16px 40px rgba(0,0,0,.42);padding:10px 12px;color:#d7e4f5;font-family:Arial;font-size:10px;line-height:1.5;pointer-events:none';document.body.appendChild(tooltip);}
  if(gexChart){gexChart.destroy();gexChart=null;}
  const barH=Math.max(300,data.length*22);canvas.style.height=barH+'px';
  gexChart=new Chart(canvas.getContext('2d'),{
    type:'bar',data:{labels,datasets:[{data:values,backgroundColor:bgC,borderColor:bdC,borderWidth:1,borderRadius:1,borderSkipped:false}]},
    options:{indexAxis:'y',responsive:true,maintainAspectRatio:false,animation:{duration:200},
      plugins:{legend:{display:false},tooltip:{enabled:false},zoom:{pan:{enabled:true,mode:'y',modifierKey:'shift'},zoom:{wheel:{enabled:true,modifierKey:'shift'},pinch:{enabled:true},mode:'y'}}},
      scales:{
        y:{grid:{color:'rgba(42,64,96,0.35)',lineWidth:0.5},ticks:{color:'#5a7a99',font:{family:'Arial',size:11}},border:{color:'#1e3050'}},
        x:{grid:{color:ctx=>ctx.tick.value===0?'rgba(200,200,200,.25)':'rgba(42,64,96,.35)',lineWidth:ctx=>ctx.tick.value===0?1.5:0.5},
          ticks:{color:'#5a7a99',font:{family:'Arial',size:11},callback:v=>Math.abs(v)>=1000?'$'+(v/1000).toFixed(0)+'B':'$'+v.toFixed(0)+'M'},border:{color:'#1e3050'}}
      },
      onHover:(evt,els,ch)=>{
        if(!tooltip)return;
        if(!els.length){tooltip.style.display='none';return;}
        const idx=els[0].index,r=data[idx];if(!r)return;
        // Use consistent unit across all tooltip values (pick unit from largest abs value)
        const _allAbs=[Math.abs(r.netGEX),Math.abs(r.callGEX),Math.abs(r.putGEX)];
        const _maxAbs=Math.max(..._allAbs);
        const _unit = _maxAbs>=1e9?'B':_maxAbs>=1e6?'M':'K';
        const _div  = _unit==='B'?1e9:_unit==='M'?1e6:1e3;
        const fmtG=v=>{const sign=v>=0?'':'-'; return sign+'$'+(Math.abs(v)/_div).toFixed(2)+_unit;};
        const fmtIV=v=>v>0?v.toFixed(1)+'%':'—';
        // callPos/putPos = OI+Vol (what was used for netGEX)
        const callPos = (r.callOI||0) + (r.callVolume||0);
        const putPos  = (r.putOI||0)  + (r.putVolume||0);
        const fmtGamma = v => v ? v.toFixed(6) : '0';
        const fmtPos = v => v>=1000?(v/1000).toFixed(1)+'K':(v||0).toFixed(0);
        const fmtSignedPos = v => `${v>0?'+':v<0?'âˆ’':''}${fmtPos(Math.abs(v||0))}`;
        // Verify: callGEX - putGEX should equal netGEX
        const calcNet = r.callGEX - r.putGEX;
        const fromSpotPct = spotPrice ? ((r.strike - spotPrice) / spotPrice * 100) : 0;
        const fromSpotStr = fromSpotPct >= 0 ? '+' : '';
        console.log('NEW TOOLTIP FORMAT RUNNING', r.strike, r.netGEX);
        tooltip.innerHTML=`<div style="font-weight:700;color:#f4fbff;font-size:12px;margin-bottom:6px">NET GEX</div>
          <div style="display:grid;grid-template-columns:auto 1fr;gap:3px 8px;margin-bottom:10px;color:#90a9c4;font-size:10px">
            <div style="color:#a9bdd2">(strike)</div><div style="color:#fff;font-weight:700">${r.strike.toLocaleString()}</div>
            <div style="color:#a9bdd2">from spot</div><div style="color:#fff;font-weight:700">${fromSpotStr}${fromSpotPct.toFixed(2)}%</div>
            <div style="color:#a9bdd2">contract price (otm)</div><div style="color:#fff;font-weight:700">—</div>
          </div>
          <div style="border-top:1px solid #1a3a50;padding-top:8px;margin-top:8px">
            <div style="display:grid;grid-template-columns:auto 1fr;gap:3px 8px;color:#a9bdd2;font-size:10px;margin-bottom:8px">
              <div>net gex</div><div style="color:#${r.netGEX>=0?'90ffc8':'ffaaaa'};font-weight:700">${fmtG(r.netGEX)}</div>
              <div>call gex</div><div style="color:#90ffc8;font-weight:700">${fmtG(r.callGEX)}</div>
              <div>put gex</div><div style="color:#ffaaaa;font-weight:700">${fmtG(r.putGEX)}</div>
            </div>
            <div style="border-top:1px solid #1a3a50;padding-top:8px;display:grid;grid-template-columns:auto 1fr;gap:3px 8px;color:#a9bdd2;font-size:10px;margin-bottom:8px">
              <div>volume (call)</div><div style="color:#fff;font-weight:700">${fmtPos(r.callVolume||0)}</div>
              <div>volume (put)</div><div style="color:#fff;font-weight:700">${fmtPos(r.putVolume||0)}</div>
            </div>
            <div style="border-top:1px solid #1a3a50;padding-top:8px;display:grid;grid-template-columns:auto 1fr;gap:3px 8px;color:#a9bdd2;font-size:10px">
              <div>open interest (call)</div><div style="color:#fff;font-weight:700">${fmtPos(r.callOI)}</div>
              <div>open interest (put)</div><div style="color:#fff;font-weight:700">${fmtPos(r.putOI)}</div>
            </div>
          </div>`;
        const wr=canvas.parentElement.getBoundingClientRect(),bar=els[0].element;
        let left=bar.x-wr.left+14;if(left+190>wr.width-10)left=bar.x-wr.left-200;
        tooltip.style.left=left+'px';tooltip.style.top=Math.max(8,bar.y-wr.top-20)+'px';tooltip.style.display='block';
      }
    }
  });
  if(canvas)canvas.addEventListener('mouseleave',()=>{if(tooltip)tooltip.style.display='none';});
}

// Calculate Volume-Weighted Delta GEX (vGEX)
// Formula: vGEX ≈ Gamma × Volume × Delta × Spot²
// Sign: + for calls, - for puts (directional weighting)
function calculateDeltaWeightedGEX(row, spotPrice) {
  if (!spotPrice || spotPrice <= 0) return 0;
  const spot = spotPrice;
  const spotSq = spot * spot;

  // Call side: Gamma × Volume × Delta × Spot² (positive)
  // Using absolute delta for magnitude, preserve call directional sign
  const callVGEX = (row.callGamma || 0) * (row.callVolume || 0) * Math.abs(row.callDelta || 0) * spotSq;

  // Put side: negative (subtract) - same formula but negative sign
  // Using absolute delta for magnitude, preserve put directional sign (negative)
  const putVGEX = -((row.putGamma || 0) * (row.putVolume || 0) * Math.abs(row.putDelta || 0) * spotSq);

  return callVGEX + putVGEX;
}

function renderHeatmap(){
  // Update expiration display
  const expEl = document.getElementById('gex-current-exp');
  const chartExpEl = document.getElementById('chart-exp-display');
  if(selectedExpiry) {
    const dte = getDTE(selectedExpiry);
    const expText = `${selectedExpiry} (${dte}DTE)`;
    if(expEl) expEl.textContent = `(${expText})`;
    if(chartExpEl) chartExpEl.textContent = expText;
  } else {
    if(expEl) expEl.textContent = '(—)';
    if(chartExpEl) chartExpEl.textContent = '—';
  }
  
  const body=document.getElementById('heatmap-body');if(!body)return;
  const _hmSpot = spotPrice > 0 ? spotPrice : 0;
  let data=[...rawChain]
    .filter(r => {
      const deltaWeightedGEX = calculateDeltaWeightedGEX(r, spotPrice);
      const vexPlusDWGEX = (r.netVolGEX || 0) + (deltaWeightedGEX || 0);
      return Math.abs(r.netGEX||0) > 0 || Math.abs(r.netVolGEX||0) > 0 || Math.abs(r.netDEX||0) > 0 || Math.abs(deltaWeightedGEX||0) > 0 || Math.abs(vexPlusDWGEX||0) > 0;
    })
    .filter(r => _hmSpot <= 0 || (r.strike >= _hmSpot - 100 && r.strike <= _hmSpot + 100))
    .sort((a,b)=>b.strike-a.strike);
  const changeMinutes = [5, 15, 30].includes(parseInt(gexChangeWindow, 10)) ? parseInt(gexChangeWindow, 10) : 30;
  const targetTs = Date.now() - changeMinutes * 60 * 1000;
  let changeSnap = null;
  for(const s of gexSnapshots){
    if(s.ts <= targetTs + 90000){
      if(!changeSnap || s.ts > changeSnap.ts) changeSnap = s;
    }
  }
  const rows=data.map(r=>{
    const prev = changeSnap?.data?.get(r.strike);
    const deltaWeightedGEX = calculateDeltaWeightedGEX(r, spotPrice);
    const changeNet = prev == null ? 0 : (r.netGEX || 0) - prev;
    const vexPlusDWGEX = (r.netVolGEX || 0) + (deltaWeightedGEX || 0);
    return {...r,dispNet:r.netGEX,dispCall:r.callGEX,dispPut:-Math.abs(r.putGEX),dispVolGEX:r.netVolGEX,dispDEX:r.netDEX,dispVEX:vexPlusDWGEX,dispDWGEX:deltaWeightedGEX,changeNet};
  });
  const robustScale = (values, pct = 0.95) => {
    const abs = values
      .map(v => Math.abs(Number(v || 0)))
      .filter(v => Number.isFinite(v) && v > 0)
      .sort((a, b) => a - b);
    if (!abs.length) return 1;
    const idx = Math.min(abs.length - 1, Math.max(0, Math.floor(abs.length * pct)));
    return Math.max(1, abs[idx]);
  };
  // Use a robust per-column ceiling so one outlier does not flatten the entire heatmap.
  const mN   = robustScale(rows.map(r => r.dispNet), 0.95);
  const mC   = robustScale(rows.map(r => r.dispCall), 0.95);
  const mP   = robustScale(rows.map(r => r.dispPut), 0.95);
  const mV   = robustScale(rows.map(r => r.dispVolGEX || 0), 0.95);
  const mDEX = robustScale(rows.map(r => r.dispDEX || 0), 0.95);
  const mVEX = robustScale(rows.map(r => r.dispVEX || 0), 0.95);
  const mDWGEX = robustScale(rows.map(r => r.dispDWGEX || 0), 0.95);

  const fmtG=v=>{const abs=Math.abs(v);const sign=v>=0?'':'-';if(abs>=1e9)return sign+'$'+(abs/1e9).toFixed(2)+'B';if(abs>=1e6)return sign+'$'+(abs/1e6).toFixed(2)+'M';if(abs>=1e3)return sign+'$'+(abs/1e3).toFixed(2)+'K';return sign+'$'+abs.toFixed(2);};
  const fmtChg=v=>{const abs=Math.abs(v||0);const sign=v>0?'+':v<0?'-':'';if(abs>=1e9)return sign+'$'+(abs/1e9).toFixed(2)+'B';if(abs>=1e6)return sign+'$'+(abs/1e6).toFixed(2)+'M';if(abs>=1e3)return sign+'$'+(abs/1e3).toFixed(2)+'K';return sign+'$'+abs.toFixed(2);};
  const fmtOI=v=>v>=1000?(v/1000).toFixed(1)+'K':(v||0).toString();
  const atm=data.length?data.reduce((p,c)=>Math.abs(c.strike-spotPrice)<Math.abs(p.strike-spotPrice)?c:p,data[0]):null;

  // Rank by absolute net GEX - top 5 each side
  const aboveATM=rows.filter(r=>r.strike>(atm?.strike||0));
  const belowATM=rows.filter(r=>r.strike<=(atm?.strike||0));
  const rankSide=arr=>{const m=new Map();[...arr].sort((a,b)=>Math.abs(b.netGEX)-Math.abs(a.netGEX)).slice(0,5).forEach((r,i)=>m.set(r.strike,i+1));return m;};
  const rankAbove=rankSide(aboveATM), rankBelow=rankSide(belowATM);
  const rankColors={1:'#ffd700',2:'#c0c0c0',3:'#cd7f32',4:'#4a7a99',5:'#3a5570'};
  const rankBg={1:'rgba(255,215,0,0.15)',2:'rgba(192,192,192,0.1)',3:'rgba(205,127,50,0.1)',4:'rgba(74,122,153,0.08)',5:'rgba(58,85,112,0.06)'};

  const visCols=[
    {key:'net',label:'NET GEX',cls:''},
    {key:'vol',label:'VOL ONLY GEX',cls:''},
    {key:'dex',label:'DEX',cls:''},
    {key:'vex',label:'VEX',cls:''},
    {key:'dwgex',label:'DELTA WEIGHTED GEX',cls:''},
  ];

  // Find strike with highest absolute value per column for gold highlight
  const topStrike={
    net:  rows.length ? rows.reduce((a,b)=>Math.abs(b.dispNet)>Math.abs(a.dispNet)?b:a, rows[0])?.strike : null,
    vol:  rows.length ? rows.reduce((a,b)=>Math.abs(b.dispVolGEX||0)>Math.abs(a.dispVolGEX||0)?b:a, rows[0])?.strike : null,
    dex:  rows.length ? rows.reduce((a,b)=>Math.abs(b.dispDEX||0)>Math.abs(a.dispDEX||0)?b:a, rows[0])?.strike : null,
    vex:  rows.length ? rows.reduce((a,b)=>Math.abs(b.dispVEX||0)>Math.abs(a.dispVEX||0)?b:a, rows[0])?.strike : null,
    dwgex:  rows.length ? rows.reduce((a,b)=>Math.abs(b.dispDWGEX||0)>Math.abs(a.dispDWGEX||0)?b:a, rows[0])?.strike : null,
  };
  const top3ByCol = {};
  [
    ['net', r => r.dispNet],
    ['vol', r => r.dispVolGEX || 0],
    ['dex', r => r.dispDEX || 0],
    ['vex', r => r.dispVEX || 0],
    ['dwgex', r => r.dispDWGEX || 0],
  ].forEach(([key, getter]) => {
    top3ByCol[key] = new Map(
      [...rows]
        .sort((a, b) => Math.abs(getter(b)) - Math.abs(getter(a)))
        .slice(0, 3)
        .map((row, idx) => [row.strike, idx + 1])
    );
  });

  const gc=`80px repeat(${visCols.length},1fr)`;
  const spotLbl=document.getElementById('hm-spot-label');if(spotLbl)spotLbl.textContent=spotPrice>0?'SPX $'+spotPrice.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}):'';
  const toolbarSel=document.getElementById('gex-change-window-toolbar');
  if(toolbarSel && toolbarSel.value !== String(changeMinutes)) toolbarSel.value = String(changeMinutes);
  let html='';

  rows.forEach(r=>{
    const isATM=atm&&r.strike===atm.strike;
    const rank=rankAbove.get(r.strike)||rankBelow.get(r.strike);
    const rankBadge=rank?`<span style="font-size:9px;font-weight:800;color:${rankColors[rank]};background:${rankBg[rank]};padding:0 3px;border-radius:2px;border:1px solid ${rankColors[rank]}44;margin-left:3px">#${rank}</span>`:'';
    const atmStyle=isATM?'outline:1.5px solid rgba(0,229,255,0.85);outline-offset:-1px;z-index:1;position:relative;':'';
    const strikeStyle=isATM?'color:#00e5ff;background:#0a2030;':'';
    const atmBadge=isATM?'<span class="atm-badge" style="font-size:7px;color:#00e5ff;background:#062030;padding:1px 3px;border-radius:1px;margin-left:2px">ATM</span>':'';
    const cells=visCols.map(col=>{
      let bg,txt,val;
      const isTop = r.strike === topStrike[col.key];
      const topRank = top3ByCol[col.key]?.get(r.strike) || 0;
      const hmC=(v,m)=>{
        if(m===0) return 'transparent';
        const raw = Math.min(Math.abs(v)/m*(ladderIntensity||1),1);
        const eased = Math.pow(raw, 1.85);
        const boosted = Math.min(1, eased + (topRank===1 ? 0.34 : topRank===2 ? 0.22 : topRank===3 ? 0.12 : 0));
        const alpha = 0.06 + boosted * 0.94;
        if(v>=0) return `rgba(41,182,246,${alpha.toFixed(2)})`;
        return `rgba(255,71,87,${alpha.toFixed(2)})`;
      };
      const hmT=()=> '#ffffff';
      if(col.key==='net'){bg=hmC(r.dispNet,mN);txt=hmT(r.dispNet,mN);val=fmtG(r.dispNet);}
      else if(col.key==='vol'){bg=hmC(r.dispVolGEX||0,mV);txt=hmT(r.dispVolGEX||0,mV);val=fmtG(r.dispVolGEX||0);}
      else if(col.key==='dex'){bg=hmC(r.dispDEX||0,mDEX);txt=hmT(r.dispDEX||0,mDEX);val=fmtG(r.dispDEX||0);}
      else if(col.key==='vex'){bg=hmC(r.dispVEX||0,mVEX);txt=hmT(r.dispVEX||0,mVEX);val=fmtG(r.dispVEX||0);}
      else if(col.key==='dwgex'){bg=hmC(r.dispDWGEX||0,mDWGEX);txt=hmT(r.dispDWGEX||0,mDWGEX);val=fmtG(r.dispDWGEX||0);}
      const highlightStyle = topRank===1
        ? 'font-weight:800;'
        : topRank===2
          ? 'font-weight:800;'
          : topRank===3
            ? 'font-weight:800;'
            : '';
      return`<div class="hm-cell" style="background:${bg};color:${txt};${highlightStyle}">${val}</div>`;
    }).join('');
    html+=`<div class="hm-row${isATM?' hm-atm':''}" data-strike="${r.strike}" style="grid-template-columns:${gc};${atmStyle}"><div class="hm-strike" style="${strikeStyle}">${r.strike.toLocaleString()}${atmBadge}</div>${cells}</div>`;
  });
  // Preserve scroll position across re-renders so the body doesn't snap
  // to show "all contracts" each refresh. Only auto-center on ATM the
  // first time the heatmap renders (or after explicit user request).
  const prevScroll = body.scrollTop;
  body.innerHTML=html;
  // Use double-RAF: first RAF triggers layout, second reads offsetTop after paint
  requestAnimationFrame(()=>{
    requestAnimationFrame(()=>{
      if(!body.dataset.hmInitialized){
        const row = body.querySelector('.hm-atm') || body.querySelector(`[data-strike="${atm?.strike}"]`);
        if(row){
          const target = row.offsetTop - (body.clientHeight / 2) + (row.offsetHeight / 2);
          body.scrollTop = Math.max(0, target);
        }
        body.dataset.hmInitialized = '1';
      } else {
        body.scrollTop = prevScroll;
      }
    });
  });
}

// Allow callers (tab switches, manual recenter) to force a recenter on next render
window.gexHeatmapRecenter = function(){
  const body=document.getElementById('heatmap-body');
  if(body) delete body.dataset.hmInitialized;
};

// ============================================================
// HEATMAP / TABLE VIEW SWITCHER
// Renders the same columns as the heatmap but each cell is a
// horizontal bar (zero-centered) instead of a colored heatmap cell.
// ============================================================
let heatmapViewMode = (function(){
  try { return localStorage.getItem('heatmapViewMode') || 'heatmap'; } catch(e){ return 'heatmap'; }
})();

window.setHeatmapViewMode = function(mode){
  if(mode !== 'heatmap' && mode !== 'table') return;
  heatmapViewMode = mode;
  try { localStorage.setItem('heatmapViewMode', mode); } catch(e){}
  const bh = document.getElementById('hm-view-btn-heatmap');
  const bt = document.getElementById('hm-view-btn-table');
  if(bh){ bh.style.background = mode==='heatmap' ? '#1a2a3a' : 'transparent'; bh.style.color = mode==='heatmap' ? '#00e5ff' : '#3a5570'; }
  if(bt){ bt.style.background = mode==='table'   ? '#1a2a3a' : 'transparent'; bt.style.color = mode==='table'   ? '#00e5ff' : '#3a5570'; }
  // Re-init scroll-to-ATM behavior on view change
  window.gexHeatmapRecenter && window.gexHeatmapRecenter();
  renderHeatmap();
};

// Wrap the heatmap render so the toolbar/dispatch decides which renderer to use.
// Keep the existing function name `renderHeatmap` callable from elsewhere while
// branching internally based on heatmapViewMode.
const _renderHeatmapOriginal = renderHeatmap;
renderHeatmap = function(){
  if(heatmapViewMode === 'table') return renderHeatmapTable();
  return _renderHeatmapOriginal.apply(this, arguments);
};
window.renderHeatmap = renderHeatmap;

function renderHeatmapTable(){
  const body=document.getElementById('heatmap-body');if(!body)return;
  const _hmtSpot = spotPrice > 0 ? spotPrice : 0;
  let data=[...rawChain]
    .filter(r => {
      const deltaWeightedGEX = calculateDeltaWeightedGEX(r, spotPrice);
      return Math.abs(deltaWeightedGEX||0) > 0 || Math.abs(r.netVolGEX||0) > 0 || Math.abs(r.netDEX||0) > 0;
    })
    .filter(r => _hmtSpot <= 0 || (r.strike >= _hmtSpot - 100 && r.strike <= _hmtSpot + 100))
    .sort((a,b)=>b.strike-a.strike);
  const changeMinutes = [5, 15, 30].includes(parseInt(gexChangeWindow, 10)) ? parseInt(gexChangeWindow, 10) : 30;
  const targetTs = Date.now() - changeMinutes * 60 * 1000;
  let changeSnap = null;
  for(const s of gexSnapshots){
    if(s.ts <= targetTs + 90000){
      if(!changeSnap || s.ts > changeSnap.ts) changeSnap = s;
    }
  }
  
  // Calculate rolling 30-min vol GEX per strike
  const thirtyMinAgo = Date.now() - 30 * 60 * 1000;
  const relevantVolSnaps = volGexSnapshots.filter(s => s.ts >= thirtyMinAgo);
  
  const rows=data.map(r=>{
    const prev = changeSnap?.data?.get(r.strike);
    const deltaWeightedGEX = calculateDeltaWeightedGEX(r, spotPrice);
    const changeNet = prev == null ? 0 : (deltaWeightedGEX || 0) - prev;

    // Rolling 30-min vol GEX: average of vol GEX over the period
    let rolling30VolGex = r.netVolGEX || 0;
    if(relevantVolSnaps.length > 0){
      let sum = 0;
      relevantVolSnaps.forEach(snap => {
        sum += snap.data.get(r.strike) || 0;
      });
      rolling30VolGex = sum / relevantVolSnaps.length;
    }

    const vexPlusDWGEX = (r.netVolGEX || 0) + (deltaWeightedGEX || 0);
    return {
      ...r,
      dispNet: deltaWeightedGEX,
      dispVolGEX: r.netVolGEX,
      dispDEX: r.netDEX,
      dispVEX: vexPlusDWGEX,
      dispDWGEX: deltaWeightedGEX,
      changeNet,
      rolling30VolGex
    };
  });

  // Per-column max (absolute) so each bar is normalized within its own column
  const robustScale = (values, pct = 0.95) => {
    const abs = values
      .map(v => Math.abs(Number(v || 0)))
      .filter(v => Number.isFinite(v) && v > 0)
      .sort((a, b) => a - b);
    if (!abs.length) return 1;
    const idx = Math.min(abs.length - 1, Math.max(0, Math.floor(abs.length * pct)));
    return Math.max(1, abs[idx]);
  };
  const mNet       = robustScale(rows.map(r=>r.dispNet), 0.95);
  const mVol       = robustScale(rows.map(r=>r.dispVolGEX), 0.95);
  const mDEX       = robustScale(rows.map(r=>r.dispDEX), 0.95);
  const mVEX       = robustScale(rows.map(r=>r.dispVEX), 0.95);
  const mDWGEX     = robustScale(rows.map(r=>r.dispDWGEX), 0.95);

  const fmtG = v=>{const abs=Math.abs(v);const sign=v>=0?'':'-';if(abs>=1e9)return sign+'$'+(abs/1e9).toFixed(2)+'B';if(abs>=1e6)return sign+'$'+(abs/1e6).toFixed(2)+'M';if(abs>=1e3)return sign+'$'+(abs/1e3).toFixed(2)+'K';return sign+'$'+abs.toFixed(2);};
  const fmtChg=v=>{const abs=Math.abs(v||0);const sign=v>0?'+':v<0?'-':'';if(abs>=1e9)return sign+'$'+(abs/1e9).toFixed(2)+'B';if(abs>=1e6)return sign+'$'+(abs/1e6).toFixed(2)+'M';if(abs>=1e3)return sign+'$'+(abs/1e3).toFixed(2)+'K';return sign+'$'+abs.toFixed(2);};

  const atm=data.length?data.reduce((p,c)=>Math.abs(c.strike-spotPrice)<Math.abs(p.strike-spotPrice)?c:p,data[0]):null;

  const visCols=[
    {key:'net',    label:'NET GEX',           max:mNet,    getVal:r=>r.dispNet||0,       fmt:fmtG},
    {key:'vol',    label:'VOL ONLY GEX',      max:mVol,    getVal:r=>r.dispVolGEX||0,    fmt:fmtG},
    {key:'dex',    label:'DEX',               max:mDEX,    getVal:r=>r.dispDEX||0,       fmt:fmtG},
    {key:'vex',    label:'VEX',               max:mVEX,    getVal:r=>r.dispVEX||0,       fmt:fmtG},
    {key:'dwgex',  label:'DELTA WEIGHTED GEX', max:mDWGEX,  getVal:r=>r.dispDWGEX||0,    fmt:fmtG},
  ];

  // Find strike with highest absolute value per column for gold highlight
  const topStrike={};
  visCols.forEach(c=>{ topStrike[c.key] = rows.length ? rows.reduce((a,b)=>Math.abs(c.getVal(b))>Math.abs(c.getVal(a))?b:a, rows[0])?.strike : null; });

  // Rank by absolute net GEX - top 5 each side (kept consistent with heatmap)
  const aboveATM=rows.filter(r=>r.strike>(atm?.strike||0));
  const belowATM=rows.filter(r=>r.strike<=(atm?.strike||0));
  const rankSide=arr=>{const m=new Map();[...arr].sort((a,b)=>Math.abs(b.netGEX)-Math.abs(a.netGEX)).slice(0,5).forEach((r,i)=>m.set(r.strike,i+1));return m;};
  const rankAbove=rankSide(aboveATM), rankBelow=rankSide(belowATM);
  const rankColors={1:'#ffd700',2:'#c0c0c0',3:'#cd7f32',4:'#4a7a99',5:'#3a5570'};
  const rankBg={1:'rgba(255,215,0,0.15)',2:'rgba(192,192,192,0.1)',3:'rgba(205,127,50,0.1)',4:'rgba(74,122,153,0.08)',5:'rgba(58,85,112,0.06)'};

  const gc=`80px repeat(${visCols.length},1fr)`;
  const spotLbl=document.getElementById('hm-spot-label');if(spotLbl)spotLbl.textContent=spotPrice>0?'SPX $'+spotPrice.toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2}):'';
  const toolbarSel=document.getElementById('gex-change-window-toolbar');
  if(toolbarSel && toolbarSel.value !== String(changeMinutes)) toolbarSel.value = String(changeMinutes);

  // Bar cell: bar grows from LEFT edge, full-width scale. Label pinned RIGHT.
  function makeBarCell(value, maxAbs, fmt, isTop){
    const v = value || 0;
    const pct = maxAbs > 0 ? Math.min(Math.abs(v)/maxAbs, 1)*85 : 0;
    const isPos = v >= 0;
    const barColor = isTop ? 'rgba(180,140,0,0.6)' : (isPos ? 'rgba(20,83,45,0.85)' : 'rgba(127,29,29,0.85)');
    const txtColor = '#ffffff';
    const fontW = isTop ? 800 : 600;
    const label = fmt(v);
    return `<div class="hm-cell hm-bar-cell" style="position:relative;height:22px;padding:0;background:transparent;border-right:1px solid #0d1825;overflow:hidden;"><span style="position:absolute;left:0;top:1px;bottom:1px;width:${pct}%;background:${barColor};border-radius:0 2px 2px 0;"></span><span style="position:absolute;top:0;bottom:0;right:5px;left:0;display:flex;align-items:center;justify-content:flex-end;font-size:10px;font-weight:${fontW};color:${txtColor};white-space:nowrap;pointer-events:none;z-index:1;">${label}</span></div>`;
  }

  let html='';
  rows.forEach(r=>{
    const isATM = atm && r.strike===atm.strike;
    const rank = rankAbove.get(r.strike) || rankBelow.get(r.strike);
    const rankBadge = rank ? `<span style="font-size:9px;font-weight:800;color:${rankColors[rank]};background:${rankBg[rank]};padding:0 3px;border-radius:2px;border:1px solid ${rankColors[rank]}44;margin-left:3px">#${rank}</span>` : '';
    const atmStyle = isATM ? 'box-shadow:inset 0 0 0 1.5px rgba(255,255,255,0.85);' : '';
    const strikeStyle = isATM ? 'color:#00e5ff;background:#0a2030;' : '';
    const atmBadge = isATM ? '<span class="atm-badge" style="font-size:7px;color:#00e5ff;background:#062030;padding:1px 3px;border-radius:1px;margin-left:2px">ATM</span>' : '';
    const cells = visCols.map(col=>makeBarCell(col.getVal(r), col.max, col.fmt, r.strike===topStrike[col.key])).join('');
    html += `<div class="hm-row${isATM?' hm-atm':''}" data-strike="${r.strike}" style="grid-template-columns:${gc};${atmStyle}"><div class="hm-strike" style="${strikeStyle}">${r.strike.toLocaleString()}${rankBadge}${atmBadge}</div>${cells}</div>`;
  });

  // Preserve scroll position across re-renders (same behavior as heatmap mode)
  const prevScroll = body.scrollTop;
  body.innerHTML = html;
  requestAnimationFrame(()=>{
    requestAnimationFrame(()=>{
      if(!body.dataset.hmInitialized){
        const row = body.querySelector('.hm-atm') || body.querySelector(`[data-strike="${atm?.strike}"]`);
        if(row){
          const target = row.offsetTop - (body.clientHeight / 2) + (row.offsetHeight / 2);
          body.scrollTop = Math.max(0, target);
        }
        body.dataset.hmInitialized = '1';
      } else {
        body.scrollTop = prevScroll;
      }
    });
  });
}

