function calcStraddle(){
  if(!rawChain.length||!spotPrice) return null;
  const atm=rawChain.reduce((p,c)=>Math.abs(c.strike-spotPrice)<Math.abs(p.strike-spotPrice)?c:p,rawChain[0]);
  const liveIV=(atm.callIV+Math.abs(atm.putIV))/2/100;
  if(!sessionIV&&liveIV>0){
    sessionIV=liveIV;
    const ivEl=document.getElementById('rs-iv-locked');
    if(ivEl)ivEl.textContent='Locked: '+(sessionIV*100).toFixed(2)+'%';
  }
  const iv=sessionIV||liveIV;
  if(!iv) return null;
  const dte=selectedExpiry?Math.max(getDTE(selectedExpiry),1):7;
  const T=252;
  return{
    straddle:  spotPrice*iv*Math.sqrt(dte/T),
    sigma1:    spotPrice*iv*Math.sqrt(dte/T),
    dailyMove: spotPrice*iv*Math.sqrt(1/T),
    iv, liveIV, dte
  };
}

// ── DAILY EM FREEZE (capture once 4–6pm ET, hold until next window) ──────────
// The EM value itself is unchanged (still calcStraddle().dailyMove). We only
// snapshot it once per ET day during the 16:00–18:00 ET window and reuse that
// frozen value (move + iv + dte) for the rest of the day so it doesn't drift.
const DAILY_EM_LS_KEY = 'dailyEMFreeze';

function etNowParts(){
  // Returns {date:'YYYY-MM-DD', hour:0-23} in America/New_York
  const d = new Date();
  const date = new Intl.DateTimeFormat('en-CA', { timeZone:'America/New_York', year:'numeric', month:'2-digit', day:'2-digit' }).format(d);
  const hour = parseInt(new Intl.DateTimeFormat('en-US', { timeZone:'America/New_York', hour:'numeric', hour12:false }).format(d), 10);
  return { date, hour };
}

function readDailyEMFreeze(){
  try { return JSON.parse(localStorage.getItem(DAILY_EM_LS_KEY) || 'null'); }
  catch(_) { return null; }
}

function writeDailyEMFreeze(rec){
  try { localStorage.setItem(DAILY_EM_LS_KEY, JSON.stringify(rec)); } catch(_) {}
}

// Returns the frozen daily move/iv/dte to display.
//
// The EM is computed (via calcStraddle) ONLY inside the 4–6pm ET capture
// window, and only once per ET day. Every other read — including the REFRESH /
// recalc button — is a pure cache read: it returns the stored capture and never
// recomputes. This is why hitting refresh outside the window no longer changes
// the EM value.
function getFrozenDailyEM(){
  const { date, hour } = etNowParts();
  const stored = readDailyEMFreeze();
  const inWindow = hour >= 16 && hour < 18;       // 16:00–17:59 ET
  const haveToday = stored && stored.etDate === date;

  // Capture (the ONLY path that calls calcStraddle) — once, inside the window.
  if (inWindow && !haveToday) {
    const s = calcStraddle();
    if (s && isFinite(s.dailyMove) && s.dailyMove > 0) {
      const rec = { etDate: date, dailyMove: s.dailyMove, iv: s.iv, dte: s.dte, capturedAt: Date.now() };
      writeDailyEMFreeze(rec);
      return rec;
    }
  }
  // Everywhere else: cache only. No recompute, so refresh/recalc is stable.
  return stored || null;
}
window.getFrozenDailyEM = getFrozenDailyEM;








