function getNiceStep(rawStep){
  const mag=Math.pow(10,Math.floor(Math.log10(Math.abs(rawStep)||1)));
  const norm=rawStep/mag;
  const nice=norm<1.5?1:norm<3?2:norm<7?5:10;
  return nice*mag;
}

function buildTTChainRows(items, price){
  const combined = {};
  const spot = price || 1;
  const asArray = value => Array.isArray(value) ? value : (value ? [value] : []);
  const getStrikeGroups = expGroup => {
    const raw = expGroup?.strikes || expGroup?.['option-strikes'] || expGroup?.strikeMap || expGroup?.strike_map || [];
    if (Array.isArray(raw)) return raw;
    if (raw && typeof raw === 'object') {
      return Object.entries(raw).map(([strike, value]) => {
        if (Array.isArray(value)) return { strike, options: value };
        if (value && typeof value === 'object') return { strike, ...value };
        return { strike };
      });
    }
    return [];
  };
  const sideFromOption = opt => String(
    opt?.type || opt?.optionType || opt?.['option-type'] || opt?.putCall || opt?.['put-call'] || opt?.symbol || ''
  ).toUpperCase().includes('P') ? 'put' : 'call';
  for (const expGroup of (items || [])) {
    for (const strikeGroup of getStrikeGroups(expGroup)) {
      const strike = parseFloat(strikeGroup['strike-price'] || strikeGroup.strikePrice || strikeGroup.strike || 0);
      if (!strike) continue;
      if (!combined[strike]) {
        combined[strike] = {
          strike,
          callGamma:0, putGamma:0,
          callOI:0, putOI:0,
          callVolume:0, putVolume:0,
          callDelta:0, putDelta:0,
          callGEX:0, putGEX:0,
          callVolGEX:0, putVolGEX:0,
          callDEX:0, putDEX:0,
          callVolDEX:0, putVolDEX:0
        };
      }
      const row = combined[strike];
      const readOptionNumber = (opt, keys) => {
        const sources = [opt, opt?.greeks, opt?.['theo-greeks'], opt?.option, opt?.instrument];
        for (const source of sources) {
          if (!source || typeof source !== 'object') continue;
          for (const key of keys) {
            const value = source[key];
            if (value === null || value === undefined || value === '') continue;
            const number = Number(String(value).replace(/,/g, ''));
            if (Number.isFinite(number)) return number;
          }
        }
        return 0;
      };
      const addSide = (opt, side) => {
        if (!opt) return;
        const gamma = readOptionNumber(opt, ['gamma', 'theo-gamma']);
        const oi = readOptionNumber(opt, ['open-interest', 'open_interest', 'openInterest', 'open-interest-quantity', 'openInterestQuantity', 'oi']);
        const vol = readOptionNumber(opt, ['volume', 'day-volume', 'day_volume', 'total-volume', 'totalVolume']);
        const delta = Math.abs(readOptionNumber(opt, ['delta', 'theo-delta']));
        if (side === 'call') {
          row.callGamma += gamma;
          row.callOI += oi;
          row.callVolume += vol;
          row.callDelta += delta;
          row.callGEX += calcDollarGammaExposure(gamma, oi + vol, spot);
          row.callVolGEX += calcDollarGammaExposure(gamma, vol, spot);
          row.callDEX += delta * (oi + vol) * spot * 100;
          row.callVolDEX += delta * vol * spot * 100;
        } else {
          row.putGamma += gamma;
          row.putOI += oi;
          row.putVolume += vol;
          row.putDelta += delta;
          row.putGEX += calcDollarGammaExposure(gamma, oi + vol, spot);
          row.putVolGEX += calcDollarGammaExposure(gamma, vol, spot);
          row.putDEX += delta * (oi + vol) * spot * 100;
          row.putVolDEX += delta * vol * spot * 100;
        }
      };
      asArray(strikeGroup.call || strikeGroup.calls || strikeGroup['call-option'] || strikeGroup.callOption)
        .forEach(opt => addSide(opt, 'call'));
      asArray(strikeGroup.put || strikeGroup.puts || strikeGroup['put-option'] || strikeGroup.putOption)
        .forEach(opt => addSide(opt, 'put'));
      asArray(strikeGroup.options || strikeGroup.option || strikeGroup.legs)
        .forEach(opt => addSide(opt, sideFromOption(opt)));
    }
  }

  return Object.values(combined).map(row => {
    row.netGEX = row.callGEX - row.putGEX;
    row.netVolGEX = row.callVolGEX - row.putVolGEX;
    row.netDEX = row.callDEX - row.putDEX;
    row.volNetDEX = row.callVolDEX - row.putVolDEX;
    return row;
  }).sort((a,b) => a.strike - b.strike);
}

function buildFallbackCompareRows(ticker){
  const src = GEX_DATA?.[ticker];
  if (!src) return [];
  const savedView = (() => {
    try { return localStorage.getItem('dteGexView'); } catch (e) { return null; }
  })();
  const mode = savedView === 'combined' ? 'combined' : (savedView != null && savedView !== '' ? parseInt(savedView, 10) : null);
  const strikeMap = {};
  const addRows = entries => {
    entries.forEach(([dteKey, rows]) => {
      const dte = parseInt(dteKey, 10);
      if (mode === 'combined' && !(dte >= 1 && dte <= 7)) return;
      if (typeof mode === 'number' && Number.isFinite(mode) && dte !== mode) return;
      (rows || []).forEach(r => {
        const strike = parseFloat(r.strike || 0);
        if (!strike) return;
        if (!strikeMap[strike]) {
          strikeMap[strike] = {
            strike,
            callGamma: 0,
            putGamma: 0,
            callOI: 0,
            putOI: 0,
            callVolume: 0,
            putVolume: 0,
            callDelta: 0,
            putDelta: 0,
            callGEX: 0,
            putGEX: 0,
            netGEX: 0,
            callVolGEX: 0,
            putVolGEX: 0,
            netVolGEX: 0,
            callDEX: 0,
            putDEX: 0,
            netDEX: 0,
            callVolDEX: 0,
            putVolDEX: 0,
            volNetDEX: 0
          };
        }
        strikeMap[strike].callGEX += parseFloat(r.callGEX || 0) || 0;
        strikeMap[strike].putGEX += parseFloat(r.putGEX || 0) || 0;
        strikeMap[strike].netGEX += parseFloat(r.netGEX || 0) || 0;
        strikeMap[strike].callVolGEX += parseFloat(r.callGEX || 0) || 0;
        strikeMap[strike].putVolGEX += parseFloat(r.putGEX || 0) || 0;
        strikeMap[strike].netVolGEX += parseFloat(r.netGEX || 0) || 0;
      });
    });
  };
  addRows(Object.entries(src));
  if (!Object.keys(strikeMap).length) {
    Object.entries(src).forEach(([_, rows]) => {
      (rows || []).forEach(r => {
        const strike = parseFloat(r.strike || 0);
        if (!strike) return;
        if (!strikeMap[strike]) {
          strikeMap[strike] = {
            strike,
            callGamma: 0,
            putGamma: 0,
            callOI: 0,
            putOI: 0,
            callVolume: 0,
            putVolume: 0,
            callDelta: 0,
            putDelta: 0,
            callGEX: 0,
            putGEX: 0,
            netGEX: 0,
            callVolGEX: 0,
            putVolGEX: 0,
            netVolGEX: 0,
            callDEX: 0,
            putDEX: 0,
            netDEX: 0,
            callVolDEX: 0,
            putVolDEX: 0,
            volNetDEX: 0
          };
        }
        strikeMap[strike].callGEX += parseFloat(r.callGEX || 0) || 0;
        strikeMap[strike].putGEX += parseFloat(r.putGEX || 0) || 0;
        strikeMap[strike].netGEX += parseFloat(r.netGEX || 0) || 0;
        strikeMap[strike].callVolGEX += parseFloat(r.callGEX || 0) || 0;
        strikeMap[strike].putVolGEX += parseFloat(r.putGEX || 0) || 0;
        strikeMap[strike].netVolGEX += parseFloat(r.netGEX || 0) || 0;
      });
    });
  }
  return Object.values(strikeMap).sort((a,b) => a.strike - b.strike);
}

function filterCompareExpirations(items){
  if (!items || !items.length) return items || [];
  const today = new Date();
  today.setHours(0,0,0,0);
  const todayStr = today.toISOString().slice(0,10);
  
  // Compute 1DTE = next weekday
  const oneDte = new Date(today);
  do { oneDte.setDate(oneDte.getDate() + 1); }
  while (oneDte.getDay() === 0 || oneDte.getDay() === 6);
  const oneDteStr = oneDte.toISOString().slice(0,10);
  
  // Next Friday strictly after today
  const nextFri = new Date(today);
  const daysToFri = ((5 - nextFri.getDay()) + 7) % 7 || 7;
  nextFri.setDate(nextFri.getDate() + daysToFri);
  const nextFriStr = nextFri.toISOString().slice(0,10);
  
  // Sort available expirations and find closest match for each target
  const sortedDates = items
    .map(g => g['expiration-date'])
    .filter(Boolean)
    .sort();
  const findClosest = (target) => {
    if (sortedDates.includes(target)) return target;
    return sortedDates.find(d => d >= target) || null;
  };
  const allowed = new Set();
  const zero = findClosest(todayStr);
  const one = findClosest(oneDteStr);
  const fri = findClosest(nextFriStr);
  if (zero) allowed.add(zero);
  if (one) allowed.add(one);
  if (fri) allowed.add(fri);
  
  // Use selectedDTEs from DTE pill selection
  const getDTELocal = dateStr => {
    const x = new Date(dateStr + 'T12:00:00');
    x.setHours(0,0,0,0);
    return Math.round((x - today) / 86400000);
  };
  
  let filtered = items.filter(expGroup => allowed.has(expGroup['expiration-date']));
  
  // Filter to selected expiry date strings
  if (selectedDTEs && selectedDTEs.size > 0) {
    const matched = filtered.filter(g => selectedDTEs.has(g['expiration-date'] || ''));
    if (matched.length) filtered = matched;
  }
  
  return filtered.length ? filtered : items;
}

function getCompareExpirationForDTE(selectedDTEValue) {
  if (selectedDTEValue === null || selectedDTEValue === undefined || selectedDTEValue === '1-7') return '';
  const numericDTE = Number(selectedDTEValue);
  if (!Number.isFinite(numericDTE)) return '';
  const sortedExpiries = Object.keys(expiryMap || {}).sort();
  const matchedExpiry = sortedExpiries.find(expDate => (
    isGexTradingDay(expDate) && getDTE(expDate) === numericDTE
  ));
  return matchedExpiry || '';
}

async function fetchOverviewCompareGEX() {
  const ticker = overviewCompareTicker || 'SPY';
  try {
    const selectedCompareExpiration = getCompareExpirationForDTE(window.AppState?.selectedDTE ?? gexSelectedDTE);
    const compareChainUrl = selectedCompareExpiration
      ? `${window.location.origin}/proxy/api/tt/chains/${encodeURIComponent(ticker)}?range=all&expiration=${encodeURIComponent(selectedCompareExpiration)}`
      : `${window.location.origin}/proxy/api/tt/chains/${encodeURIComponent(ticker)}?range=all`;
    const [chainResp, quoteResp] = await Promise.all([
      fetch(compareChainUrl),
      fetch(`${window.location.origin}/proxy/api/tt/quotes-batch?equity[]=${encodeURIComponent(ticker)}`)
    ]);
    if (!chainResp.ok) throw new Error('Compare chain HTTP ' + chainResp.status);
    const chainRaw = await chainResp.json();
    let price = 0;
    if (quoteResp.ok) {
      const quoteRaw = await quoteResp.json();
      const qItem = (quoteRaw?.data?.items || []).find(item => item.symbol === ticker) || (quoteRaw?.data?.items || [])[0] || {};
      price = parseFloat(
        qItem.last || qItem.mark || qItem.mid ||
        qItem['last-price'] || qItem['mark-price'] || qItem['mid-price'] ||
        qItem['last-trade-price'] || 0
      ) || 0;
    }
    // Fallback to underlying price from chain response
    if (!price && chainRaw?.data?.underlyingPrice) {
      price = chainRaw.data.underlyingPrice;
    }
    compareSpotPrice = price || GEX_SPOTS?.[ticker] || 0;
    console.log(`[GEX] Compare ${ticker}: spot=${compareSpotPrice}, items=${(chainRaw?.data?.items||[]).length}, strikes=${(chainRaw?.data?.items||[]).reduce((s,g)=>(s+(g.strikes||[]).length),0)}`);
    compareRawChain = buildTTChainRows(filterCompareExpirations(chainRaw?.data?.items), compareSpotPrice);
    if (!compareRawChain.length) {
      compareRawChain = buildFallbackCompareRows(ticker);
    }
    if (compareSpotPrice > 0 && GEX_SPOTS) {
      GEX_SPOTS[ticker] = compareSpotPrice;
    }
  } catch (e) {
    compareRawChain = buildFallbackCompareRows(ticker);
    compareSpotPrice = GEX_SPOTS?.[ticker] || 0;
  }
}

async function refreshCompareChain() {
  await fetchOverviewCompareGEX();
  drawOverviewChart();
}

// ── OVERVIEW CHART (GammaLux style) ────────────────────────────────
function ovClamp(v, min, max){
  return Math.max(min, Math.min(max, v));
}

function ovBuildChartRows(source){
  return densifyStrikeRows(source || []);
}

function densifyStrikeRows(rows) {
  const source = [...(rows || [])]
    .filter(r => Number.isFinite(Number(r?.strike)))
    .sort((a, b) => Number(a.strike) - Number(b.strike));
  if (!source.length) return [];

  const universe = getSpxStrikeUniverse();
  const step = inferStrikeStep(universe.length ? universe : source.map(r => Number(r.strike)));
  const byStrike = new Map(source.map(r => [Number(r.strike), r]));
  const minStrike = Number(source[0].strike);
  const maxStrike = Number(source[source.length - 1].strike);
  const padded = [];

  for (let strike = minStrike; strike <= maxStrike + step * 0.25; strike += step) {
    const normalizedStrike = +strike.toFixed(4);
    const existing = byStrike.get(normalizedStrike);
    if (existing) {
      padded.push(existing);
      continue;
    }
    padded.push({
      strike: normalizedStrike,
      spotPrice: spotPrice || 0,
      callGamma: 0,
      putGamma: 0,
      callOI: 0,
      putOI: 0,
      callDelta: 0,
      putDelta: 0,
      callIV: 0,
      putIV: 0,
      callGEX: 0,
      putGEX: 0,
      netGEX: 0,
      callMark: 0,
      putMark: 0,
      callVolume: 0,
      putVolume: 0,
      callVolGEX: 0,
      putVolGEX: 0,
      netVolGEX: 0,
      callOIGEX: 0,
      putOIGEX: 0,
      netOIGEX: 0,
      callDEX: 0,
      putDEX: 0,
      callVolDEX: 0,
      putVolDEX: 0,
      volNetDEX: 0,
    });
  }

  return padded;
}

function getHighestNetGexRow(rows, field = 'netGEX') {
  const source = (rows || []).filter(Boolean);
  if (!source.length) return null;
  return source.reduce((best, row) => Math.abs(Number(row?.[field] || 0)) > Math.abs(Number(best?.[field] || 0)) ? row : best, source[0]);
}

function ovDefaultStart(rows, spot, count){
  if(!rows.length || count >= rows.length) return 0;
  const anchor = spot > 0 ? spot : rows[Math.floor(rows.length / 2)].strike;
  const atmIdx = rows.reduce((best, row, i) => Math.abs(row.strike - anchor) < Math.abs(rows[best].strike - anchor) ? i : best, 0);
  return ovClamp(atmIdx - Math.floor(count / 2), 0, rows.length - count);
}

function ovEnsureViewport(leftRows, rightRows, leftSpot, rightSpot){
  const maxLen = Math.max(leftRows.length, rightRows.length, MIN_GEX_STRIKE_COUNT);
  const configured = getConfiguredStrikeCount();
  const requested = configured > 0 ? configured : (ovViewport.count || DEFAULT_GEX_STRIKE_COUNT);
  const count = ovClamp(requested, MIN_GEX_STRIKE_COUNT, Math.max(MIN_GEX_STRIKE_COUNT, maxLen));
  ovViewport.count = count;
  window.__gexOverviewNav = ovViewport;
  if(currentStrikeCount !== count){
    currentStrikeCount = count;
    if(window.AppState) window.AppState.strikeCount = count;
  }
  const leftCount = Math.min(count, leftRows.length || count);
  const rightCount = Math.min(count, rightRows.length || count);
  if(ovViewport.leftStart == null) ovViewport.leftStart = ovDefaultStart(leftRows, leftSpot, leftCount);
  if(ovViewport.rightStart == null) ovViewport.rightStart = ovDefaultStart(rightRows, rightSpot, rightCount);
  ovViewport.leftStart = ovClamp(ovViewport.leftStart || 0, 0, Math.max(0, leftRows.length - leftCount));
  ovViewport.rightStart = ovClamp(ovViewport.rightStart || 0, 0, Math.max(0, rightRows.length - rightCount));
}

function ovVisibleRows(rows, side){
  if(!rows.length) return [];
  const count = Math.min(ovViewport.count || DEFAULT_GEX_STRIKE_COUNT, rows.length);
  const key = side === 'right' ? 'rightStart' : 'leftStart';
  const start = ovClamp(ovViewport[key] || 0, 0, Math.max(0, rows.length - count));
  ovViewport[key] = start;
  window.__gexOverviewNav = ovViewport;
  return rows.slice(start, start + count);
}

function ovResetViewport(){
  ovViewport = { count: DEFAULT_GEX_STRIKE_COUNT, leftStart: null, rightStart: null };
  window.__gexOverviewNav = ovViewport;
  setConfiguredStrikeCount(DEFAULT_GEX_STRIKE_COUNT);
}

function drawOverviewChartFreshSimple(){
  const canvas = document.getElementById('overview-canvas');
  if(!canvas) return;
  const container = document.getElementById('overview-scroll');
  const W = Math.max(1, container ? container.clientWidth : canvas.clientWidth || 900);
  const H = Math.max(1, container ? container.clientHeight : canvas.clientHeight || 500);
  if (canvas.width !== W) canvas.width = W;
  if (canvas.height !== H) canvas.height = H;
  const ctx = canvas.getContext('2d');
  if(!ctx) return;

  const fallbackBucket = (() => {
    const spx = GEX_DATA?.SPX || {};
    const keys = Object.keys(spx).sort((a, b) => {
      const na = Number(a), nb = Number(b);
      if (Number.isFinite(na) && Number.isFinite(nb)) return na - nb;
      return String(a).localeCompare(String(b));
    });
    return spx['-1'] || spx['0'] || (keys.length ? spx[keys[0]] : null) || [];
  })();

  // Build densified rows and apply viewport slicing so zoom/scroll work
  const allRows = ovBuildChartRows(Array.isArray(rawChain) && rawChain.length ? rawChain : fallbackBucket);
  const compareSource = compareRawChain && compareRawChain.length ? compareRawChain : [];
  const compareAllRows = ovBuildChartRows(compareSource);
  const rightSpot = compareSpotPrice || (typeof GEX_SPOTS !== 'undefined' && GEX_SPOTS?.[overviewCompareTicker]) || spotPrice;
  ovEnsureViewport(allRows, compareAllRows, spotPrice, rightSpot);
  const rows = ovVisibleRows(allRows, 'left');

  ctx.clearRect(0, 0, W, H);
  ctx.fillStyle = '#050810';
  ctx.fillRect(0, 0, W, H);

  if(!rows.length){
    ctx.fillStyle = '#2a4060';
    ctx.font = '13px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('Waiting for data...', W / 2, H / 2 - 18);
    ctx.font = '11px Arial';
    ctx.fillText(`expiries: ${Object.keys(expiryMap || {}).length}`, W / 2, H / 2 + 2);
    ctx.fillText(`selected: ${selectedExpiry || '-'}`, W / 2, H / 2 + 18);
    ctx.fillText(`rawChain: ${(rawChain && rawChain.length) || 0}`, W / 2, H / 2 + 34);
    ctx.fillText(`spot: ${Number(spotPrice || 0).toFixed(2)}`, W / 2, H / 2 + 50);
    return;
  }

  const sorted = [...rows].sort((a, b) => a.strike - b.strike);
  const minStrike = sorted[0].strike;
  const maxStrike = sorted[sorted.length - 1].strike;
  const pad = { l: 48, r: 18, t: 30, b: 30 };
  const chartW = Math.max(1, W - pad.l - pad.r);
  const chartH = Math.max(1, H - pad.t - pad.b);
  const midY = pad.t + chartH / 2;
  const span = Math.max(1, maxStrike - minStrike);
  const minVisible = Math.max(1.5, Math.min(8, chartH * 0.018));

  // Linear Y-axis: true max with 10% headroom — no sqrt distortion, no clipping
  const netGEXVals = sorted.map(r => Math.abs(Number(r.netGEX || 0))).filter(v => Number.isFinite(v) && v > 0);
  const maxAbs = Math.max(netGEXVals.length ? netGEXVals[netGEXVals.length - 1] : 1, 1);
  const maxG = maxAbs * 1.10 / (ovYScale || 1);
  const yFor = v => midY - (Number(v || 0) / maxG) * (chartH / 2);

  // Grid lines
  ctx.strokeStyle = 'rgba(37, 84, 120, 0.35)';
  ctx.lineWidth = 1;
  for (let i = 0; i <= 4; i++) {
    const y = pad.t + (chartH * i / 4);
    ctx.beginPath();
    ctx.moveTo(pad.l, y);
    ctx.lineTo(W - pad.r, y);
    ctx.stroke();
  }

  // Zero line
  ctx.strokeStyle = 'rgba(0, 229, 255, 0.55)';
  ctx.beginPath();
  ctx.moveTo(pad.l, midY);
  ctx.lineTo(W - pad.r, midY);
  ctx.stroke();

  // Bars — linear height, uncapped
  const barW = Math.max(2, chartW / Math.max(10, sorted.length * 1.25) * 0.82);
  sorted.forEach(row => {
    const gex = Number(row.netGEX || 0);
    if (gex === 0) return;
    const x = sorted.length > 1
      ? pad.l + ((row.strike - minStrike) / span) * chartW
      : pad.l + chartW / 2;
    const h = Math.max(minVisible, Math.abs(yFor(gex) - midY));
    const y = gex >= 0 ? midY - h : midY;
    ctx.fillStyle = gex >= 0 ? 'rgba(0, 229, 255, 0.72)' : 'rgba(255, 92, 92, 0.72)';
    ctx.fillRect(x - barW / 2, y, barW, h);
  });

  // Peak label
  const peakRow = sorted.reduce((best, row) => Math.abs(Number(row.netGEX || 0)) > Math.abs(Number(best.netGEX || 0)) ? row : best, sorted[0]);
  if (peakRow && peakRow.netGEX !== 0) {
    const peakX = sorted.length > 1 ? pad.l + ((peakRow.strike - minStrike) / span) * chartW : pad.l + chartW / 2;
    const peakGEX = Number(peakRow.netGEX || 0);
    const peakH = Math.max(minVisible, Math.abs(yFor(peakGEX) - midY));
    const peakY = peakGEX >= 0 ? midY - peakH : midY;
    ctx.fillStyle = '#ffd966';
    ctx.font = '11px Arial';
    ctx.textAlign = 'left';
    ctx.fillText(`Peak ${peakRow.strike.toLocaleString()}`, Math.min(W - 120, peakX + 8), Math.max(pad.t + 12, peakY - 6));
  }

  // Spot price line
  const atm = Number(spotPrice || sorted[Math.floor(sorted.length / 2)]?.strike || 0);
  if (atm > 0 && atm >= minStrike && atm <= maxStrike) {
    const atmX = sorted.length > 1 ? pad.l + ((atm - minStrike) / span) * chartW : pad.l + chartW / 2;
    ctx.setLineDash([5, 5]);
    ctx.strokeStyle = 'rgba(200, 200, 200, 0.35)';
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(atmX, pad.t);
    ctx.lineTo(atmX, H - pad.b);
    ctx.stroke();
    ctx.setLineDash([]);
  }

  // Strike axis labels (first, last, spot nearest)
  ctx.fillStyle = '#4a6a88';
  ctx.font = '10px Arial';
  ctx.textAlign = 'center';
  if (sorted.length > 1) {
    ctx.fillText(sorted[0].strike.toLocaleString(), pad.l, H - pad.b + 14);
    ctx.fillText(sorted[sorted.length - 1].strike.toLocaleString(), W - pad.r, H - pad.b + 14);
  }

  // Header
  ctx.fillStyle = '#d6e9ff';
  ctx.font = '12px Arial';
  ctx.textAlign = 'left';
  ctx.fillText('SPX GEX', 12, 16);
  ctx.fillStyle = '#2a4060';
  ctx.font = '10px Arial';
  ctx.fillText(`${rows.length} / ${allRows.length} strikes`, 12, 28);
}

function drawOverviewChart(){
  const canvas = document.getElementById('overview-canvas');
  if(!canvas) return;
  const container = document.getElementById('overview-scroll');
  const W = container ? container.clientWidth : 900;
  const H = container ? container.clientHeight : 500;
  if(W < 10 || H < 10){
    if(rawChain.length) renderOptionsLadder(rawChain);
    return;
  }
  if(canvas.width !== W) canvas.width = W;
  if(canvas.height !== H) canvas.height = H;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0,0,W,H);

  if(!rawChain.length){
    ctx.fillStyle='#2a4060'; ctx.font='13px Arial'; ctx.textAlign='center';
    ctx.fillText('Waiting for data…', W/2, H/2); return;
  }

  const compareSource = compareRawChain && compareRawChain.length ? compareRawChain : buildFallbackCompareRows(overviewCompareTicker);
  // Resolve freshest available SPX spot — prefer dxLink cache over the module-level var
  // in case the chart is redrawing between fetches and spotPrice hasn't been updated yet
  const _dxSpx = (typeof dxQuoteCache !== 'undefined') ? (dxQuoteCache['$SPX'] || dxQuoteCache['SPX'] || {}) : {};
  const _dxSpot = parseFloat(_dxSpx.last || _dxSpx.price || 0);
  const _resolvedSpot = (_dxSpot > 100 ? _dxSpot : 0) || spotPrice;
  if (_resolvedSpot > 0 && _resolvedSpot !== spotPrice) spotPrice = _resolvedSpot;
  const rightSpot = compareSpotPrice || (typeof GEX_SPOTS !== 'undefined' && GEX_SPOTS?.[overviewCompareTicker]) || spotPrice;
  const leftRows = ovBuildChartRows(rawChain);
  const rightRows = ovBuildChartRows(compareSource);
  ovEnsureViewport(leftRows, rightRows, spotPrice, rightSpot);
  let data = ovVisibleRows(leftRows, 'left');
  let compareData = ovVisibleRows(rightRows, 'right');
  if(!data.length) return;

  const n = data.length;
  const nR = compareData.length || n;

  // ── Split canvas: left = SPX GEX, right = SPY/compare GEX ──
  const showSpy = ovTab === 'spy';
  const DIVX = showSpy ? 0 : W;  // SPX: right=0px wide; SPY: left=0px wide
  const DIVW = 0;

  // Shared padding (top/bottom same for both halves)
  const PAD = {t:30, b:40};
  const cH = H - PAD.t - PAD.b;

  // Each panel has its own left/right internal padding
  const INNER = {l:6, r:8};
  const panelW_L = Math.max(0, DIVX);
  const panelW_R = Math.max(0, W - DIVX);
  const cW_L = Math.max(0, panelW_L - INNER.l - INNER.r);
  const cW_R = Math.max(0, panelW_R - INNER.l - INNER.r);

  // Skip rendering entirely if panel has no width
  const renderLeft  = cW_L > 10;
  const renderRight = cW_R > 10;

  // X coordinate helpers (each panel maps same strike index to its own x-space)
  const gap_L = renderLeft  ? cW_L / n  : 1;
  const gap_R = renderRight ? cW_R / nR : 1;
  const xL = i => INNER.l + (i + 0.5) * gap_L;
  const xR = i => DIVX + INNER.l + (i + 0.5) * gap_R;
  const barW_L = Math.max(2, gap_L * 0.8);
  const barW_R = Math.max(2, gap_R * 0.8);

  // ── Zero-crossing background shading (from full rawChain) ──
  const fullSorted = [...rawChain].sort((a,b)=>a.strike-b.strike);
  let zeroCrossStrike = null;
  for(let zi=0; zi<fullSorted.length-1; zi++){
    const a=fullSorted[zi].netGEX||0, b=fullSorted[zi+1].netGEX||0;
    if((a>=0&&b<0)||(a<=0&&b>0)){
      const frac=Math.abs(a)/(Math.abs(a)+Math.abs(b));
      zeroCrossStrike=fullSorted[zi].strike+frac*(fullSorted[zi+1].strike-fullSorted[zi].strike);
      break;
    }
  }
  const _crossFrac = zeroCrossStrike !== null ? (() => {
    const minS=data[0].strike, maxS=data[data.length-1].strike;
    return maxS>minS ? (zeroCrossStrike-minS)/(maxS-minS) : 0.5;
  })() : 0.5;
  const crossX_L = INNER.l + _crossFrac * cW_L;
  const crossX_R = DIVX + DIVW/2 + INNER.l + _crossFrac * cW_R;

  // Solid dark background
  if(renderLeft){
    ctx.fillStyle='#050810';
    ctx.fillRect(INNER.l, PAD.t, cW_L, cH);
  }
  if(renderRight){
    ctx.fillStyle='#050810';
    ctx.fillRect(DIVX+INNER.l, PAD.t, cW_R, cH);
  }

  // ── Y scales ──
  const isVolOnly = gexChartDataMode === 'vol-only';
  const isCallPutMode = ovChartMode === 'call-put';
  const getNetGEX = r => isVolOnly ? (r.netVolGEX||0) : (r.netGEX||0);
  const getCallGEX = r => isVolOnly ? (r.callVolGEX||0) : (r.callGEX||0);
  const getPutGEX  = r => isVolOnly ? (r.putVolGEX||0)  : (r.putGEX||0);

  // Auto-fit Y axis: always use the true max so the tallest bar is never
  // clipped off the top of the chart. A small 10% headroom keeps the peak
  // bar from touching the very edge of the canvas.
  const robustMax = (vals) => {
    const abs = vals.map(Math.abs).filter(v => v > 0).sort((a,b) => a - b);
    if(!abs.length) return 1;
    return abs[abs.length - 1]; // true max — no clipping
  };

  const netGEXvals = isCallPutMode
    ? data.flatMap(r=>[getCallGEX(r), -(Math.abs(getPutGEX(r)))])
    : data.map(r=>getNetGEX(r));
  const netMax = Math.max(robustMax(netGEXvals), 1);
  const maxG_L = (netMax * 1.10) / (ovYScale||1);

  const compareNetGEXVals = isCallPutMode
    ? compareData.flatMap(r=>[getCallGEX(r), -(Math.abs(getPutGEX(r)))])
    : compareData.map(r=>getNetGEX(r));
  const compareNetMax = Math.max(robustMax(compareNetGEXVals), 1);
  const maxG_R = (compareNetMax * 1.10) / (ovYScale||1);

  const yFor_L = v => PAD.t + cH/2 - (v/maxG_L)*(cH/2);
  const yFor_R = v => PAD.t + cH/2 - (v/maxG_R)*(cH/2);
  const yZero  = PAD.t + cH/2;
  const strokeSmoothLine = (points) => {
    if (!points.length) return;
    if (points.length === 1) {
      ctx.beginPath();
      ctx.arc(points[0].x, points[0].y, 1.5, 0, Math.PI * 2);
      ctx.fill();
      return;
    }
    ctx.beginPath();
    ctx.moveTo(points[0].x, points[0].y);
    for (let i = 0; i < points.length - 1; i++) {
      const curr = points[i];
      const next = points[i + 1];
      const midX = (curr.x + next.x) / 2;
      const midY = (curr.y + next.y) / 2;
      ctx.quadraticCurveTo(curr.x, curr.y, midX, midY);
    }
    const last = points[points.length - 1];
    ctx.lineTo(last.x, last.y);
    ctx.stroke();
  };
  const drawPeakStrikeLabel = (x, y, strike, color) => {
    if (!Number.isFinite(x) || !Number.isFinite(y) || !Number.isFinite(strike)) return;
    const label = Number(strike).toLocaleString();
    ctx.save();
    ctx.font = 'bold 10px Arial';
    const textWidth = ctx.measureText(label).width;
    const boxW = textWidth + 10;
    const boxH = 16;
    const boxX = Math.max(4, Math.min(W - boxW - 4, x - boxW / 2));
    const boxY = Math.max(4, y - 22);
    ctx.fillStyle = 'rgba(5,8,13,0.92)';
    ctx.fillRect(boxX, boxY, boxW, boxH);
    ctx.strokeStyle = color;
    ctx.lineWidth = 1;
    ctx.strokeRect(boxX, boxY, boxW, boxH);
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = color;
    ctx.fillText(label, boxX + boxW / 2, boxY + boxH / 2 + 0.5);
    ctx.restore();
  };
  const gexPeakValue = row => isCallPutMode
    ? Math.max(Math.abs(getCallGEX(row)), Math.abs(getPutGEX(row)))
    : Math.abs(getNetGEX(row));
  const gexPeakDrawValue = row => {
    if(!isCallPutMode) return getNetGEX(row);
    const callVal = Math.abs(getCallGEX(row));
    const putVal = Math.abs(getPutGEX(row));
    return callVal >= putVal ? callVal : -putVal;
  };
  const drawGexBar = (x, v, barW, yFor, posTop, posBottom, negTop, negBottom) => {
    if(!v) return;
    const yRaw = yFor(v);
    const y = v >= 0 ? Math.max(PAD.t, yRaw) : yZero;
    const yBot = v >= 0 ? yZero : Math.min(PAD.t + cH, yRaw);
    const h = Math.abs(yBot - y);
    if(h < 1) return;
    const grad = ctx.createLinearGradient(0, y, 0, yBot);
    if(v >= 0){
      grad.addColorStop(0, posTop);
      grad.addColorStop(1, posBottom);
    } else {
      grad.addColorStop(0, negTop);
      grad.addColorStop(1, negBottom);
    }
    ctx.fillStyle = grad;
    ctx.fillRect(x - barW / 2, y, barW, h);
  };

  // ── Grid + Y axis labels ──
  const fmtLbl = (g, mx) => {
    const a=Math.abs(g);
    if(a>=1e9) return (g>=0?'+':'-')+'$'+(a/1e9).toFixed(2)+'B';
    if(a>=1e6) return (g>=0?'+':'-')+'$'+(a/1e6).toFixed(2)+'M';
    return (g>=0?'+':'-')+'$'+(a/1e3).toFixed(2)+'K';
  };

  ctx.strokeStyle='rgba(30,48,80,0.4)'; ctx.lineWidth=0.5;

  // Left panel grid
  if(renderLeft){
    const step_L = getNiceStep(maxG_L/5);
    ctx.fillStyle='#2a4060'; ctx.font='9px Arial'; ctx.textAlign='right';
    for(let g=step_L; g<=maxG_L; g+=step_L){
      [yFor_L(g), yFor_L(-g)].forEach(y=>{
        ctx.beginPath(); ctx.moveTo(INNER.l,y); ctx.lineTo(INNER.l+cW_L,y); ctx.stroke();
      });
      ctx.fillText(fmtLbl(g,maxG_L), INNER.l+cW_L-2, yFor_L(g)+3);
      ctx.fillText(fmtLbl(-g,maxG_L), INNER.l+cW_L-2, yFor_L(-g)+3);
    }
  }

  // Right panel grid
  if(renderRight){
    const step_R = getNiceStep(maxG_R/5);
    ctx.textAlign='right';
    for(let g=step_R; g<=maxG_R; g+=step_R){
      [yFor_R(g), yFor_R(-g)].forEach(y=>{
        ctx.beginPath(); ctx.moveTo(DIVX+INNER.l,y); ctx.lineTo(DIVX+INNER.l+cW_R,y); ctx.stroke();
      });
      ctx.fillText(fmtLbl(g,maxG_R), DIVX+INNER.l+cW_R-2, yFor_R(g)+3);
      ctx.fillText(fmtLbl(-g,maxG_R), DIVX+INNER.l+cW_R-2, yFor_R(-g)+3);
    }
  }

  // Zero lines
  ctx.strokeStyle='rgba(90,122,153,0.4)'; ctx.lineWidth=1; ctx.setLineDash([3,3]);
  if(renderLeft)  { ctx.beginPath(); ctx.moveTo(INNER.l,yZero); ctx.lineTo(INNER.l+cW_L,yZero); ctx.stroke(); }
  if(renderRight) { ctx.beginPath(); ctx.moveTo(DIVX+INNER.l,yZero); ctx.lineTo(DIVX+INNER.l+cW_R,yZero); ctx.stroke(); }
  ctx.setLineDash([]);

  // ── Clip and draw bars ──
  // LEFT: Net GEX (OI+Vol) bars — blue positive, amber negative
  ctx.save();
  ctx.beginPath(); ctx.rect(INNER.l, PAD.t, cW_L, cH); ctx.clip();
  data.forEach((r,i)=>{
    const x=xL(i);
    if(isCallPutMode){
      drawGexBar(x, Math.abs(getCallGEX(r)), barW_L, yFor_L, 'rgba(41,182,246,0.9)', 'rgba(41,182,246,0.2)', 'rgba(255,179,0,0.2)', 'rgba(255,179,0,0.9)');
      drawGexBar(x, -Math.abs(getPutGEX(r)), barW_L, yFor_L, 'rgba(41,182,246,0.9)', 'rgba(41,182,246,0.2)', 'rgba(255,179,0,0.2)', 'rgba(255,179,0,0.9)');
    } else {
      drawGexBar(x, getNetGEX(r), barW_L, yFor_L, 'rgba(41,182,246,0.9)', 'rgba(41,182,246,0.2)', 'rgba(255,179,0,0.2)', 'rgba(255,179,0,0.9)');
    }
  });


  ctx.restore();

  // ── OI Overlay (Call/Put OI shaded areas with right-axis scale) ──
  if(showOIOverlay){
    ctx.save();
    ctx.beginPath(); ctx.rect(INNER.l, PAD.t, cW_L, cH); ctx.clip();
    
    // Get max OI for right-axis scaling
    const maxCallOI = Math.max(...data.map(r => r.callOI || 0), 1);
    const maxPutOI = Math.max(...data.map(r => r.putOI || 0), 1);
    const maxOI = Math.max(maxCallOI, maxPutOI);
    
    // Right-axis scale: top of chart = max OI, bottom = 0 (OI always positive)
    const yForOI = v => PAD.t + cH * (1 - v / maxOI);
    
    // Build smooth curve points for Call OI
    const callOIPoints = data.map((r, i) => ({ x: xL(i), y: yForOI(r.callOI || 0) }));
    
    // Draw Call OI (green shaded area with smooth curve)
    ctx.beginPath();
    ctx.moveTo(xL(0), PAD.t + cH); // Start at bottom left
    ctx.lineTo(callOIPoints[0].x, callOIPoints[0].y); // Go to first point
    // Smooth curve through points
    for (let i = 0; i < callOIPoints.length - 1; i++) {
      const curr = callOIPoints[i];
      const next = callOIPoints[i + 1];
      const midX = (curr.x + next.x) / 2;
      const midY = (curr.y + next.y) / 2;
      ctx.quadraticCurveTo(curr.x, curr.y, midX, midY);
    }
    const lastCall = callOIPoints[callOIPoints.length - 1];
    ctx.lineTo(lastCall.x, lastCall.y);
    ctx.lineTo(xL(data.length - 1), PAD.t + cH); // End at bottom right
    ctx.closePath();
    const callGrad = ctx.createLinearGradient(0, PAD.t, 0, PAD.t + cH);
    callGrad.addColorStop(0, 'rgba(144,238,144,0.35)'); // Light green top
    callGrad.addColorStop(1, 'rgba(144,238,144,0.08)'); // Fade to transparent
    ctx.fillStyle = callGrad;
    ctx.fill();
    
    // Build smooth curve points for Put OI
    const putOIPoints = data.map((r, i) => ({ x: xL(i), y: yForOI(r.putOI || 0) }));
    
    // Draw Put OI (red shaded area with smooth curve)
    ctx.beginPath();
    ctx.moveTo(xL(0), PAD.t + cH); // Start at bottom left
    ctx.lineTo(putOIPoints[0].x, putOIPoints[0].y); // Go to first point
    // Smooth curve through points
    for (let i = 0; i < putOIPoints.length - 1; i++) {
      const curr = putOIPoints[i];
      const next = putOIPoints[i + 1];
      const midX = (curr.x + next.x) / 2;
      const midY = (curr.y + next.y) / 2;
      ctx.quadraticCurveTo(curr.x, curr.y, midX, midY);
    }
    const lastPut = putOIPoints[putOIPoints.length - 1];
    ctx.lineTo(lastPut.x, lastPut.y);
    ctx.lineTo(xL(data.length - 1), PAD.t + cH); // End at bottom right
    ctx.closePath();
    const putGrad = ctx.createLinearGradient(0, PAD.t, 0, PAD.t + cH);
    putGrad.addColorStop(0, 'rgba(255,182,193,0.35)'); // Light red top
    putGrad.addColorStop(1, 'rgba(255,182,193,0.08)'); // Fade to transparent
    ctx.fillStyle = putGrad;
    ctx.fill();
    
    ctx.restore();
    
    // ── Right Y-axis for OI ──
    ctx.save();
    ctx.fillStyle='#5a7a99'; ctx.font='9px Arial'; ctx.textAlign='left';
    const fmtOI = v => {
      if(v >= 1e6) return (v/1e6).toFixed(1)+'M';
      if(v >= 1e3) return (v/1e3).toFixed(1)+'K';
      return v.toFixed(0);
    };
    const oiSteps = [0, maxOI * 0.25, maxOI * 0.5, maxOI * 0.75, maxOI];
    oiSteps.forEach(v => {
      const y = yForOI(v);
      ctx.fillText(fmtOI(v), INNER.l + cW_L + 4, y + 3);
    });
    // Axis label
    ctx.save();
    ctx.translate(INNER.l + cW_L + 28, PAD.t + cH / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillStyle = '#5a7a99';
    ctx.font = 'bold 10px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('OPEN INTEREST', 0, 0);
    ctx.restore();
    ctx.restore();
  }

  if(showOverviewDEX){
    const dexData_L = data.map(r => r.netDEX || 0);
    const maxDexL = Math.max(...dexData_L.map(v => Math.abs(v || 0)).filter(v => v > 0), 1);
    const yDexL = v => yZero - (v / maxDexL) * (cH / 2) * 0.6;
    ctx.save();
    ctx.beginPath(); ctx.rect(INNER.l, PAD.t, cW_L, cH); ctx.clip();
    ctx.strokeStyle='rgba(255,255,255,0.78)';
    ctx.lineWidth=2;
    strokeSmoothLine(dexData_L.map((v, i) => ({ x: xL(i), y: yDexL(v) })));
    ctx.restore();
  }

  if(showOverviewFlipCurve){
    const gexProfileData = data.map(r => r.netGEX || 0);
    const maxProfileL = Math.max(...gexProfileData.map(v => Math.abs(v || 0)).filter(v => v > 0), 1);
    const yProfileL = v => yZero - (v / maxProfileL) * (cH / 2) * 0.6;
    ctx.save();
    ctx.beginPath(); ctx.rect(INNER.l, PAD.t, cW_L, cH); ctx.clip();
    ctx.strokeStyle='#00e5ff';
    ctx.lineWidth=2;
    ctx.setLineDash([2,4]);
    strokeSmoothLine(gexProfileData.map((v, i) => ({ x: xL(i), y: yProfileL(v) })));
    ctx.setLineDash([]);
    ctx.restore();
  }

  const leftPeakRow = data.reduce((best, row) => {
    if(!best) return row;
    const bestAbsNet = Math.abs(getNetGEX(best));
    const rowAbsNet = Math.abs(getNetGEX(row));
    return rowAbsNet > bestAbsNet ? row : best;
  }, null);
  if (leftPeakRow) {
    const peakColor = (leftPeakRow.netGEX || 0) >= 0 ? '#29b6f6' : '#ffb300';
    drawPeakStrikeLabel(xL(data.indexOf(leftPeakRow)), yFor_L(gexPeakDrawValue(leftPeakRow)), leftPeakRow.strike, peakColor);
  }

  // RIGHT: Vol GEX bars — green positive, red negative
  if(renderRight){
  ctx.save();
  ctx.beginPath(); ctx.rect(DIVX+INNER.l, PAD.t, cW_R, cH); ctx.clip();
  compareData.forEach((r,i)=>{
    const x=xR(i);
    if(isCallPutMode){
      drawGexBar(x, Math.abs(getCallGEX(r)), barW_R, yFor_R, 'rgba(0,230,118,0.9)', 'rgba(0,230,118,0.2)', 'rgba(255,71,87,0.2)', 'rgba(255,71,87,0.9)');
      drawGexBar(x, -Math.abs(getPutGEX(r)), barW_R, yFor_R, 'rgba(0,230,118,0.9)', 'rgba(0,230,118,0.2)', 'rgba(255,71,87,0.2)', 'rgba(255,71,87,0.9)');
    } else {
      drawGexBar(x, getNetGEX(r), barW_R, yFor_R, 'rgba(0,230,118,0.9)', 'rgba(0,230,118,0.2)', 'rgba(255,71,87,0.2)', 'rgba(255,71,87,0.9)');
    }
  });
  ctx.restore();
  } // end renderRight bars

  // ── OI Overlay for RIGHT panel ──
  if(renderRight && showOIOverlay){
    ctx.save();
    ctx.beginPath(); ctx.rect(DIVX+INNER.l, PAD.t, cW_R, cH); ctx.clip();
    
    const maxCallOI_R = Math.max(...compareData.map(r => r.callOI || 0), 1);
    const maxPutOI_R = Math.max(...compareData.map(r => r.putOI || 0), 1);
    const maxOI_R = Math.max(maxCallOI_R, maxPutOI_R);
    
    const yForOI_R = v => PAD.t + cH * (1 - v / maxOI_R);
    
    // Build smooth curve points for Call OI
    const callOIPoints_R = compareData.map((r, i) => ({ x: xR(i), y: yForOI_R(r.callOI || 0) }));
    
    // Call OI (green with smooth curve)
    ctx.beginPath();
    ctx.moveTo(xR(0), PAD.t + cH);
    ctx.lineTo(callOIPoints_R[0].x, callOIPoints_R[0].y);
    for (let i = 0; i < callOIPoints_R.length - 1; i++) {
      const curr = callOIPoints_R[i];
      const next = callOIPoints_R[i + 1];
      const midX = (curr.x + next.x) / 2;
      const midY = (curr.y + next.y) / 2;
      ctx.quadraticCurveTo(curr.x, curr.y, midX, midY);
    }
    const lastCall_R = callOIPoints_R[callOIPoints_R.length - 1];
    ctx.lineTo(lastCall_R.x, lastCall_R.y);
    ctx.lineTo(xR(compareData.length - 1), PAD.t + cH);
    ctx.closePath();
    const callGrad_R = ctx.createLinearGradient(0, PAD.t, 0, PAD.t + cH);
    callGrad_R.addColorStop(0, 'rgba(144,238,144,0.35)');
    callGrad_R.addColorStop(1, 'rgba(144,238,144,0.08)');
    ctx.fillStyle = callGrad_R;
    ctx.fill();
    
    // Build smooth curve points for Put OI
    const putOIPoints_R = compareData.map((r, i) => ({ x: xR(i), y: yForOI_R(r.putOI || 0) }));
    
    // Put OI (red with smooth curve)
    ctx.beginPath();
    ctx.moveTo(xR(0), PAD.t + cH);
    ctx.lineTo(putOIPoints_R[0].x, putOIPoints_R[0].y);
    for (let i = 0; i < putOIPoints_R.length - 1; i++) {
      const curr = putOIPoints_R[i];
      const next = putOIPoints_R[i + 1];
      const midX = (curr.x + next.x) / 2;
      const midY = (curr.y + next.y) / 2;
      ctx.quadraticCurveTo(curr.x, curr.y, midX, midY);
    }
    const lastPut_R = putOIPoints_R[putOIPoints_R.length - 1];
    ctx.lineTo(lastPut_R.x, lastPut_R.y);
    ctx.lineTo(xR(compareData.length - 1), PAD.t + cH);
    ctx.closePath();
    const putGrad_R = ctx.createLinearGradient(0, PAD.t, 0, PAD.t + cH);
    putGrad_R.addColorStop(0, 'rgba(255,182,193,0.35)');
    putGrad_R.addColorStop(1, 'rgba(255,182,193,0.08)');
    ctx.fillStyle = putGrad_R;
    ctx.fill();
    
    ctx.restore();
    
    // ── Right Y-axis for OI (right panel) ──
    ctx.save();
    ctx.fillStyle='#5a7a99'; ctx.font='9px Arial'; ctx.textAlign='left';
    const fmtOI_R = v => {
      if(v >= 1e6) return (v/1e6).toFixed(1)+'M';
      if(v >= 1e3) return (v/1e3).toFixed(1)+'K';
      return v.toFixed(0);
    };
    const oiSteps_R = [0, maxOI_R * 0.25, maxOI_R * 0.5, maxOI_R * 0.75, maxOI_R];
    oiSteps_R.forEach(v => {
      const y = yForOI_R(v);
      ctx.fillText(fmtOI_R(v), DIVX + INNER.l + cW_R + 4, y + 3);
    });
    // Axis label
    ctx.save();
    ctx.translate(DIVX + INNER.l + cW_R + 28, PAD.t + cH / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.fillStyle = '#5a7a99';
    ctx.font = 'bold 10px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('OPEN INTEREST', 0, 0);
    ctx.restore();
    ctx.restore();
  }

  // ── DEX line for RIGHT panel (Vol GEX) ──
  if(renderRight && showOverviewDEX){
    const dexData_R = compareData.map(r => r.netDEX || 0);
    const maxDexR = Math.max(...dexData_R.map(v => Math.abs(v || 0)).filter(v => v > 0), 1);
    const yDexR = v => yZero - (v / maxDexR) * (cH / 2) * 0.6;
    ctx.save();
    ctx.beginPath(); ctx.rect(DIVX+INNER.l, PAD.t, cW_R, cH); ctx.clip();
    ctx.strokeStyle='rgba(255,255,255,0.78)';
    ctx.lineWidth=2;
    strokeSmoothLine(dexData_R.map((v, i) => ({ x: xR(i), y: yDexR(v) })));
    ctx.restore();
  }

  if(renderRight){
    const rightPeakRow = compareData.reduce((best, row) => {
      if(!best) return row;
      const bestAbsNet = Math.abs(best.netGEX || 0);
      const rowAbsNet = Math.abs(row.netGEX || 0);
      return rowAbsNet > bestAbsNet ? row : best;
    }, null);
    if (rightPeakRow) {
      const peakColor = (rightPeakRow.netGEX || 0) >= 0 ? '#00e676' : '#ff4757';
      drawPeakStrikeLabel(xR(compareData.indexOf(rightPeakRow)), yFor_R(gexPeakDrawValue(rightPeakRow)), rightPeakRow.strike, peakColor);
    }
  }

  // ── Level lines (both panels) ──
  const lv = window._levels || {};
  const lvDefs = [
    {key:'callWall',  val:lv.callWall, color:'rgba(0,230,118,0.9)',  label:'CWall', dash:[6,3]},
    {key:'putWall',   val:lv.putWall,  color:'rgba(255,71,87,0.9)',  label:'PWall', dash:[6,3]},
    {key:'estMoveUp', val:lv.estUp,    color:'rgba(0,229,255,0.6)',  label:'↑Est',  dash:[4,3]},
    {key:'estMoveDn', val:lv.estDn,    color:'rgba(0,229,255,0.6)',  label:'↓Est',  dash:[4,3]},
  ];
  lvDefs.forEach(l=>{
    if(!mainChartLevels[l.key] || !l.val) return;
    const fi=data.findIndex(r=>r.strike>=l.val); if(fi<0) return;
    const xLeft=xL(fi), xRight=xR(fi);
    ctx.save(); ctx.setLineDash(l.dash); ctx.strokeStyle=l.color; ctx.lineWidth=1.2;
    // Left panel
    ctx.beginPath(); ctx.rect(INNER.l,PAD.t,cW_L,cH); ctx.clip();
    ctx.beginPath(); ctx.moveTo(xLeft,PAD.t); ctx.lineTo(xLeft,PAD.t+cH); ctx.stroke();
    ctx.restore();
    ctx.save(); ctx.setLineDash(l.dash); ctx.strokeStyle=l.color; ctx.lineWidth=1.2;
    ctx.restore();
    // Label (left panel only to avoid clutter)
    ctx.setLineDash([]); ctx.fillStyle=l.color; ctx.font='bold 9px Arial'; ctx.textAlign='center';
    ctx.fillText(l.label, xLeft, PAD.t+10);
  });

  // ── Spot price line (both panels) — interpolated between strikes ──
  const interpX = (rows, spot, xFn) => {
    if (!rows.length) return null;
    const fi = rows.findIndex(r => r.strike >= spot);
    if (fi < 0) return xFn(rows.length - 1);           // spot above all visible
    if (fi === 0) return xFn(0);                        // spot below all visible
    const prev = rows[fi - 1], curr = rows[fi];
    const span = curr.strike - prev.strike;
    const frac = span > 0 ? (spot - prev.strike) / span : 0;
    return xFn(fi - 1) + frac * (xFn(fi) - xFn(fi - 1));
  };

  if(renderLeft && spotPrice > 0){
    const xLeft = interpX(data, spotPrice, xL);
    if(xLeft !== null){
      ctx.save();
      ctx.beginPath(); ctx.rect(INNER.l, PAD.t, cW_L, cH); ctx.clip();
      ctx.setLineDash([5,5]); ctx.strokeStyle='rgba(200,200,200,0.35)'; ctx.lineWidth=1;
      ctx.beginPath(); ctx.moveTo(xLeft,PAD.t); ctx.lineTo(xLeft,PAD.t+cH); ctx.stroke();
      ctx.setLineDash([]);
      ctx.restore();
    }
  }
  if(renderRight && rightSpot > 0){
    const xRight = interpX(compareData, rightSpot, xR);
    if(xRight !== null){
      ctx.save();
      ctx.beginPath(); ctx.rect(DIVX+INNER.l, PAD.t, cW_R, cH); ctx.clip();
      ctx.setLineDash([5,5]); ctx.strokeStyle='rgba(200,200,200,0.35)'; ctx.lineWidth=1;
      ctx.beginPath(); ctx.moveTo(xRight,PAD.t); ctx.lineTo(xRight,PAD.t+cH); ctx.stroke();
      ctx.setLineDash([]);
      ctx.restore();
    }
  }

  // ── X axis strike labels ──
  ctx.fillStyle='#5a7a99'; ctx.font='bold 9px Arial'; ctx.textAlign='center';
  const isFiftyStrike = strike => Number.isFinite(Number(strike)) && Math.abs(Number(strike) % 50) < 0.001;
  if(renderLeft) data.forEach((r,i)=>{
    if(!isFiftyStrike(r.strike)) return;
    ctx.fillStyle = '#5a7a99'; ctx.font = '9px Arial';
    ctx.fillText(r.strike.toLocaleString(), xL(i), PAD.t+cH+14);
  });
  if(renderRight) compareData.forEach((r,i)=>{
    if(!isFiftyStrike(r.strike)) return;
    ctx.fillStyle = '#5a7a99'; ctx.font = '9px Arial';
    ctx.fillText(r.strike.toLocaleString(), xR(i), PAD.t+cH+14);
  });

  // ── Panel labels ──
  ctx.font='bold 10px Arial'; ctx.textAlign='center';
  const modeLabel = isVolOnly ? 'Volume Only' : 'OI + Volume';
  if(renderLeft){
    ctx.fillStyle='rgba(41,182,246,0.7)';
    ctx.fillText(isCallPutMode ? `CALLS / PUTS GEX  (${modeLabel})` : `NET GEX  (${modeLabel})`, W/2, PAD.t-8);
  }
  if(renderRight){
    ctx.fillStyle='rgba(0,230,118,0.7)';
    ctx.fillText(isCallPutMode ? `${overviewCompareTicker} CALLS / PUTS GEX  (${modeLabel})` : `${overviewCompareTicker} NET GEX  (${modeLabel})`, DIVX + (W-DIVX)/2, PAD.t-8);
  }

  // ── Legend ──
  if(renderLeft){
    ctx.textAlign='left'; ctx.font='10px Arial';
    (isCallPutMode ? [['#29b6f6','Call GEX'],['#ffb300','Put GEX']] : [['#29b6f6','+ Net GEX'],['#ffb300','− Net GEX']]).forEach(([col,lbl],i)=>{
      ctx.fillStyle=col; ctx.fillRect(INNER.l+i*80,4,10,8);
      ctx.fillStyle='#5a7a99'; ctx.fillText(lbl, INNER.l+i*80+13,12);
    });
  }
  if(renderRight){
    ctx.textAlign='left';
    ctx.fillStyle='rgba(5,8,13,0.92)';
    ctx.fillRect(DIVX+INNER.l-2, 0, 210, 18);
    ctx.textAlign='left'; ctx.font='10px Arial';
    (isCallPutMode ? [[ '#00e676', `${overviewCompareTicker} Call GEX` ], [ '#ff4757', `${overviewCompareTicker} Put GEX` ]] : [[ '#00e676', `+ ${overviewCompareTicker} Net GEX` ], [ '#ff4757', `- ${overviewCompareTicker} Net GEX` ]]).forEach(([col,lbl],i)=>{
      ctx.fillStyle=col; ctx.fillRect(DIVX+INNER.l+i*102,4,10,8);
      ctx.fillStyle='#5a7a99'; ctx.fillText(lbl, DIVX+INNER.l+i*102+13,12);
    });
  }

  // Y-scale hint
  if((ovYScale||1)!==1){
    ctx.fillStyle='rgba(0,229,255,0.6)'; ctx.font='11px Arial'; ctx.textAlign='left';
    ctx.fillText('Y: '+(ovYScale||1).toFixed(1)+'×', INNER.l+2, PAD.t+10);
  }

  // Update level bar + render ladder
  updateOVLevelBar();
  renderOptionsLadder(data);
}




function updateOVLevelBar(){
  if(!rawChain.length) return;
  const fmtS=v=>v!=null?v.toLocaleString('en-US',{maximumFractionDigits:0}):'—';
  const fmtDist=v=>{
    if(v==null||!isFinite(v)||!spotPrice) return '';
    const diff=v-spotPrice;
    const sign=diff>0?'+':diff<0?'-':'±';
    const pct=(diff/spotPrice)*100;
    return ` (${sign}${Math.abs(diff).toLocaleString('en-US',{minimumFractionDigits:2,maximumFractionDigits:2})}, ${pct>=0?'+':''}${pct.toFixed(2)}%)`;
  };
  const fmtLevel=v=>v!=null?`${fmtS(v)}${fmtDist(v)}`:'—';
  const fmtG=v=>{const a=Math.abs(v);const s=v>=0?'+':'-';return s+'$'+(a>=1e9?(a/1e9).toFixed(2)+'B':a>=1e6?(a/1e6).toFixed(2)+'M':(a/1e3).toFixed(2)+'K');};

  // Recalculate gamma zero for current chain
  const sorted = [...rawChain].sort((a,b) => a.strike - b.strike);
  gammaZeroPoint = calculateGammaZero(sorted);

  // Use the correct GEX field based on current chart mode
  const getVal = r => ovChartMode==='volgex' ? (r.netVolGEX||0) : (r.netGEX||0);
  const totalGEX = rawChain.reduce((s,r)=>s+getVal(r),0);

  // Calculate total Delta, Theta, Vega exposures
  const totalDEX = rawChain.reduce((s,r)=>s+(r.netDEX||0),0);
  const totalCHEX = rawChain.reduce((s,r)=>s+(Math.abs(Number(r.callTheta||0)) - Math.abs(Number(r.putTheta||0)))*(Number(r.callOI||0)+Number(r.putOI||0)+Number(r.callVolume||0)+Number(r.putVolume||0))*(Number(spotPrice)||0)*100,0);
  const totalVEX = rawChain.reduce((s,r)=>s+(Math.abs(Number(r.callVega||0)) - Math.abs(Number(r.putVega||0)))*(Number(r.callOI||0)+Number(r.putOI||0)+Number(r.callVolume||0)+Number(r.putVolume||0))*(Number(spotPrice)||0)*100,0);

  // Recompute call/put walls and flip for current mode
  const chain = rawChain;
  let callWall, putWall, modeFlip;

  if(ovChartMode==='volgex'){
    // Vol GEX walls
    callWall = chain.reduce((a,b)=>(b.callVolGEX||0)>(a.callVolGEX||0)?b:a, chain[0])?.strike;
    putWall  = chain.reduce((a,b)=>Math.abs(b.putVolGEX||0)>Math.abs(a.putVolGEX||0)?b:a, chain[0])?.strike;
    // Vol GEX flip
    const sv=[...chain].sort((a,b)=>a.strike-b.strike);
    const avgAbs=sv.reduce((s,r)=>s+Math.abs(r.netVolGEX||0),0)/sv.length;
    const thr=avgAbs*0.15;
    for(let i=0;i<sv.length-1;i++){
      const c=sv[i],n=sv[i+1];
      if(Math.sign(c.netVolGEX)!==Math.sign(n.netVolGEX)&&Math.abs(c.netVolGEX)>=thr||Math.abs(n.netVolGEX)>=thr){
        modeFlip=Math.round((c.strike - c.netVolGEX*(n.strike-c.strike)/(n.netVolGEX-c.netVolGEX))*100)/100;
        break;
      }
    }
  } else if(ovChartMode==='callput'){
    callWall = chain.reduce((a,b)=>(b.callGEX||0)>(a.callGEX||0)?b:a, chain[0])?.strike;
    putWall  = chain.reduce((a,b)=>Math.abs(b.putGEX||0)>Math.abs(a.putGEX||0)?b:a, chain[0])?.strike;
    modeFlip = flipPoint;
  } else {
    callWall = (window._levels||{}).callWall;
    putWall  = (window._levels||{}).putWall;
    modeFlip = flipPoint;
  }

  window._levelMathContext={callWall,putWall,flip:modeFlip,totalGEX,totalDEX,totalCHEX,totalVEX,mode:ovChartMode};
  safeSet('ov-flip',    fmtLevel(modeFlip));
  safeSet('ov-callwall',fmtLevel(callWall));
  safeSet('ov-putwall', fmtLevel(putWall));
  safeSet('ov-netgex',  fmtG(totalGEX));
  const straddle=calcStraddle();
  if(straddle) safeSet('ov-iv', (straddle.iv*100).toFixed(1)+'%');
}

const GEX_MATH_INFO={
  callWall:{
    title:'Call Wall',
    body:[
      'For each strike, call GEX = call gamma x (call open interest + call volume) x 100 x SPX spot.',
      'The call wall is the strike with the largest positive call GEX.',
      'On ES views, the SPX level is shifted by the ES/SPX previous-close basis.'
    ]
  },
  putWall:{
    title:'Put Wall',
    body:[
      'For each strike, put GEX = put gamma x (put open interest + put volume) x 100 x SPX spot.',
      'Puts are treated as negative exposure in net GEX. The put wall is the strike with the largest absolute put GEX.',
      'On ES views, the SPX level is shifted by the ES/SPX previous-close basis.'
    ]
  },
  flip:{
    title:'GEX Flip',
    body:[
      'Net GEX per strike = call GEX - put GEX.',
      'The flip is the nearest meaningful strike area where net GEX changes sign from negative to positive or positive to negative.',
      'If no clean sign crossing exists, the fallback is the significant strike whose net GEX is closest to zero.'
    ]
  }
};

function ensureGexMathTooltip(){
  let tt=document.getElementById('gex-math-tooltip');
  if(tt) return tt;
  tt=document.createElement('div');
  tt.id='gex-math-tooltip';
  tt.style.cssText='position:fixed;display:none;z-index:10000;width:310px;max-width:calc(100vw - 24px);background:#07101a;border:1px solid #25415f;border-radius:6px;box-shadow:0 16px 40px rgba(0,0,0,.42);padding:10px 12px;color:#d7e4f5;font-family:Arial;font-size:11px;line-height:1.45;pointer-events:none';
  document.body.appendChild(tt);
  return tt;
}

function formatGexInfoNumber(v,digits=0){
  const n=Number(v);
  return isFinite(n)?n.toLocaleString('en-US',{minimumFractionDigits:digits,maximumFractionDigits:digits}):'--';
}

function buildGexMathHTML(kind){
  const info=GEX_MATH_INFO[kind]||GEX_MATH_INFO.flip;
  const ctx=window._levelMathContext||{};
  const lv=window._levels||{};
  const esLv=(typeof getESLevelsFromSPX==='function')?getESLevelsFromSPX(lv):{};
  const key=kind==='flip'?'flip':kind;
  const spx=ctx[key]??lv[key];
  const es=esLv[key];
  const basis=getESCloseBasis?.();
  return `<div style="font-weight:700;color:#f4fbff;font-size:12px;margin-bottom:6px">${info.title}</div>
    <div style="display:grid;grid-template-columns:auto 1fr;gap:3px 8px;margin-bottom:8px;color:#90a9c4">
      <div>SPX</div><div style="color:#fff;font-weight:700">${formatGexInfoNumber(spx,0)}</div>
      <div>ES</div><div style="color:#8dc4ff;font-weight:700">${formatGexInfoNumber(es,0)}</div>
      <div>Basis</div><div>${basis==null?'--':(basis>=0?'+':'')+formatGexInfoNumber(basis,2)}</div>
    </div>
    ${info.body.map(line=>`<div style="margin-top:5px;color:#a9bdd2">${line}</div>`).join('')}`;
}

function positionGexMathTooltip(tt,x,y){
  const pad=12;
  tt.style.display='block';
  const rect=tt.getBoundingClientRect();
  let left=x+14, top=y+14;
  if(left+rect.width>window.innerWidth-pad) left=x-rect.width-14;
  if(top+rect.height>window.innerHeight-pad) top=y-rect.height-14;
  tt.style.left=Math.max(pad,left)+'px';
  tt.style.top=Math.max(pad,top)+'px';
}

function initGexMathInfoTooltips(){
  if(document.body?.dataset.gexMathInfoBound==='1') return;
  if(!document.body) return;
  document.body.dataset.gexMathInfoBound='1';
  document.addEventListener('mouseover',e=>{
    const target=e.target.closest?.('[data-gex-info]');
    if(!target) return;
    const tt=ensureGexMathTooltip();
    tt.innerHTML=buildGexMathHTML(target.dataset.gexInfo);
    positionGexMathTooltip(tt,e.clientX,e.clientY);
  });
  document.addEventListener('mousemove',e=>{
    const target=e.target.closest?.('[data-gex-info]');
    const tt=document.getElementById('gex-math-tooltip');
    if(!target||!tt||tt.style.display==='none') return;
    positionGexMathTooltip(tt,e.clientX,e.clientY);
  });
  document.addEventListener('mouseout',e=>{
    if(!e.target.closest?.('[data-gex-info]')) return;
    const to=e.relatedTarget;
    if(to&&to.closest?.('[data-gex-info]')) return;
    const tt=document.getElementById('gex-math-tooltip');
    if(tt) tt.style.display='none';
  });
}

document.addEventListener('DOMContentLoaded',initGexMathInfoTooltips);
setTimeout(initGexMathInfoTooltips,0);

function renderOptionsLadder(data){
  const body=document.getElementById('ladder-body');
  if(!body) return;
  
  // Use same logic as grid: 20 above + ATM + 20 below
  if(!rawChain || !rawChain.length) { body.innerHTML = ''; return; }
  
  const spot = spotPrice || 0;
  const sorted = [...rawChain].sort((a, b) => b.strike - a.strike);
  
  // 20 strikes each side of ATM
  const atmIdx = sorted.reduce((bi, r, i) => Math.abs(r.strike - spot) < Math.abs(sorted[bi].strike - spot) ? i : bi, 0);
  const lo = Math.max(0, atmIdx - 20);
  const strikes = sorted.slice(lo, lo + 41);

  // Build top-5 rankings for net GEX above and below ATM
  const atm = strikes.reduce((p,cur)=>Math.abs(cur.strike-spot)<Math.abs(p.strike-spot)?cur:p, strikes[0]);
  const aboveATM = strikes.filter(r=>r.strike > atm.strike);
  const belowATM = strikes.filter(r=>r.strike <= atm.strike);

  // Rank by absolute net GEX - top 5 each side
  const rankSide = (rows) => {
    const ranked = [...rows].sort((a,b)=>Math.abs(b.netGEX||0)-Math.abs(a.netGEX||0));
    const map = new Map();
    ranked.slice(0,5).forEach((r,i)=>map.set(r.strike, i+1));
    return map;
  };
  const rankAbove = rankSide(aboveATM);
  const rankBelow = rankSide(belowATM);

  const maxNetGEX  = Math.max(...strikes.map(r=>Math.abs(r.netGEX||0)),1);
  const maxCallGEX = Math.max(...strikes.map(r=>Math.abs(r.callGEX||0)),1);
  const maxPutGEX  = Math.max(...strikes.map(r=>Math.abs(r.putGEX||0)),1);
  const maxDEX     = Math.max(...strikes.map(r=>{const cPos=(r.callOI||0)+(r.callVolume||0);const pPos=(r.putOI||0)+(r.putVolume||0);return Math.abs(((r.callDelta||0)*cPos-Math.abs(r.putDelta||0)*pPos)*(spot||1)*100);}),1);

  // Top strike per column for gold highlight
  const topNetStrike = strikes.reduce((a,b)=>Math.abs(b.netGEX||0)>Math.abs(a.netGEX||0)?b:a, strikes[0])?.strike;
  const topVolStrike = strikes.reduce((a,b)=>Math.abs(b.netVolGEX||0)>Math.abs(a.netVolGEX||0)?b:a, strikes[0])?.strike;
  const topDexStrike = strikes.reduce((a,b)=>Math.abs(b.netDEX||0)>Math.abs(a.netDEX||0)?b:a, strikes[0])?.strike;

  const isFlip = r=>flipPoint&&Math.abs(r.strike-flipPoint)<3;

  // Always display in K units so values are comparable at a glance
  const fmtG = v=>{
    const a=Math.abs(v);
    const s=v<0?'-':'+';
    if(a>=1e9) return s+'$'+(a/1e9).toFixed(2)+'B';
    if(a>=1e6) return s+'$'+(a/1e6).toFixed(2)+'M';
    return s+'$'+(a/1e3).toFixed(2)+'K';
  };

  const heat=(v,max,r,g,b)=>{
    const t=Math.min(Math.abs(v)/max*(ladderIntensity||1),1);
    return `rgba(${r},${g},${b},${(t*0.55).toFixed(2)})`;
  };

  // Rank badge colors
  const rankColors = {1:'#ffd700',2:'#c0c0c0',3:'#cd7f32',4:'#4a7a99',5:'#3a5570'};
  const rankBg     = {1:'rgba(255,215,0,0.15)',2:'rgba(192,192,192,0.1)',3:'rgba(205,127,50,0.1)',4:'rgba(74,122,153,0.08)',5:'rgba(58,85,112,0.06)'};

  // GEX change columns
  const snap = getGexChangeSnapshot();
  const ageStr = getSnapshotAge();
  const ageEl = document.getElementById('gex-snapshot-age');
  if(ageEl) ageEl.textContent = ageStr ? `Δ base: ${ageStr}` : 'Δ waiting…';
  const maxChg = snap ? Math.max(...strikes.map(r=>Math.abs(Math.round(((r.netVolGEX||0)-(snap.get(r.strike)||0))/100)*100)),1) : 1;

  // Get 1-min snapshot: find snapshot closest to 1 minute ago
  const get1MinSnap = ()=>{
    if(!gex1MinSnapshots.length) return null;
    const target = Date.now() - 60000;
    let best = null;
    for(const s of gex1MinSnapshots){
      if(s.ts <= target + 30000){
        if(!best || s.ts > best.ts) best = s;
      }
    }
    return best ? best.data : null;
  };
  const snap1min = get1MinSnap();
  const maxChg1m = snap1min ? Math.max(...sorted.map(r=>Math.abs((r.netVolGEX||0)-(snap1min.get(r.strike)||0))),1) : 1;

  // ── 5-min snapshot: closest snapshot to 5 minutes ago ──
  const get5MinSnap = ()=>{
    if(!gexSnapshots.length) return null;
    const target = Date.now() - 5*60*1000;
    let best = null;
    for(const s of gexSnapshots){
      if(s.ts <= target + 60000){ // within 1 min of target
        if(!best || s.ts > best.ts) best = s;
      }
    }
    return best ? best.data : null;
  };
  const snap5min = get5MinSnap();
  const maxChg5m = snap5min ? Math.max(...sorted.map(r=>Math.abs((r.netGEX||0)-(snap5min.get(r.strike)||0))),1) : 1;

  // ── Per-update (refresh) delta ──
  const maxChgUpd = gexPrevSnapshot ? Math.max(...sorted.map(r=>Math.abs(Math.round(((r.netGEX||0)-(gexPrevSnapshot.get(r.strike)||0))/100)*100)),1) : 1;

  let html='';
  strikes.forEach(row=>{
    const net   = row.netGEX||0;

    const isATM = row.strike===atm?.strike;

    // Δ UPDATE: net GEX change since last refresh snapshot (always vs previous refresh)
    const prevUpd = gexPrevSnapshot ? (gexPrevSnapshot.get(row.strike)||0) : null;
    const chgUpd  = prevUpd !== null ? net - prevUpd : null;
    const chgRndU = chgUpd !== null ? Math.round(chgUpd/100)*100 : null;
    const chgBgU  = chgRndU ? (chgRndU>0 ? heat(chgRndU,maxChgUpd,41,182,246) : heat(chgRndU,maxChgUpd,255,100,60)) : 'transparent';
    const chgColU = !chgRndU ? '#2a4060' : chgRndU>0 ? '#7ad4ff' : '#ff9060';
    const chgTxtU = chgUpd===null ? '—' : chgRndU===0 ? '' : (chgRndU>0?'+':'')+fmtG(chgRndU);

    // Δ 1MIN: net GEX change vs 1 minute ago
    const prev1m  = snap1min ? (snap1min.get(row.strike)||0) : null;
    const chg1m   = prev1m !== null ? net - prev1m : null;
    const chgRnd1m = chg1m !== null ? Math.round(chg1m/100)*100 : null;
    const chgBg1m  = chgRnd1m ? (chgRnd1m>0 ? heat(chgRnd1m,maxChg1m,100,180,255) : heat(chgRnd1m,maxChg1m,255,100,60)) : 'transparent';
    const chgCol1m = !chgRnd1m ? '#2a4060' : chgRnd1m>0 ? '#a0d4ff' : '#ff9060';
    const chgTxt1m = chg1m===null ? '—' : chgRnd1m===0 ? '' : (chgRnd1m>0?'+':'')+fmtG(chgRnd1m);

    // Δ 5MIN: net GEX change vs 5 minutes ago
    const prev5m  = snap5min ? (snap5min.get(row.strike)||0) : null;
    const chg5m   = prev5m !== null ? net - prev5m : null;
    const chgRnd5m = chg5m !== null ? Math.round(chg5m/100)*100 : null;
    const chgBg5m  = chgRnd5m ? (chgRnd5m>0 ? heat(chgRnd5m,maxChg5m,255,150,60) : heat(chgRnd5m,maxChg5m,255,80,60)) : 'transparent';
    const chgCol5m = !chgRnd5m ? '#2a4060' : chgRnd5m>0 ? '#ffb060' : '#ff6060';
    const chgTxt5m = chg5m===null ? '—' : chgRnd5m===0 ? '' : (chgRnd5m>0?'+':'')+fmtG(chgRnd5m);

    // Get rank for this strike
    const rank = rankAbove.get(row.strike) || rankBelow.get(row.strike);

    const netGex  = row.netGEX||0;
    const cPos    = (row.callOI||0) + (row.callVolume||0);
    const pPos    = (row.putOI||0) + (row.putVolume||0);
    const volNetDex = ((row.callDelta||0)*cPos - Math.abs(row.putDelta||0)*pPos) * (spotPrice||1) * 100;

    const netBg     = netGex>=0 ? heat(netGex,maxNetGEX,41,182,246) : heat(netGex,maxNetGEX,255,100,60);
    const dexBg     = volNetDex>=0 ? heat(volNetDex,maxDEX,41,182,246) : heat(volNetDex,maxDEX,255,100,60);

    const isTopNet  = row.strike === topNetStrike;
    const isTopDex  = row.strike === topDexStrike;

    const netColor  = isTopNet ? '#ffd700' : '#ffffff';
    const dexColor  = isTopDex ? '#ffd700' : volNetDex>=0 ? '#7ad4ff' : '#ff9060';
    const strikeBg  = isATM ? '#0a2030' : 'transparent';
    const strikeCol = isATM ? '#00e5ff' : '#ffffff';
    const atmOutline = isATM ? 'box-shadow:inset 0 0 0 1.5px rgba(255,255,255,0.85);' : '';
    const rowBorder  = isATM ? 'border-top:1px solid rgba(255,255,255,0.5);border-bottom:1px solid rgba(255,255,255,0.5);' : '';

    const rankBadge = rank
      ? `<span style="font-size:9px;font-weight:800;color:${rankColors[rank]};background:${rankBg[rank]};padding:0 4px;border-radius:2px;border:1px solid ${rankColors[rank]}44;margin-left:3px">#${rank}</span>`
      : '';

    html+=`<div data-strike="${row.strike}" style="display:grid;grid-template-columns:80px 160px 160px;border-bottom:1px solid #080d14;${rowBorder}${atmOutline}">
      <div style="padding:4px 3px;font-size:11px;font-weight:700;color:${strikeCol};text-align:center;background:${strikeBg};border-right:1px solid #0d1520;display:flex;align-items:center;justify-content:center;gap:2px">
        ${row.strike.toLocaleString()}${isATM?'<span style="font-size:7px;color:#00e5ff;background:#062030;padding:1px 3px;border-radius:1px;margin-left:2px">ATM</span>':''}
      </div>
      <div style="padding:4px 5px;font-size:11px;font-weight:${isTopNet?'800':'700'};color:${netColor};text-align:right;background:${netBg};border-right:1px solid #0d1520;display:flex;align-items:center;justify-content:flex-end;gap:2px">${netGex?fmtG(netGex):'—'}${rankBadge}</div>
      <div style="padding:4px 5px;font-size:11px;font-weight:${isTopDex?'800':'700'};color:${dexColor};text-align:right;background:${dexBg}">${volNetDex?fmtG(volNetDex):'—'}</div>
    </div>`;
  });
  body.innerHTML=html;

  centerOptionsLadderATM();
}

function centerOptionsLadderATM(){
  const body=document.getElementById('ladder-body');
  if(!body||!spotPrice||!body.children.length) return;
  requestAnimationFrame(()=>{
    const rows=[...body.children];
    let closest=null,closestDiff=Infinity;
    rows.forEach(row=>{
      const strike=parseFloat(row.dataset.strike||'');
      if(!isFinite(strike)) return;
      const diff=Math.abs(strike-spotPrice);
      if(diff<closestDiff){closestDiff=diff;closest=row;}
    });
    if(!closest) return;
    body.scrollTop=Math.max(0, closest.offsetTop - (body.clientHeight/2) + (closest.offsetHeight/2));
  });
}


// Pan/zoom for overview
function initOvEvents(){
  const scroll = document.getElementById('overview-scroll');
  const canvas = document.getElementById('overview-canvas');
  if(!scroll || !canvas) return;
  if(scroll.dataset.ovNavReady === '1') return;
  scroll.dataset.ovNavReady = 'binding';
  scroll.style.overflow = 'hidden';
  scroll.style.touchAction = 'none';
  scroll.style.userSelect = 'none';
  canvas.style.touchAction = 'none';
  canvas.style.userSelect = 'none';
  canvas.style.cursor = 'grab';

  let tooltip = document.getElementById('ov-tooltip');
  if(!tooltip){
    tooltip = document.createElement('div');
    tooltip.id = 'ov-tooltip';
    tooltip.style.cssText = 'position:absolute;background:#0d1520;border:1px solid #2a4060;border-radius:3px;padding:8px 12px;font-size:11px;color:#e8edf5;pointer-events:none;display:none;z-index:50;min-width:160px;font-family:Arial';
    scroll.appendChild(tooltip);
  }

  const panelForEvent = e => {
    const rect = scroll.getBoundingClientRect();
    const x = e.clientX - rect.left;
    // When showing SPX only, everything is left panel; when SPY only, everything is right panel
    const side = ovTab === 'spy' ? 'right' : ovTab === 'chart' ? 'left' : (x >= rect.width / 2 ? 'right' : 'left');
    return { rect, x, y: e.clientY - rect.top, side };
  };

  const rowsForSide = side => {
    const compareSource = compareRawChain.length ? compareRawChain : buildFallbackCompareRows(overviewCompareTicker);
    const rightSpot = compareSpotPrice || GEX_SPOTS?.[overviewCompareTicker] || spotPrice;
    const leftRows = ovBuildChartRows(rawChain);
    const rightRows = ovBuildChartRows(compareSource);
    ovEnsureViewport(leftRows, rightRows, spotPrice, rightSpot);
    return {
      rows: side === 'right' ? rightRows : leftRows,
      spot: side === 'right' ? rightSpot : spotPrice,
      startKey: side === 'right' ? 'rightStart' : 'leftStart',
      color: side === 'right' ? '#00e676' : '#29b6f6',
      label: side === 'right' ? overviewCompareTicker + ' Net GEX' : 'Net GEX'
    };
  };

  const applyCount = (nextCount, anchor = null) => {
    const compareSource = compareRawChain.length ? compareRawChain : buildFallbackCompareRows(overviewCompareTicker);
    const leftRows = ovBuildChartRows(rawChain);
    const rightRows = ovBuildChartRows(compareSource);
    const maxLen = Math.max(leftRows.length, rightRows.length, MIN_GEX_STRIKE_COUNT);
    const oldCount = ovViewport.count || DEFAULT_GEX_STRIKE_COUNT;
    const count = ovClamp(Math.round(nextCount), MIN_GEX_STRIKE_COUNT, Math.max(MIN_GEX_STRIKE_COUNT, maxLen));
    if(count === oldCount) return;
    const nextStart = (side, rows, fallbackStart) => {
      const rowCount = rows.length;
      if(!rowCount) return 0;
      const visibleOld = Math.min(oldCount, rowCount);
      const visibleNew = Math.min(count, rowCount);
      const oldStart = ovClamp(fallbackStart || 0, 0, Math.max(0, rowCount - visibleOld));
      let dataIndex;
      let fraction;
      if(anchor && anchor.side === side){
        fraction = ovClamp(anchor.fraction, 0, 1);
        dataIndex = oldStart + fraction * visibleOld;
      } else {
        fraction = 0.5;
        dataIndex = oldStart + visibleOld / 2;
      }
      return ovClamp(Math.round(dataIndex - fraction * visibleNew), 0, Math.max(0, rowCount - visibleNew));
    };
    ovViewport.leftStart = nextStart('left', leftRows, ovViewport.leftStart);
    ovViewport.rightStart = nextStart('right', rightRows, ovViewport.rightStart);
    ovViewport.count = count;
    setConfiguredStrikeCount(count);
    markOverviewUserInteraction();
    drawOverviewChart();
  };

  const onWheel = e => {
    if(!rawChain.length) return;
    window.__gexOverviewNavEvent = {type:'wheel', at:Date.now(), deltaY:e.deltaY};
    tooltip.style.display = 'none';
    e.preventDefault();
    e.stopPropagation();
    const p = panelForEvent(e);
    const isSinglePanel = ovTab === 'chart' || ovTab === 'spy';
    const panelLeft = (!isSinglePanel && p.side === 'right') ? p.rect.width / 2 : 0;
    const panelW = Math.max(1, isSinglePanel ? p.rect.width : p.rect.width / 2);
    const anchor = {
      side: p.side,
      fraction: ovClamp((p.x - panelLeft) / panelW, 0, 1)
    };
    const factor = e.deltaY > 0 ? 1.16 : 0.86;
    applyCount((ovViewport.count || DEFAULT_GEX_STRIKE_COUNT) * factor, anchor);
  };
  scroll.addEventListener('wheel', onWheel, { passive:false });

  let drag = null;
  const beginDrag = e => {
    window.__gexOverviewNavEvent = {type:'pointerdown', at:Date.now(), x:e.clientX, y:e.clientY};
    if(e.button !== undefined && e.button !== 0) return;
    const p = panelForEvent(e);
    tooltip.style.display = 'none';
    const info = rowsForSide(p.side);
    if(!info.rows.length) return;
    const isSP = ovTab === 'chart' || ovTab === 'spy';
    drag = { side: p.side, startX: e.clientX, startLeft: ovViewport.leftStart || 0, startRight: ovViewport.rightStart || 0, pxPerStrike: Math.max(2, (isSP ? p.rect.width : p.rect.width / 2) / Math.max(1, ovViewport.count || DEFAULT_GEX_STRIKE_COUNT)), pointerId: e.pointerId };
    markOverviewUserInteraction();
    canvas.style.cursor = 'grabbing';
    tooltip.style.display = 'none';
    try { scroll.setPointerCapture(e.pointerId); } catch(err) {}
    e.preventDefault();
  };
  scroll.addEventListener('pointerdown', beginDrag);

  const continueDrag = e => {
    if(drag){
      const dx = e.clientX - drag.startX;
      const shift = Math.round(-dx / drag.pxPerStrike);
      const side = rowsForSide(drag.side);
      const maxStart = Math.max(0, side.rows.length - Math.min(ovViewport.count || DEFAULT_GEX_STRIKE_COUNT, side.rows.length));
      if(drag.side === 'right') ovViewport.rightStart = ovClamp(drag.startRight + shift, 0, maxStart);
      else ovViewport.leftStart = ovClamp(drag.startLeft + shift, 0, maxStart);
      window.__gexOverviewNav = ovViewport;
      window.__gexOverviewNavEvent = {type:'drag', at:Date.now(), side:drag.side, shift, viewport:{...ovViewport}};
      markOverviewUserInteraction();
      drawOverviewChart();
      e.preventDefault();
      return;
    }

    const p = panelForEvent(e);
    const plotTop = 30;
    const plotBottom = p.rect.height - 40;
    if(p.x < 0 || p.x > p.rect.width || p.y < plotTop || p.y > plotBottom){
      tooltip.style.display = 'none';
      canvas.style.cursor = 'default';
      return;
    }
    const info = rowsForSide(p.side);
    const visible = ovVisibleRows(info.rows, p.side);
    if(!visible.length){ tooltip.style.display = 'none'; return; }
    const isSinglePanel = ovTab === 'chart' || ovTab === 'spy';
    const panelLeft = (!isSinglePanel && p.side === 'right') ? p.rect.width / 2 : 0;
    const panelW = isSinglePanel ? p.rect.width : p.rect.width / 2;
    // Expand hover zone - find closest strike within reasonable distance
    const strikeW = Math.max(1, panelW / visible.length);
    const normalIdx = (p.x - panelLeft) / strikeW;
    const idx = ovClamp(Math.round(normalIdx), 0, visible.length - 1);
    const r = visible[idx];
    if(!r){ tooltip.style.display = 'none'; return; }
    const fmtG = v => { const a=Math.abs(v||0), sign=(v||0)>=0?'+':'-'; if(a>=1e9)return sign+'$'+(a/1e9).toFixed(2)+'B'; if(a>=1e6)return sign+'$'+(a/1e6).toFixed(2)+'M'; if(a>=1e3)return sign+'$'+(a/1e3).toFixed(2)+'K'; return sign+'$'+a.toFixed(2); };
    const fmtPos = v => v>=1000?(v/1000).toFixed(1)+'K':(v||0).toFixed(0);
    const diff = r.strike - (info.spot || 0);
    const fromSpotPct = (info.spot || 0) ? (diff / (info.spot || 1) * 100) : 0;
    const fromSpotStr = fromSpotPct >= 0 ? '+' : '';
    tooltip.innerHTML = '<div style="font-weight:700;color:#f4fbff;font-size:12px;margin-bottom:6px">NET GEX</div>'+
      '<div style="display:grid;grid-template-columns:auto 1fr;gap:3px 8px;margin-bottom:10px;color:#90a9c4;font-size:10px">'+
        '<div style="color:#a9bdd2">(strike)</div><div style="color:#fff;font-weight:700">'+r.strike.toLocaleString()+'</div>'+
        '<div style="color:#a9bdd2">from spot</div><div style="color:#fff;font-weight:700">'+fromSpotStr+fromSpotPct.toFixed(2)+'%</div>'+
        '<div style="color:#a9bdd2">contract price (otm)</div><div style="color:#fff;font-weight:700">—</div>'+
      '</div>'+
      '<div style="border-top:1px solid #1a3a50;padding-top:8px;margin-top:8px">'+
        '<div style="display:grid;grid-template-columns:auto 1fr;gap:3px 8px;color:#a9bdd2;font-size:10px;margin-bottom:8px">'+
          '<div>net gex</div><div style="color:#'+(((r.netGEX||0)>=0?'90ffc8':'ffaaaa'))+';font-weight:700">'+fmtG(r.netGEX)+'</div>'+
          '<div>call gex</div><div style="color:#90ffc8;font-weight:700">'+fmtG(r.callGEX)+'</div>'+
          '<div>put gex</div><div style="color:#ffaaaa;font-weight:700">'+fmtG(r.putGEX)+'</div>'+
        '</div>'+
        '<div style="border-top:1px solid #1a3a50;padding-top:8px;display:grid;grid-template-columns:auto 1fr;gap:3px 8px;color:#a9bdd2;font-size:10px;margin-bottom:8px">'+
          '<div>volume (call)</div><div style="color:#fff;font-weight:700">'+fmtPos(r.callVolume||0)+'</div>'+
          '<div>volume (put)</div><div style="color:#fff;font-weight:700">'+fmtPos(r.putVolume||0)+'</div>'+
        '</div>'+
        '<div style="border-top:1px solid #1a3a50;padding-top:8px;display:grid;grid-template-columns:auto 1fr;gap:3px 8px;color:#a9bdd2;font-size:10px">'+
          '<div>open interest (call)</div><div style="color:#fff;font-weight:700">'+fmtPos(r.callOI||0)+'</div>'+
          '<div>open interest (put)</div><div style="color:#fff;font-weight:700">'+fmtPos(r.putOI||0)+'</div>'+
        '</div>'+
      '</div>';
    let left = p.x + 14;
    if(left + 180 > p.rect.width - 10) left = p.x - 190;
    tooltip.style.left = left + 'px';
    tooltip.style.top = Math.max(30, p.y - 35) + 'px';
    tooltip.style.display = 'block';
    canvas.style.cursor = 'grab';
  };
  scroll.addEventListener('pointermove', continueDrag);
  scroll.addEventListener('mousemove', continueDrag);
  document.addEventListener('mousemove', continueDrag);

  const endDrag = () => {
    if(!drag) return;
    try { scroll.releasePointerCapture?.(drag.pointerId); } catch(err) {}
    drag = null;
    markOverviewUserInteraction(2500);
    tooltip.style.display = 'none';
    canvas.style.cursor = 'grab';
  };
  scroll.addEventListener('pointerup', endDrag);
  scroll.addEventListener('pointercancel', endDrag);
  scroll.addEventListener('mouseup', endDrag);
  document.addEventListener('mouseup', endDrag);
  scroll.addEventListener('mouseleave', () => { tooltip.style.display = 'none'; endDrag(); });
  canvas.addEventListener('mouseleave', () => { tooltip.style.display = 'none'; });
  scroll.addEventListener('dblclick', e => {
    e.preventDefault();
    ovResetViewport();
    ovYScale = 1;
    drawOverviewChart();
  });
  scroll.dataset.ovNavReady = '1';
}

