async function getBuySellHistoryRows() {
  if (typeof DB === 'undefined' || !DB?.db || !DB.db.objectStoreNames?.contains('buySellScores')) return [];
  const today = new Date().toISOString().split('T')[0];
  try {
    if (typeof DB.queryBuySellScores_Today === 'function') return await DB.queryBuySellScores_Today();
  } catch (err) {
    console.warn('Buy/Sell IndexedDB query failed, falling back:', err);
  }
  if (typeof DB._getAllRecords === 'function') {
    return (await DB._getAllRecords('buySellScores')).filter(r => r.date === today).sort((a, b) => a.timestamp - b.timestamp);
  }
  try {
    const res = await fetch(`/proxy/api/backup/buy-sell-scores?date=${today}`);
    if (res.ok) {
      const data = await res.json();
      return (Array.isArray(data.records) ? data.records : []).sort((a, b) => Number(a.timestamp || 0) - Number(b.timestamp || 0));
    }
  } catch (err) {}
  return [];
}

async function backupBuySellScore(record) {
  try {
    await fetch(window.location.origin + '/proxy/api/backup/buy-sell-scores', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ record })
    });
  } catch (err) {
    console.warn('Buy/Sell file backup failed:', err);
  }
}

let buySellBackupRestoreStarted = false;
async function restoreBuySellScoresFromBackup() {
  if (buySellBackupRestoreStarted) return;
  buySellBackupRestoreStarted = true;
  if (typeof DB === 'undefined' || !DB?.db || typeof DB.saveBuySellScore !== 'function') return;
  try {
    const today = new Date().toISOString().split('T')[0];
    const res = await fetch(`/proxy/api/backup/buy-sell-scores?date=${today}`);
    if (!res.ok) return;
    const data = await res.json();
    const records = Array.isArray(data.records) ? data.records : [];
    for (const record of records) {
      await DB.saveBuySellScore(record);
    }
  } catch (err) {
    console.warn('Buy/Sell backup restore failed:', err);
  }
}

function niceAxisRange(values, padPct = 0.08) {
  const nums = values.map(Number).filter(Number.isFinite);
  if (!nums.length) return { min: 0, max: 1 };
  let min = Math.min(...nums), max = Math.max(...nums);
  if (min === max) { min -= 1; max += 1; }
  const pad = (max - min) * padPct;
  return { min: min - pad, max: max + pad };
}

async function renderBuySellHistoryChart() {
  const canvas = document.getElementById('buy-sell-history-canvas');
  if (!canvas) return;
  
  // Only render Mon–Fri
  const etNow = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/New_York' }));
  const dayOfWeek = etNow.getDay();
  const isWeekday = dayOfWeek >= 1 && dayOfWeek <= 5;
  
  if (!isWeekday) {
    const parent = canvas.parentElement;
    const W = Math.max(240, parent?.clientWidth || 480);
    const H = Math.max(140, parent?.clientHeight || 220);
    canvas.width = W;
    canvas.height = H;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, W, H);
    ctx.fillStyle = '#0a0f16';
    ctx.fillRect(0, 0, W, H);
    ctx.fillStyle = '#3a5570';
    ctx.font = '12px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('Market closed on weekends', W / 2, H / 2);
    return;
  }
  
  await restoreBuySellScoresFromBackup();
  const parent = canvas.parentElement;
  const W = Math.max(240, parent?.clientWidth || 480);
  const H = Math.max(140, parent?.clientHeight || 220);
  canvas.width = W;
  canvas.height = H;
  const ctx = canvas.getContext('2d');
  ctx.clearRect(0, 0, W, H);
  ctx.fillStyle = '#0a0f16';
  ctx.fillRect(0, 0, W, H);

  let rows = (await getBuySellHistoryRows()).slice().sort((a, b) => a.timestamp - b.timestamp);
  
  // Filter to 9:00 AM - 3:30 PM ET
  rows = rows.filter(r => {
    const timeStr = r.time || '';
    const [hh, mm] = timeStr.split(':').map(Number);
    if (isNaN(hh) || isNaN(mm)) return true; // Keep malformed times
    const mins = hh * 60 + mm;
    return mins >= 540 && mins <= 930; // 9:00 AM = 540 mins, 3:30 PM = 930 mins
  });
  
  const PAD = { l: 48, r: 42, t: 22, b: 42 };
  const cW = W - PAD.l - PAD.r;
  const cH = H - PAD.t - PAD.b;

  ctx.fillStyle = '#e8edf5';
  ctx.font = '11px Arial';
  ctx.textAlign = 'center';
  ctx.fillText('BUY/SELL SCORES - 5 Min Intraday Trend', W / 2, 12);

  if (rows.length < 2) {
    ctx.fillStyle = '#3a5570';
    ctx.font = '12px Arial';
    ctx.fillText('Waiting for Buy/Sell score history...', W / 2, H / 2);
    return;
  }

  const priceRange = niceAxisRange(rows.map(r => r.spxPrice));
  const buyRange = niceAxisRange(rows.map(r => r.buyPct), 0.12);
  buyRange.min = Math.max(0, Math.min(100, buyRange.min));
  buyRange.max = Math.max(buyRange.min + 1, Math.min(100, buyRange.max));
  const xAt = i => PAD.l + (i / Math.max(1, rows.length - 1)) * cW;
  const yPrice = v => PAD.t + cH - ((v - priceRange.min) / (priceRange.max - priceRange.min || 1)) * cH;
  const yBuy = v => PAD.t + cH - ((v - buyRange.min) / (buyRange.max - buyRange.min || 1)) * cH;

  ctx.strokeStyle = '#1f2b3a';
  ctx.lineWidth = 1;
  ctx.font = '9px Arial';
  for (let i = 0; i <= 5; i++) {
    const y = PAD.t + (i / 5) * cH;
    ctx.beginPath(); ctx.moveTo(PAD.l, y); ctx.lineTo(PAD.l + cW, y); ctx.stroke();
    const priceVal = priceRange.max - (i / 5) * (priceRange.max - priceRange.min);
    const buyVal = buyRange.max - (i / 5) * (buyRange.max - buyRange.min);
    ctx.fillStyle = '#00c8ff'; ctx.textAlign = 'right'; ctx.fillText(priceVal.toFixed(0), PAD.l - 6, y + 3);
    ctx.fillStyle = '#00e676'; ctx.textAlign = 'left'; ctx.fillText(buyVal.toFixed(0), PAD.l + cW + 6, y + 3);
  }

  rows.forEach((r, i) => {
    const x = xAt(i);
    ctx.strokeStyle = '#162333';
    ctx.beginPath(); ctx.moveTo(x, PAD.t); ctx.lineTo(x, PAD.t + cH); ctx.stroke();
    ctx.save();
    ctx.translate(x, PAD.t + cH + 12);
    ctx.rotate(-Math.PI / 4);
    ctx.fillStyle = '#9aa7b8';
    ctx.textAlign = 'right';
    ctx.font = '8px Arial';
    ctx.fillText((r.time || '').slice(0, 5), 0, 0);
    ctx.restore();
  });

  const drawLine = (key, yFn, color) => {
    ctx.strokeStyle = color;
    ctx.lineWidth = 2;
    ctx.beginPath();
    rows.forEach((r, i) => {
      const x = xAt(i), y = yFn(Number(r[key]));
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.stroke();
    const last = rows[rows.length - 1];
    ctx.fillStyle = color;
    ctx.beginPath();
    ctx.arc(xAt(rows.length - 1), yFn(Number(last[key])), 4, 0, Math.PI * 2);
    ctx.fill();
  };
  drawLine('spxPrice', yPrice, '#ffffff');
  drawLine('buyPct', yBuy, '#00e676');

  ctx.fillStyle = '#ffffff'; ctx.font = '10px Arial'; ctx.textAlign = 'left';
  ctx.fillRect(PAD.l + 6, PAD.t + 5, 18, 2); ctx.fillText('SPXW Price', PAD.l + 30, PAD.t + 8);
  ctx.fillStyle = '#00e676';
  ctx.fillRect(PAD.l + 6, PAD.t + 18, 18, 2); ctx.fillText('Buy %', PAD.l + 30, PAD.t + 21);
  ctx.save(); ctx.translate(12, PAD.t + cH / 2); ctx.rotate(-Math.PI / 2);
  ctx.fillStyle = '#ffffff'; ctx.textAlign = 'center'; ctx.fillText('SPXW Price', 0, 0); ctx.restore();
  ctx.save(); ctx.translate(W - 10, PAD.t + cH / 2); ctx.rotate(Math.PI / 2);
  ctx.fillStyle = '#00e676'; ctx.textAlign = 'center'; ctx.fillText('Buy %', 0, 0); ctx.restore();
}
