// Position ES stats ladder spine through the dot column
(function positionESLSpine(){
  function align(){
    const body = document.getElementById('stats-body');
    const spine = document.getElementById('esl-spine');
    const firstDot = body ? body.querySelector('.esl-row > div:nth-child(2)') : null;
    if(!body || !spine || !firstDot) return;
    const bodyRect = body.getBoundingClientRect();
    const dotRect = firstDot.getBoundingClientRect();
    const dotCenter = dotRect.left + dotRect.width/2 - bodyRect.left;
    spine.style.left = Math.round(dotCenter) + 'px';
  }
})();

