window.gexTakeSnapshot = function gexTakeSnapshot() {
  const now = new Date();
  const etStr = now.toLocaleString('en-US', {timeZone:'America/New_York'});
  const et = new Date(etStr);
  const h = String(et.getHours()).padStart(2,'0');
  const m = String(et.getMinutes()).padStart(2,'0');
  const time = `${h}:${m}`;

  let strike = '—';
  if (rawChain && rawChain.length) {
    const peak = getHighestNetGexRow(rawChain, 'netGEX') || rawChain[0];
    strike = peak.strike;
  } else if (spotPrice > 0) {
    strike = Math.round(spotPrice / 5) * 5; // round to nearest 5
  }

  if (!window.gexPeakSnaps) window.gexPeakSnaps = [];
  window.gexPeakSnaps.push({ time, strike, auto: false });
  gexRenderSnapshots();

  // Send to Discord (deferred until functions are available)
  window.pendingDiscordSnap = { strike, time: Date.now() };

  // Save to database
  if (DB && DB.db && rawChain && rawChain.length) {
    const mvcOI  = getHighestNetGexRow(rawChain, 'netGEX') || rawChain[0];
    const mvcVol = getHighestNetGexRow(rawChain, 'netVolGEX') || rawChain[0];
    const price  = spotPrice > 0 ? spotPrice : (esPrice > 0 ? esPrice : 0);
    DB.saveMVCSnapshot(
      { strike: mvcOI.strike,  value: mvcOI.netGEX,       volume: mvcOI.callVolume  + mvcOI.putVolume  },
      { strike: mvcVol.strike, value: mvcVol.netVolGEX||0, volume: mvcVol.callVolume + mvcVol.putVolume },
      price,
      esPrice,
      selectedExpiry || 'â€”',
      'manual',
      totalNetGEX,
      (window.topDexRow && window.topDexRow.strike != null ? window.topDexRow.strike : window.AppState?.netDexStrike ?? null),
      totalNetDEX_OI,
      totalNetDEX_Vol,
      totalNetGEX_Vol,
      flipPoint
    ).then(() => console.log(`✓ DB MVC saved [manual]: ${mvcOI.strike} @ ${price}`))
     .catch(e  => console.error('DB MVC save failed:', e));
  }
};

function gexClearSnapshots() {
  window.gexPeakSnaps = [];
  gexRenderSnapshots();
}

function gexRenderSnapshots() {
  const el = document.getElementById('gex-peak-list');
  if (!el) return;
  if (!window.gexPeakSnaps) window.gexPeakSnaps = [];
  if (!window.gexPeakSnaps.length) { el.innerHTML = '<span style="font-size:12px;color:#2a4060">no snapshots yet</span>'; return; }
  
  el.innerHTML = window.gexPeakSnaps.map((s, i) => {
    const isAuto = s.auto ? `title="${s.time} auto-snapshot"` : `title="Manual snap at ${s.time}"`;
    const dot = s.auto ? '◆' : '◇';
    return `<div ${isAuto}
      style="display:flex;align-items:center;gap:5px;background:#0a1420;border:1px solid #1e3050;border-radius:2px;padding:3px 8px;cursor:default;white-space:nowrap">
      <span style="font-size:10px;color:#ffffff">${dot}</span>
      <span style="font-size:11px;color:#ffffff">${s.time}</span>
      <span style="font-size:13px;color:#ffb300;font-weight:700;font-variant-numeric:tabular-nums">${typeof s.strike === 'number' ? s.strike.toLocaleString() : s.strike}</span>
      <span onclick="window.gexPeakSnaps.splice(${i},1);gexRenderSnapshots()" 
        style="font-size:10px;color:#1e3050;cursor:pointer;margin-left:2px;line-height:1" title="Remove">✕</span>
    </div>`;
  }).join('');
}

// Auto-snapshot at 9:45am, 10:30am, 12:00pm Eastern
function gexAutoSnapshot() {
  const now = new Date();
  const etStr = now.toLocaleString('en-US', {timeZone:'America/New_York'});
  const et = new Date(etStr);
  const h = et.getHours(), m = et.getMinutes(), s = et.getSeconds();
  const times = [[9,45],[10,30],[12,0]];
  if (times.some(([th,tm]) => h===th && m===tm && s < 5)) {
    if (!rawChain.length) return;
    const peak = getHighestNetGexRow(rawChain, 'netGEX') || rawChain[0];
    const time = `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}`;
    // Only snap once per time window (check not already snapped this minute)
    const alreadySnapped = (window.gexPeakSnaps||[]).some(s => s.time === time && s.auto);
    if (!alreadySnapped) {
      if (!window.gexPeakSnaps) window.gexPeakSnaps = [];
      window.gexPeakSnaps.push({ time, strike: peak.strike, netGEX: peak.netGEX, auto: true });
      gexRenderSnapshots();
      console.log(`✓ Auto-snapshot at ${time} ET: strike ${peak.strike}`);

      // Send to Discord (deferred)
      window.pendingDiscordSnap = { strike: peak.strike, time: Date.now() };

      // Save to database
      if (DB && DB.db) {
        const mvcVol = getHighestNetGexRow(rawChain, 'netVolGEX') || rawChain[0];
        const price  = spotPrice > 0 ? spotPrice : (esPrice > 0 ? esPrice : 0);
        const label  = `auto-${time}`;
        DB.saveMVCSnapshot(
          { strike: peak.strike,   value: peak.netGEX,        volume: peak.callVolume   + peak.putVolume   },
          { strike: mvcVol.strike, value: mvcVol.netVolGEX||0, volume: mvcVol.callVolume + mvcVol.putVolume },
          price,
          label
        ).then(() => console.log(`✓ DB MVC saved [${label}]: ${peak.strike} @ ${price}`))
         .catch(e  => console.error('DB MVC auto-save failed:', e));
      }
    }
  }
}
