function mockSetExp(exp, el) {
  document.querySelectorAll('#dte-gex-pills .nav-pill').forEach(p => p.classList.remove('active'));
  const combined = document.getElementById('dte-gex-pill-combined');
  if (combined) combined.classList.remove('active');
  if (el) el.classList.add('active');
  
  const lbl = document.getElementById('dte-gex-label');
  const expDate = new Date(exp + 'T12:00:00');
  const today = new Date(); today.setHours(0,0,0,0);
  const dte = Math.round((expDate - today) / 86400000);
  if (lbl) lbl.textContent = (dte <= 0 ? '0' : dte) + 'DTE — ' + exp;
  
  computeGEXMulti([exp]);
  if (typeof renderGEXTable === 'function') setTimeout(renderGEXTable, 50);
}

