        <div style="font-size:11px;color:var(--text2);line-height:1.45;margin-top:7px">Buy ${event.buyPct}% / Sell ${event.sellPct}% | GEX ${event.gexScore}% | DEX ${event.dexScore}% | CHEX ${event.chexScore}% | VEX ${event.vexScore}%</div>
