// INSIGHTS PAGE LOADER - Inject insights.html dynamically
// ═══════════════════════════════════════════════════════════════════════════

(async function loadInsightsPage() {
  console.log('[Insights] Loading insights.html...');
  
  try {
    // Fetch insights.html
    const response = await fetch('pages/insights/insights.html');
    if (!response.ok) throw new Error('HTTP ' + response.status);
    
    const insightsHTML = await response.text();
    console.log('[Insights] Fetched', insightsHTML.length, 'bytes');
    
    // Create page-insights container
    let pageInsights = document.getElementById('page-insights');
    if (!pageInsights) {
      pageInsights = document.createElement('div');
      pageInsights.id = 'page-insights';
      pageInsights.style.display = 'none';
      pageInsights.style.flexDirection = 'column';
      pageInsights.style.flex = '1';
      pageInsights.style.minHeight = '0';
      pageInsights.style.overflow = 'hidden';
      pageInsights.style.background = 'var(--bg0)';
      document.body.appendChild(pageInsights);
    }
    
    // Extract and execute script
    const scriptMatch = insightsHTML.match(/<script>([\s\S]*?)<\/script>/);
    const scriptContent = scriptMatch ? scriptMatch[1] : '';
    
    if (!scriptContent) throw new Error('No script in insights.html');
    
    // Inject HTML
    const htmlOnly = insightsHTML.replace(/<script>[\s\S]*?<\/script>/g, '');
    pageInsights.innerHTML = htmlOnly;
    
    // Execute script globally
    (new Function(scriptContent))();
    
    console.log('[Insights] ✓ Loaded - switchInsightsTab:', typeof switchInsightsTab);

  } catch (e) {
    console.error('[Insights] Load failed:', e.message);
  }
})();

// ═══════════════════════════════════════════════════════════════════════
// SNAPSHOT TAB FUNCTIONS - Auto-update from bzila data
// ═══════════════════════════════════════════════════════════════════════
window.updateSnapshotMetrics = function() {
  try {
    const bzila = window.bzila || {};
    if (!bzila.bullVol) return;

    // Update metrics every time
    const pcEl = document.getElementById('snap-pc-ratio');
    if (pcEl) pcEl.textContent = ((bzila.putVol || 0) / (bzila.callVol || 1)).toFixed(2);

    const bbEl = document.getElementById('snap-bb-ratio');
    if (bbEl) bbEl.textContent = ((bzila.buyVol || 0) / (bzila.sellVol || 1)).toFixed(2);

    const bullEl = document.getElementById('snap-bull-vol');
    if (bullEl) bullEl.textContent = (bzila.bullVol || 0).toLocaleString();

    const bearEl = document.getElementById('snap-bear-vol');
    if (bearEl) bearEl.textContent = (bzila.bearVol || 0).toLocaleString();

    const bullPct = bzila.bullPct || 0.5;
    const gaugeBar = document.getElementById('snap-gauge-bar');
    if (gaugeBar) gaugeBar.style.width = (bullPct * 100) + '%';

    const gaugeText = document.getElementById('snap-gauge-text');
    if (gaugeText) {
      gaugeText.textContent = Math.round(bullPct * 100) + '% BC + SP';
      gaugeText.style.color = bullPct > 0.5 ? '#00e676' : bullPct < 0.5 ? '#ff4757' : '#ffb300';
    }

    const statusEl = document.getElementById('snap-status');
    if (statusEl) {
      statusEl.textContent = bzila.status || 'WAITING';
      statusEl.style.color = bzila.status === 'LIVE' ? '#00e676' : '#3a5570';
    }
  } catch (e) {
    // Silent fail
  }
};

// Flow session key for the Snapshot tab accumulators (top-3 flow + bars).
// Resets at 09:30 and 18:00 ET — same rule as the net premium sparkline so all
// snapshot accumulators clear together. Falls back to a local computation if
// the overview.html helper hasn't loaded yet.
function getSnapshotFlowSessionKey(date = new Date()) {
  if (typeof window.getFlowSessionKey === 'function') return window.getFlowSessionKey(date);
  const dt = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/New_York', hour12: false, hour: '2-digit', minute: '2-digit'
  }).formatToParts(date);
  const get = (t) => Number(dt.find((p) => p.type === t)?.value || 0);
  const dstr = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'America/New_York', year: 'numeric', month: '2-digit', day: '2-digit'
  }).format(date);
  const mins = get('hour') * 60 + get('minute');
  const OPEN = 9 * 60 + 30, EVE = 18 * 60;
  const bucket = mins < OPEN ? 'pre' : (mins < EVE ? 'rth' : 'eve');
  return dstr + ':' + bucket;
}
window.getSnapshotFlowSessionKey = getSnapshotFlowSessionKey;

// Initialize cumulative GEX per strike + restore persistent data from localStorage/SQLite
if (!window._cumulativeGEXByStrike) {
  window._cumulativeGEXByStrike = {};
  window._cumulativeGEXSession = getSnapshotFlowSessionKey();
  try {
    const saved = localStorage.getItem('spxFlow_v1');
    if (saved) {
      const data = JSON.parse(saved);
      const sessionKey = getSnapshotFlowSessionKey();
      // Only restore if the saved data belongs to the current flow session
      // (matches on our 09:30/18:00 session key written by updateSnapshotTop3).
      if (data.snapshotSession === sessionKey) {
        // Restore cumulative GEX
        if (data.cumulativeGEXByStrike && typeof data.cumulativeGEXByStrike === 'object') {
          window._cumulativeGEXByStrike = data.cumulativeGEXByStrike;
          console.log('[snapshot] Restored cumulative GEX from localStorage');
        }
        // Restore premium flows to bzila for display
        if (window.bzila) {
          if (data.netPremiumFlow) window.bzila.netPremium = data.netPremiumFlow;
          if (data.callPremiumFlow) window.bzila.callPremiumFlow = data.callPremiumFlow;
          if (data.putPremiumFlow) window.bzila.putPremiumFlow = data.putPremiumFlow;
        }
      }
    }
  } catch (e) {
    console.warn('[snapshot] Failed to restore data:', e);
  }

  // Restore from SQLite if localStorage was empty
  (async () => {
    try {
      const today = new Date().toISOString().split('T')[0];
      const response = await fetch(`/proxy/api/db/query?table=bzila_live_snapshots&date=${today}&limit=100`);
      if (response.ok) {
        const result = await response.json();
        const records = result.data || [];
        if (records.length > 0) {
          // Get the most recent record for today
          const latest = records[0];
          if (latest.data && typeof latest.data === 'object') {
            const data = latest.data.data ? JSON.parse(latest.data.data) : latest.data;
            const sessionKey = getSnapshotFlowSessionKey();
            if (data.sessionKey === sessionKey && data.cumulativeGEXByStrike) {
              window._cumulativeGEXByStrike = data.cumulativeGEXByStrike;
              console.log('[snapshot] Restored from SQLite');
            }
          }
        }
      }
    } catch (e) {
      console.warn('[snapshot] SQLite restore failed:', e);
    }
  })();

  // Periodic save to SQLite every 30 seconds (for persistence across restarts)
  setInterval(() => {
    window.saveSnapshotDataToSQLite?.();
  }, 30000);
}

// Save snapshot metrics to SQLite for persistent storage
window.saveSnapshotDataToSQLite = async function() {
  try {
    const bzila = window.bzila || {};
    if (!bzila.bullVol && !window._cumulativeGEXByStrike) return; // Nothing to save

    const now = new Date();
    const sessionKey = getSnapshotFlowSessionKey(now);

    const snapshotData = {
      timestamp: now.getTime(),
      date: now.toISOString().split('T')[0],
      ticker: 'SPX',
      data: JSON.stringify({
        sessionKey,
        bullVol: bzila.bullVol || 0,
        bearVol: bzila.bearVol || 0,
        bullPct: bzila.bullPct || 0.5,
        putVol: bzila.putVol || 0,
        callVol: bzila.callVol || 0,
        buyVol: bzila.buyVol || 0,
        sellVol: bzila.sellVol || 0,
        status: bzila.status || 'WAITING',
        netPremium: bzila.netPremium || 0,
        callPremiumFlow: bzila.callPremiumFlow || [],
        putPremiumFlow: bzila.putPremiumFlow || [],
        recentTrades: bzila.recentTrades || [],
        cumulativeGEXByStrike: window._cumulativeGEXByStrike || {}
      })
    };

    const response = await fetch('/proxy/api/db/insert', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ table: 'bzila_live_snapshots', data: snapshotData })
    });

    if (!response.ok) {
      console.warn('[snapshot] SQLite save failed:', response.status);
    }
  } catch (e) {
    console.warn('[snapshot] SQLite save error:', e.message);
  }
};

window.updateSnapshotTop3 = function() {
  try {
    const bzila = window.bzila || {};
    const trades = (bzila.recentTrades && Array.isArray(bzila.recentTrades)) ? bzila.recentTrades : [];

    // Session rollover: clear the top-3 accumulator at 09:30 / 18:00 ET so the
    // bars + flow lists reset on the same schedule as the net premium sparkline.
    const _sessionKey = getSnapshotFlowSessionKey();
    if (window._cumulativeGEXSession !== _sessionKey) {
      window._cumulativeGEXByStrike = {};
      window._cumulativeGEXSession = _sessionKey;
    }

    // Don't update if no trades available
    if (!trades || trades.length === 0) return;

    const normalizeSide = (s) => (s || '').toLowerCase();
    const normalizeType = (t) => (t || '').toLowerCase();
    const spotPrice = window.spotPrice || 5500; // fallback

    // Accumulate GEX by strike (only add new trades, don't recalculate)
    trades.forEach(t => {
      if (!t.strike) return;
      const strike = String(t.strike);
      const side = normalizeSide(t.side);
      const type = normalizeType(t.type);

      const key = `${strike}:${side}:${type}`;
      if (!window._cumulativeGEXByStrike[key]) {
        window._cumulativeGEXByStrike[key] = 0;
      }

      // Simple GEX approximation: size * price * side_multiplier
      const sizeNum = t.size || 0;
      const gexDelta = sizeNum * spotPrice * (side === 'buy' ? 1 : -1) * (type === 'c' ? 1 : -1);
      window._cumulativeGEXByStrike[key] += gexDelta;
    });

    // Get top 3 by cumulative GEX per side+type
    const getTop3 = (side, type) => {
      const entries = Object.entries(window._cumulativeGEXByStrike)
        .filter(([k, v]) => {
          const [s, si, ty] = k.split(':');
          return si === side && ty === type;
        })
        .map(([k, v]) => ({ strike: k.split(':')[0], gex: Math.abs(v) }))
        .sort((a, b) => b.gex - a.gex)
        .slice(0, 3);
      return entries;
    };

    const bc = getTop3('buy', 'c');
    const sc = getTop3('sell', 'c');
    const bp = getTop3('buy', 'p');
    const sp = getTop3('sell', 'p');

    const render = (arr, barColor) => {
      if (!arr || arr.length === 0) return '<div style="color:#fff;font-size:9px">Waiting...</div>';
      const maxGex = Math.max(...arr.map(a => a.gex || 0), 1);
      return arr.map((item, i) => {
        const gex = item.gex || 0;
        const displayGex = gex > 1000000 ? (gex / 1000000).toFixed(1) + 'M' : gex > 1000 ? (gex / 1000).toFixed(1) + 'K' : gex.toFixed(0);
        const barWidth = Math.max((gex / maxGex) * 100, 4);
        // Gradient: brighten at right edge for a glow effect
        const barGrad = `linear-gradient(90deg, ${barColor}55 0%, ${barColor}cc 60%, ${barColor} 100%)`;
        return `<div style="display:flex;align-items:center;gap:3px;font-size:10px;flex:0 0 auto;padding:1px 0">
          <span style="width:12px;color:#fff;font-weight:700;flex-shrink:0">${i+1}</span>
          <span style="width:40px;font-weight:700;color:#e0e8f0;font-variant-numeric:tabular-nums;flex-shrink:0;font-size:11px">${item.strike}</span>
          <div style="flex:1;height:8px;background:#0d1a26;border-radius:3px;overflow:hidden;min-width:0">
            <div style="height:100%;background:${barGrad};width:${barWidth}%;transition:width 0.3s ease;border-radius:3px;box-shadow:0 0 6px ${barColor}66"></div>
          </div>
          <span style="width:38px;text-align:right;color:#c0d4e0;font-size:10px;font-weight:600;flex-shrink:0">${displayGex}</span>
        </div>`;
      }).join('');
    };

    // Helper: total GEX of top-3
    const totalGex = (arr) => arr.reduce((s, a) => s + (a.gex || 0), 0);
    const fmtVol = (v) => v > 1000000 ? (v/1000000).toFixed(1)+'M' : v > 1000 ? (v/1000).toFixed(1)+'K' : v.toFixed(0);

    const el = (id) => document.getElementById(id);
    if (el('snap-top-buy-calls-list')) el('snap-top-buy-calls-list').innerHTML = render(bc, '#00e676');
    if (el('snap-top-sell-calls-list')) el('snap-top-sell-calls-list').innerHTML = render(sc, '#ff4757');
    if (el('snap-top-buy-puts-list')) el('snap-top-buy-puts-list').innerHTML = render(bp, '#00e676');
    if (el('snap-top-sell-puts-list')) el('snap-top-sell-puts-list').innerHTML = render(sp, '#ff4757');

    // Net Flow Sentiment Bar (BC + SP = bull, SC + BP = bear)
    const bullTotal = totalGex(bc) + totalGex(sp);
    const bearTotal = totalGex(sc) + totalGex(bp);
    const sentTotal = bullTotal + bearTotal || 1;
    const bullPct = (bullTotal / sentTotal) * 100;
    const bearPct = (bearTotal / sentTotal) * 100;

    const bullBar = el('snap-sentiment-bull-bar');
    const bearBar = el('snap-sentiment-bear-bar');
    const bullLabel = el('snap-bull-sentiment');
    const bearLabel = el('snap-bear-sentiment');
    const bullBreak = el('snap-bull-breakdown');
    const bearBreak = el('snap-bear-breakdown');

    if (bullBar) bullBar.style.width = bullPct.toFixed(1) + '%';
    if (bearBar) bearBar.style.width = bearPct.toFixed(1) + '%';
    if (bullLabel) bullLabel.textContent = fmtVol(bullTotal) + ' Net Bullish';
    if (bearLabel) bearLabel.textContent = fmtVol(bearTotal) + ' Net Bearish';
    if (bullBreak) bullBreak.textContent = `$${fmtVol(bullTotal)} = ${fmtVol(totalGex(bc))} (BC) + ${fmtVol(totalGex(sp))} (SP)`;
    if (bearBreak) bearBreak.textContent = `$${fmtVol(bearTotal)} = ${fmtVol(totalGex(sc))} (SC) + ${fmtVol(totalGex(bp))} (BP)`;
  } catch (e) {
    // Silent fail
  }
};

// Update metrics every 500ms
setInterval(window.updateSnapshotMetrics, 500);

// Update top 3 every 500ms - data accumulates so no flickering
setInterval(window.updateSnapshotTop3, 500);

